{
  "name": "Industrial Assembly Line Simulator",
  "description": "A high-fidelity industrial production line simulation featuring automated vehicle assembly, station processing, quality control loops, and real-time dashboard analytics.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  finished: boolean;
  progress: number;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Truck,
  Zap
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS 
} from './constants';
import { Vehicle, Point, SimulationStats } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); // frames between spawns
  const [speed, setSpeed] = useState(2.5);
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 9);
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: MAIN_PATH_POINTS,
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: Math.random() < 0.15,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, []);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    // Spawning
    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Vehicle ${v.id.toUpperCase()} completed and shipped.`);
        currentVehicles.splice(i, 1);
        continue;
      }

      // Movement
      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // Station Triggering
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        const station = currentMap[v.pathIdx];

        if (station) {
          v.waitingTimer = station.wait;

          // Logic mapping based on station name/type
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          // Defect Detection at Quality Control
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = REPAIR_PATH_POINTS;
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`QC Alert: Defect detected in ${v.id.toUpperCase()}. Rerouting to Repair.`);
          }

          // Return from Repair
          if (station.name === 'FCPA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = MAIN_PATH_POINTS;
            v.pathIdx = 18; // Index of Area Branca in MAIN_PATH_POINTS
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: ${v.id.toUpperCase()} returning to line.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Draw Main Conveyor Lines
    ctx.beginPath();
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.moveTo(MAIN_PATH_POINTS[0].x, MAIN_PATH_POINTS[0].y);
    MAIN_PATH_POINTS.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.stroke();

    // Animated Flow Dots
    ctx.lineWidth = 2;
    ctx.strokeStyle = COLORS.YELLOW_PATH;
    for (let i = 0; i < MAIN_PATH_POINTS.length - 1; i++) {
      const p1 = MAIN_PATH_POINTS[i];
      const p2 = MAIN_PATH_POINTS[i+1];
      const dx = p2.x - p1.x;
      const dy = p2.y - p1.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist === 0) continue;

      const nx = dx / dist;
      const ny = dy / dist;

      for (let d = (animOffsetRef.current % 30); d < dist; d += 30) {
        ctx.beginPath();
        ctx.arc(p1.x + nx * d, p1.y + ny * d, 2, 0, Math.PI * 2);
        ctx.fillStyle = COLORS.YELLOW_PATH;
        ctx.fill();
      }
    }

    // Draw Repair Line
    ctx.beginPath();
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    ctx.moveTo(REPAIR_PATH_POINTS[0].x, REPAIR_PATH_POINTS[0].y);
    REPAIR_PATH_POINTS.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.stroke();

    // Draw Stations
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS)].forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      // Glow effect for MGR
      if (s.type === 'MGR') {
        ctx.beginPath();
        ctx.ellipse(s.pos.x, s.pos.y, 100, 80, 0, 0, Math.PI * 2);
        ctx.strokeStyle = 'rgba(71, 85, 105, 0.4)';
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      ctx.fillStyle = s.type === 'REPAIR' ? '#7f1d1d' : COLORS.STATION;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 12px Inter, sans-serif';
      ctx.fillText(s.name, x + 8, y + 20);

      if (s.type === 'MGR') {
        ctx.font = '10px sans-serif';
        ctx.fillStyle = '#94a3b8';
        ctx.fillText('ENGINE UNIT', x + 8, y + 35);
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const x = v.pos.x - vw / 2;
      const y = v.pos.y - vh / 2;

      // Shadow
      ctx.shadowBlur = 8;
      ctx.shadowColor = 'rgba(0,0,0,0.5)';

      // Body
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(x, y, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = '#ffffff';
      ctx.lineWidth = 1;
      ctx.stroke();
      ctx.shadowBlur = 0;

      // Progress bar if waiting
      if (v.waitingTimer > 0) {
        const totalWait = (v.inRepair ? REPAIR_STATIONS : STATIONS)[v.pathIdx]?.wait || 60;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(x, y - 10, vw, 4);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(x, y - 10, vw * prog, 4);
      }

      // Visual components
      if (v.hasEngine) {
        ctx.fillStyle = '#cbd5e1';
        ctx.fillRect(v.pos.x - 5, v.pos.y - 5, 10, 10);
      }
      if (v.hasWheels) {
        ctx.fillStyle = COLORS.WHEEL;
        [[-12, -14], [12, -14], [-12, 14], [12, 14]].forEach(([dx, dy]) => {
          ctx.beginPath();
          ctx.arc(v.pos.x + dx, v.pos.y + dy, 4, 0, Math.PI * 2);
          ctx.fill();
        });
      }
    });

    // Title Overlay
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V3.1', 50, 40);
    ctx.font = '14px Inter, sans-serif';
    ctx.fillStyle = '#94a3b8';
    ctx.fillText('REAL-TIME LOGISTICS SIMULATION', 50, 60);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      {/* Sidebar */}
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl">
        <div className="flex items-center gap-3 mb-2">
          <div className="bg-blue-600 p-2 rounded-lg">
            <Settings className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        {/* Status Dashboard */}
        <div className="grid grid-cols-2 gap-3">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1">
              <Activity className="w-4 h-4" />
              <span className="text-[10px] font-bold uppercase tracking-wider">Produced</span>
            </div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1">
              <AlertTriangle className="w-4 h-4" />
              <span className="text-[10px] font-bold uppercase tracking-wider">Defects</span>
            </div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-green-400 mb-1">
              <Zap className="w-4 h-4" />
              <span className="text-[10px] font-bold uppercase tracking-wider">Active Units</span>
            </div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-amber-400 mb-1">
              <CheckCircle2 className="w-4 h-4" />
              <span className="text-[10px] font-bold uppercase tracking-wider">Efficiency</span>
            </div>
            <p className="text-2xl font-black">{stats.produced > 0 ? Math.round((1 - stats.defects / (stats.produced + stats.defects)) * 100) : 100}%</p>
          </div>
        </div>

        {/* Controls */}
        <div className="space-y-6">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">
              Speed Multiplier <span>{speed.toFixed(1)}x</span>
            </label>
            <input 
              type="range" min="0.5" max="8" step="0.1" 
              value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))}
              className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">
              Spawn Interval <span>{spawnRate} frames</span>
            </label>
            <input 
              type="range" min="60" max="600" step="10" 
              value={spawnRate} onChange={(e) => setSpawnRate(parseInt(e.target.value))}
              className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => setIsRunning(!isRunning)}
              className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${
                isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'
              }`}
            >
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button 
              onClick={resetSimulation}
              className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"
            >
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Logs */}
        <div className="flex-1 flex flex-col gap-2 min-h-0">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase">
            <Activity className="w-3 h-3" /> System Logs
          </div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.length === 0 && <div className="text-slate-600 italic">No events recorded...</div>}
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main Viewport */}
      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas 
            ref={canvasRef} 
            width={SIM_WIDTH} 
            height={SIM_HEIGHT}
            className="cursor-crosshair"
          />
        </div>

        {/* Interactive Overlays */}
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full">
              <Truck className="w-6 h-6 text-blue-400" />
            </div>
            <div>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Global Status</p>
              <p className="text-lg font-bold text-blue-400">Production Live</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Truck,
  Zap,
  Gauge
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS 
