import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Truck,
  Zap,
  Info,
  Clock,
  Gauge,
  Cpu,
  MapPin
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - i; i >= 0; i--) {
      // Logic safety
    }

    // Using simple loop to avoid index issues with splice
    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} delivered to Patio Final.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`QC FAIL: Unit ${v.id.toUpperCase()} rerouted to FCPA Area.`);
          }

          if (station.name.includes('FCPA') && v.inRepair) {
            // Processing in FCPA is done, move to next point in repair path (Area Branca)
          }

          // Return logic to Area Branca index in main path
          if (station.name === 'Área Branca' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; // Area Branca index
            v.color = COLORS.VEHICLE;
            addLog(`Quality Pass: Unit ${v.id.toUpperCase()} returned to line.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));

    // Repair Path Drawing
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    ctx.lineWidth = 2;
    ctx.strokeStyle = COLORS.YELLOW_PATH;
    const drawAnimatedDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i];
        const p2 = pts[i+1];
        const dx = p2.x - p1.x;
        const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        const nx = dx / dist;
        const ny = dy / dist;
        for (let d = (animOffsetRef.current % 30); d < dist; d += 30) {
          ctx.beginPath();
          ctx.arc(p1.x + nx * d, p1.y + ny * d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };

    drawAnimatedDots(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawAnimatedDots(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(b => drawAnimatedDots(b));

    let hoveredStation: Station | null = null;
    let hoveredStatus = "Idle";

    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const isRollTest = s.name.includes('Teste Rolo');
      const w = s.width || (isRollTest ? 140 : 110);
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;
      const isHovered = mousePosRef.current && 
        mousePosRef.current.x >= x && mousePosRef.current.x <= x + w &&
        mousePosRef.current.y >= y && mousePosRef.current.y <= y + h;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let currentStationStatus = "Idle";
      if (vehicleAtStation) {
        currentStationStatus = vehicleAtStation.waitingTimer > 0 ? "Processing" : "Occupied";
      }

      if (isHovered) {
        hoveredStation = s;
        hoveredStatus = currentStationStatus;
      }

      if (s.type === 'MGR') {
        ctx.beginPath();
        ctx.ellipse(s.pos.x, s.pos.y, 100, 80, 0, 0, Math.PI * 2);
        ctx.strokeStyle = isHovered ? 'rgba(59, 130, 246, 0.6)' : 'rgba(71, 85, 105, 0.4)';
        ctx.lineWidth = isHovered ? 4 : 2;
        ctx.stroke();
      }

      let baseColor = COLORS.STATION;
      if (currentStationStatus === "Processing") baseColor = COLORS.STATION_PROCESSING;
      else if (currentStationStatus === "Occupied") baseColor = COLORS.STATION_HOLDING;

      if (s.type === 'REPAIR' && currentStationStatus === "Idle") baseColor = '#7f1d1d';
      if (s.name.includes('FCPA')) baseColor = currentStationStatus === "Idle" ? '#334155' : baseColor;

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();

      ctx.strokeStyle = isHovered ? '#ffffff' : COLORS.STATION_BORDER;
      ctx.lineWidth = isHovered ? 3 : 2;
      ctx.stroke();

      ctx.beginPath();
      ctx.arc(x + 10, y + 10, 4, 0, Math.PI * 2);
      ctx.fillStyle = currentStationStatus === "Processing" ? '#4ade80' : 
                      currentStationStatus === "Occupied" ? '#fbbf24' : '#94a3b8';
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 11px Inter, sans-serif';
      ctx.fillText(s.name, x + 18, y + 15);

      if (isRollTest) {
        ctx.font = '9px Inter, sans-serif';
        ctx.fillStyle = 'rgba(255,255,255,0.7)';
        ctx.fillText('ECATS TEST SYSTEM', x + 18, y + 30);
      }
    });

    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const x = v.pos.x - vw / 2;
      const y = v.pos.y - vh / 2;

      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(x, y, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = '#ffffff';
      ctx.lineWidth = 1;
      ctx.stroke();

      const currentStation = [...Object.values(STATIONS), ...PARALLEL_ROLL_STATIONS, ...Object.values(REPAIR_STATIONS)].find(
        s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5
      );

      if (v.waitingTimer > 0) {
        const totalWait = currentStation?.wait || 100; 
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(x, y - 10, vw, 4);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(x, y - 10, Math.max(0, vw * prog), 4);

        if (currentStation?.name.includes('Teste Rolo')) {
            const speedVal = Math.floor(Math.sin(prog * Math.PI) * 100);
            ctx.fillStyle = '#fbbf24';
            ctx.font = 'bold 9px monospace';
            ctx.textAlign = 'center';
            ctx.fillText(`${speedVal}`, v.pos.x, v.pos.y + 4);
            ctx.textAlign = 'left';
        }
      }

      if (v.hasEngine) {
        ctx.fillStyle = '#cbd5e1';
        ctx.fillRect(v.pos.x - 5, v.pos.y - 5, 10, 10);
      }
      if (v.hasWheels) {
        ctx.fillStyle = COLORS.WHEEL;
        [[-12, -14], [12, -14], [-12, 14], [12, 14]].forEach(([dx, dy]) => {
          ctx.beginPath();
          ctx.arc(v.pos.x + dx, v.pos.y + dy, 4, 0, Math.PI * 2);
          ctx.fill();
        });
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.0', 50, 40);
    ctx.font = '14px Inter, sans-serif';
    ctx.fillStyle = '#94a3b8';
    ctx.fillText('QUALITY LOOP: FAI > FCPA > PATIO FINAL', 50, 60);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="p-4 bg-slate-800/40 rounded-xl border border-cyan-500/30 shadow-inner">
           <div className="flex items-center gap-2 text-cyan-400 mb-3">
             <Cpu className="w-4 h-4" />
             <span className="text-[10px] font-bold uppercase tracking-wider">ECATS Online Status</span>
           </div>
           <div className="space-y-3">
             {PARALLEL_ROLL_STATIONS.map((s, idx) => {
               const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
               const speedKmH = v && v.waitingTimer > 0 ? Math.floor(Math.sin((1 - v.waitingTimer / s.wait) * Math.PI) * 100) : 0;
               return (
                 <div key={s.id} className="flex flex-col gap-1">
                   <div className="flex justify-between text-[10px]">
                     <span className="text-slate-400">Lane {idx + 1}</span>
                     <span className={speedKmH > 0 ? "text-cyan-400" : "text-slate-600"}>{speedKmH > 0 ? 'TESTING' : 'IDLE'}</span>
                   </div>
                   <div className="h-2 w-full bg-slate-700 rounded-full overflow-hidden">
                     <div className="h-full bg-cyan-500" style={{ width: `${speedKmH}%` }} />
                   </div>
                 </div>
               );
             })}
           </div>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-amber-400 mb-1"><CheckCircle2 className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Efficiency</span></div>
            <p className="text-2xl font-black">{stats.produced > 0 ? Math.round((1 - stats.defects / (stats.produced + stats.defects)) * 100) : 100}%</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Speed Multiplier <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Truck,
  Zap,
  Info,
  Clock,
  Gauge,
  Cpu,
  MapPin
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    // Fix: removed redundant and erroneous loop on line 101 to fix "Block-scoped variable 'i' used before its declaration"

    // Using simple loop to avoid index issues with splice
    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} delivered to Patio Final.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`QC FAIL: Unit ${v.id.toUpperCase()} rerouted to FCPA Area.`);
          }

          if (station.name.includes('FCPA') && v.inRepair) {
            // Processing in FCPA is done, move to next point in repair path (Area Branca)
          }

          // Return logic to Area Branca index in main path
          if (station.name === 'Área Branca' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; // Area Branca index
            v.color = COLORS.VEHICLE;
            addLog(`Quality Pass: Unit ${v.id.toUpperCase()} returned to line.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));

    // Repair Path Drawing
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    ctx.lineWidth = 2;
    ctx.strokeStyle = COLORS.YELLOW_PATH;
    const drawAnimatedDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i];
        const p2 = pts[i+1];
        const dx = p2.x - p1.x;
        const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        const nx = dx / dist;
        const ny = dy / dist;
        for (let d = (animOffsetRef.current % 30); d < dist; d += 30) {
          ctx.beginPath();
          ctx.arc(p1.x + nx * d, p1.y + ny * d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };

    drawAnimatedDots(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawAnimatedDots(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(b => drawAnimatedDots(b));

    let hoveredStation: Station | null = null;
    let hoveredStatus = "Idle";

    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const isRollTest = s.name.includes('Teste Rolo');
      const w = s.width || (isRollTest ? 140 : 110);
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;
      const isHovered = mousePosRef.current && 
        mousePosRef.current.x >= x && mousePosRef.current.x <= x + w &&
        mousePosRef.current.y >= y && mousePosRef.current.y <= y + h;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let currentStationStatus = "Idle";
      if (vehicleAtStation) {
        currentStationStatus = vehicleAtStation.waitingTimer > 0 ? "Processing" : "Occupied";
      }

      if (isHovered) {
        hoveredStation = s;
        hoveredStatus = currentStationStatus;
      }

      if (s.type === 'MGR') {
        ctx.beginPath();
        ctx.ellipse(s.pos.x, s.pos.y, 100, 80, 0, 0, Math.PI * 2);
        ctx.strokeStyle = isHovered ? 'rgba(59, 130, 246, 0.6)' : 'rgba(71, 85, 105, 0.4)';
        ctx.lineWidth = isHovered ? 4 : 2;
        ctx.stroke();
      }

      let baseColor = COLORS.STATION;
      if (currentStationStatus === "Processing") baseColor = COLORS.STATION_PROCESSING;
      else if (currentStationStatus === "Occupied") baseColor = COLORS.STATION_HOLDING;

      if (s.type === 'REPAIR' && currentStationStatus === "Idle") baseColor = '#7f1d1d';
      if (s.name.includes('FCPA')) baseColor = currentStationStatus === "Idle" ? '#334155' : baseColor;

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();

      ctx.strokeStyle = isHovered ? '#ffffff' : COLORS.STATION_BORDER;
      ctx.lineWidth = isHovered ? 3 : 2;
      ctx.stroke();

      ctx.beginPath();
      ctx.arc(x + 10, y + 10, 4, 0, Math.PI * 2);
      ctx.fillStyle = currentStationStatus === "Processing" ? '#4ade80' : 
                      currentStationStatus === "Occupied" ? '#fbbf24' : '#94a3b8';
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 11px Inter, sans-serif';
      ctx.fillText(s.name, x + 18, y + 15);

      if (isRollTest) {
        ctx.font = '9px Inter, sans-serif';
        ctx.fillStyle = 'rgba(255,255,255,0.7)';
        ctx.fillText('ECATS TEST SYSTEM', x + 18, y + 30);
      }
    });

    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const x = v.pos.x - vw / 2;
      const y = v.pos.y - vh / 2;

      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(x, y, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = '#ffffff';
      ctx.lineWidth = 1;
      ctx.stroke();

      const currentStation = [...Object.values(STATIONS), ...PARALLEL_ROLL_STATIONS, ...Object.values(REPAIR_STATIONS)].find(
        s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5
      );

      if (v.waitingTimer > 0) {
        const totalWait = currentStation?.wait || 100; 
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(x, y - 10, vw, 4);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(x, y - 10, Math.max(0, vw * prog), 4);

        if (currentStation?.name.includes('Teste Rolo')) {
            const speedVal = Math.floor(Math.sin(prog * Math.PI) * 100);
            ctx.fillStyle = '#fbbf24';
            ctx.font = 'bold 9px monospace';
            ctx.textAlign = 'center';
            ctx.fillText(`${speedVal}`, v.pos.x, v.pos.y + 4);
            ctx.textAlign = 'left';
        }
      }

      if (v.hasEngine) {
        ctx.fillStyle = '#cbd5e1';
        ctx.fillRect(v.pos.x - 5, v.pos.y - 5, 10, 10);
      }
      if (v.hasWheels) {
        ctx.fillStyle = COLORS.WHEEL;
        [[-12, -14], [12, -14], [-12, 14], [12, 14]].forEach(([dx, dy]) => {
          ctx.beginPath();
          ctx.arc(v.pos.x + dx, v.pos.y + dy, 4, 0, Math.PI * 2);
          ctx.fill();
        });
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.0', 50, 40);
    ctx.font = '14px Inter, sans-serif';
    ctx.fillStyle = '#94a3b8';
    ctx.fillText('QUALITY LOOP: FAI > FCPA > PATIO FINAL', 50, 60);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="p-4 bg-slate-800/40 rounded-xl border border-cyan-500/30 shadow-inner">
           <div className="flex items-center gap-2 text-cyan-400 mb-3">
             <Cpu className="w-4 h-4" />
             <span className="text-[10px] font-bold uppercase tracking-wider">ECATS Online Status</span>
           </div>
           <div className="space-y-3">
             {PARALLEL_ROLL_STATIONS.map((s, idx) => {
               const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
               const speedKmH = v && v.waitingTimer > 0 ? Math.floor(Math.sin((1 - v.waitingTimer / s.wait) * Math.PI) * 100) : 0;
               return (
                 <div key={s.id} className="flex flex-col gap-1">
                   <div className="flex justify-between text-[10px]">
                     <span className="text-slate-400">Lane {idx + 1}</span>
                     <span className={speedKmH > 0 ? "text-cyan-400" : "text-slate-600"}>{speedKmH > 0 ? 'TESTING' : 'IDLE'}</span>
                   </div>
                   <div className="h-2 w-full bg-slate-700 rounded-full overflow-hidden">
                     <div className="h-full bg-cyan-500" style={{ width: `${speedKmH}%` }} />
                   </div>
                 </div>
               );
             })}
           </div>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-amber-400 mb-1"><CheckCircle2 className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Efficiency</span></div>
            <p className="text-2xl font-black">{stats.produced > 0 ? Math.round((1 - stats.defects / (stats.produced + stats.defects)) * 100) : 100}%</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Speed Multiplier <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

