import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Zap,
  MapPin,
  Cpu
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Base Conveyor
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    // DRAW SPECIAL QUALITY TUNNEL (ÁGUA)
    const agua = STATIONS[21];
    if (agua) {
        const tunnelW = agua.width || 300;
        const tunnelH = agua.height || 80;
        const x = agua.pos.x - tunnelW / 2;
        const y = agua.pos.y - tunnelH / 2;

        // Background Tint
        ctx.fillStyle = 'rgba(191, 219, 254, 0.4)';
        ctx.fillRect(x, y, tunnelW, tunnelH);

        // Tunnel Borders
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 3;
        ctx.strokeRect(x, y, tunnelW, tunnelH);

        // Arrows inside
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        for(let i=0; i<3; i++) {
           const ax = x + 30 + (i * 100);
           const ay = y + tunnelH / 2;
           ctx.beginPath();
           ctx.moveTo(ax, ay - 10);
           ctx.lineTo(ax + 20, ay);
           ctx.lineTo(ax, ay + 10);
           ctx.fill();
           ctx.font = 'bold 8px Arial';
           ctx.fillStyle = 'rgba(0,0,0,0.3)';
           ctx.fillText('ÁGUA', ax - 5, ay + 2);
        }

        // Labels Qt. 2, Qt. 5 (Traffic Lights)
        const drawLight = (lx: number, ly: number, label: string) => {
           ctx.fillStyle = '#334155';
           ctx.fillRect(lx - 5, ly - 15, 10, 30);
           ctx.fillStyle = '#22c55e';
           ctx.beginPath();
           ctx.arc(lx, ly - 5, 3, 0, Math.PI*2);
           ctx.fill();
           ctx.fillStyle = COLORS.TEXT;
           ctx.font = 'bold 10px Arial';
           ctx.fillText(label, lx + 10, ly);
        };
        drawLight(x + 20, y - 20, 'Qt. 2');
        drawLight(x + 200, y + tunnelH + 20, 'Qt. 5');

        // Status Boxes T.50, T.51, T.52
        const drawStatusBox = (bx: number, by: number, label: string, color = '#15803d') => {
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.roundRect(bx, by, 35, 20, 4);
            ctx.fill();
            ctx.fillStyle = 'white';
            ctx.font = 'bold 9px Arial';
            ctx.fillText(label, bx + 6, by + 13);
        };
        drawStatusBox(x + 50, y + tunnelH + 10, 'T.50');
        drawStatusBox(x + 100, y + tunnelH + 10, 'T.51');
        drawStatusBox(x + 150, y + tunnelH + 10, 'T.52');
    }

    // RUIDO ZONE
    const ruido = STATIONS[22];
    if (ruido) {
        const rw = ruido.width || 140;
        const rh = 80;
        const rx = ruido.pos.x - rw / 2;
        const ry = ruido.pos.y - rh / 2;

        ctx.setLineDash([5, 5]);
        ctx.strokeStyle = 'rgba(255,255,255,0.3)';
        ctx.strokeRect(rx, ry, rw, rh);
        ctx.setLineDash([]);

        // Status Boxes T.53, T.54
        const drawStatusBox = (bx: number, by: number, label: string, color = '#15803d') => {
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.roundRect(bx, by, 35, 20, 4);
            ctx.fill();
            ctx.fillStyle = 'white';
            ctx.font = 'bold 9px Arial';
            ctx.fillText(label, bx + 6, by + 13);
        };
        drawStatusBox(rx + rw - 40, ry + rh - 10, 'T.53');
        drawStatusBox(rx + 10, ry + 10, 'T.54', '#3b82f6');

        // Arrow
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        ctx.beginPath();
        ctx.moveTo(rx + 30, ry + rh/2 - 10);
        ctx.lineTo(rx + 50, ry + rh/2);
        ctx.lineTo(rx + 30, ry + rh/2 + 10);
        ctx.fill();
        ctx.font = 'bold 8px Arial';
        ctx.fillStyle = 'rgba(0,0,0,0.3)';
        ctx.fillText('RUIDO', rx + 30, ry + rh/2 + 2);
    }

    // DRAW STATION BOXES (Production standard)
    const renderBox = (name: string, x: number, y: number, w: number, h: number) => {
        ctx.setLineDash([]);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.roundRect(x - w/2 - 5, y - h/2 - 5, w + 10, h + 50, 2);
        ctx.stroke();

        ctx.fillStyle = '#1e3a8a';
        ctx.font = 'italic bold 12px Arial';
        ctx.fillText(name, x - w/2, y + h/2 + 30);
    };

    renderBox('ÁREA BRANCA', 150, 700, 140, 60);
    renderBox('FUNILARIA', 350, 700, 140, 60);
    renderBox('FET', 550, 700, 140, 60);

    // Animated dots
    ctx.lineWidth = 2;
    ctx.strokeStyle = COLORS.YELLOW_PATH;
    const drawAnimatedDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i];
        const p2 = pts[i+1];
        const dx = p2.x - p1.x;
        const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        const nx = dx / dist;
        const ny = dy / dist;
        for (let d = (animOffsetRef.current % 30); d < dist; d += 30) {
          ctx.beginPath();
          ctx.arc(p1.x + nx * d, p1.y + ny * d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawAnimatedDots(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawAnimatedDots(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(b => drawAnimatedDots(b));

    // Render Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      // Don't draw the tunnel stations as boxes here (already handled or simplified)
      if (s.name === 'ÁGUA' || s.name === 'RUIDO') return;

      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let status = "Idle";
      if (vehicleAtStation) status = vehicleAtStation.waitingTimer > 0 ? "Processing" : "Occupied";

      let baseColor = COLORS.STATION;
      if (status === "Processing") baseColor = COLORS.STATION_PROCESSING;
      else if (status === "Occupied") baseColor = COLORS.STATION_HOLDING;

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter, sans-serif';
      ctx.fillText(s.name, x + 8, y + 25);
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(v.pos.x - vw / 2, v.pos.y - vh / 2, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = '#ffffff';
      ctx.lineWidth = 1;
      ctx.stroke();

      if (v.waitingTimer > 0) {
        const totalWait = [...Object.values(STATIONS), ...PARALLEL_ROLL_STATIONS, ...Object.values(REPAIR_STATIONS)].find(
            s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5
        )?.wait || 100;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(v.pos.x - vw / 2, v.pos.y - vh / 2 - 8, vw * prog, 4);
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.4', 50, 40);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Speed Multiplier <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Zap,
  MapPin,
  Cpu
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Base Conveyor
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    // DRAW SPECIAL QUALITY TUNNEL (ÁGUA)
    const agua = STATIONS[21];
    if (agua) {
        const tunnelW = agua.width || 300;
        const tunnelH = agua.height || 80;
        const x = agua.pos.x - tunnelW / 2;
        const y = agua.pos.y - tunnelH / 2;

        // Background Tint
        ctx.fillStyle = 'rgba(191, 219, 254, 0.4)';
        ctx.fillRect(x, y, tunnelW, tunnelH);

        // Tunnel Borders
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 3;
        ctx.strokeRect(x, y, tunnelW, tunnelH);

        // Arrows inside
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        for(let i=0; i<3; i++) {
           const ax = x + 30 + (i * 100);
           const ay = y + tunnelH / 2;
           ctx.beginPath();
           ctx.moveTo(ax, ay - 10);
           ctx.lineTo(ax + 20, ay);
           ctx.lineTo(ax, ay + 10);
           ctx.fill();
           ctx.font = 'bold 8px Arial';
           ctx.fillStyle = 'rgba(0,0,0,0.3)';
           ctx.fillText('ÁGUA', ax - 5, ay + 2);
        }

        // Labels Qt. 2, Qt. 5 (Traffic Lights)
        const drawLight = (lx: number, ly: number, label: string) => {
           ctx.fillStyle = '#334155';
           ctx.fillRect(lx - 5, ly - 15, 10, 30);
           ctx.fillStyle = '#22c55e';
           ctx.beginPath();
           ctx.arc(lx, ly - 5, 3, 0, Math.PI*2);
           ctx.fill();
           ctx.fillStyle = COLORS.TEXT;
           ctx.font = 'bold 10px Arial';
           ctx.fillText(label, lx + 10, ly);
        };
        drawLight(x + 20, y - 20, 'Qt. 2');
        drawLight(x + 200, y + tunnelH + 20, 'Qt. 5');

        // Status Boxes T.50, T.51, T.52
        const drawStatusBox = (bx: number, by: number, label: string, color = '#15803d') => {
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.roundRect(bx, by, 35, 20, 4);
            ctx.fill();
            ctx.fillStyle = 'white';
            ctx.font = 'bold 9px Arial';
            ctx.fillText(label, bx + 6, by + 13);
        };
        drawStatusBox(x + 50, y + tunnelH + 10, 'T.50');
        drawStatusBox(x + 100, y + tunnelH + 10, 'T.51');
        drawStatusBox(x + 150, y + tunnelH + 10, 'T.52');
    }

    // RUIDO ZONE
    const ruido = STATIONS[22];
    if (ruido) {
        const rw = ruido.width || 140;
        const rh = 80;
        const rx = ruido.pos.x - rw / 2;
        const ry = ruido.pos.y - rh / 2;

        ctx.setLineDash([5, 5]);
        ctx.strokeStyle = 'rgba(255,255,255,0.3)';
        ctx.strokeRect(rx, ry, rw, rh);
        ctx.setLineDash([]);

        // Status Boxes T.53, T.54
        const drawStatusBox = (bx: number, by: number, label: string, color = '#15803d') => {
            ctx.fillStyle = color;
            ctx.beginPath();
            ctx.roundRect(bx, by, 35, 20, 4);
            ctx.fill();
            ctx.fillStyle = 'white';
            ctx.font = 'bold 9px Arial';
            ctx.fillText(label, bx + 6, by + 13);
        };
        drawStatusBox(rx + rw - 40, ry + rh - 10, 'T.53');
        drawStatusBox(rx + 10, ry + 10, 'T.54', '#3b82f6');

        // Arrow
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        ctx.beginPath();
        ctx.moveTo(rx + 30, ry + rh/2 - 10);
        ctx.lineTo(rx + 50, ry + rh/2);
        ctx.lineTo(rx + 30, ry + rh/2 + 10);
        ctx.fill();
        ctx.font = 'bold 8px Arial';
        ctx.fillStyle = 'rgba(0,0,0,0.3)';
        ctx.fillText('RUIDO', rx + 30, ry + rh/2 + 2);
    }

    // DRAW STATION BOXES (Production standard)
    const renderBox = (name: string, x: number, y: number, w: number, h: number) => {
        ctx.setLineDash([]);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.roundRect(x - w/2 - 5, y - h/2 - 5, w + 10, h + 50, 2);
        ctx.stroke();

        ctx.fillStyle = '#1e3a8a';
        ctx.font = 'italic bold 12px Arial';
        ctx.fillText(name, x - w/2, y + h/2 + 30);
    };

    renderBox('ÁREA BRANCA', 150, 700, 140, 60);
    renderBox('FUNILARIA', 350, 700, 140, 60);
    renderBox('FET', 550, 700, 140, 60);

    // Animated dots
    ctx.lineWidth = 2;
    ctx.strokeStyle = COLORS.YELLOW_PATH;
    const drawAnimatedDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i];
        const p2 = pts[i+1];
        const dx = p2.x - p1.x;
        const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        const nx = dx / dist;
        const ny = dy / dist;
        for (let d = (animOffsetRef.current % 30); d < dist; d += 30) {
          ctx.beginPath();
          ctx.arc(p1.x + nx * d, p1.y + ny * d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawAnimatedDots(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawAnimatedDots(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(b => drawAnimatedDots(b));

    // Render Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      // Don't draw the tunnel stations as boxes here (already handled or simplified)
      if (s.name === 'ÁGUA' || s.name === 'RUIDO') return;

      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let status = "Idle";
      if (vehicleAtStation) status = vehicleAtStation.waitingTimer > 0 ? "Processing" : "Occupied";

      let baseColor = COLORS.STATION;
      if (status === "Processing") baseColor = COLORS.STATION_PROCESSING;
      else if (status === "Occupied") baseColor = COLORS.STATION_HOLDING;

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter, sans-serif';
      ctx.fillText(s.name, x + 8, y + 25);
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(v.pos.x - vw / 2, v.pos.y - vh / 2, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = '#ffffff';
      ctx.lineWidth = 1;
      ctx.stroke();

      if (v.waitingTimer > 0) {
        const totalWait = [...Object.values(STATIONS), ...PARALLEL_ROLL_STATIONS, ...Object.values(REPAIR_STATIONS)].find(
            s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5
        )?.wait || 100;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(v.pos.x - vw / 2, v.pos.y - vh / 2 - 8, vw * prog, 4);
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.4', 50, 40);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Speed Multiplier <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Defect Rate (FAI QC) <span>{Math.round(defectRate * 100)}%</span></label>
            <input type="range" min="0" max="1" step="0.01" value={defectRate} onChange={(e) => setDefectRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  isBlocked?: boolean;
  color: string;
  finished: boolean;
  progress: number;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Zap,
  MapPin,
  Cpu
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      isBlocked: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        v.isBlocked = false;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      // Check for blocking (simple collision avoidance)
      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const dx = other.pos.x - v.pos.x;
        const dy = other.pos.y - v.pos.y;
        const distSq = dx * dx + dy * dy;
        // Block if another vehicle is ahead within 48 pixels
        return distSq < 48 * 48 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        v.isBlocked = true;
        continue;
      }
      v.isBlocked = false;

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Base Conveyor
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    // DRAW SPECIAL QUALITY TUNNEL (ÁGUA)
    const agua = STATIONS[21];
    if (agua) {
        const tunnelW = agua.width || 300;
        const tunnelH = agua.height || 80;
        const x = agua.pos.x - tunnelW / 2;
        const y = agua.pos.y - tunnelH / 2;

        const vehicleAtTunnel = vehiclesRef.current.some(v => 
          v.pos.x >= x && v.pos.x <= x + tunnelW && 
          Math.abs(v.pos.y - agua.pos.y) < 20
        );

        // Background Tint
        ctx.fillStyle = vehicleAtTunnel ? 'rgba(56, 189, 248, 0.2)' : 'rgba(191, 219, 254, 0.4)';
        ctx.fillRect(x, y, tunnelW, tunnelH);

        // Tunnel Borders
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 3;
        ctx.strokeRect(x, y, tunnelW, tunnelH);

        // Arrows inside
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        for(let i=0; i<3; i++) {
           const ax = x + 30 + (i * 100);
           const ay = y + tunnelH / 2;
           ctx.beginPath();
           ctx.moveTo(ax, ay - 10);
           ctx.lineTo(ax + 20, ay);
           ctx.lineTo(ax, ay + 10);
           ctx.fill();
        }
    }

    // DRAW STATION BOXES (Production standard groups)
    const renderBox = (name: string, x: number, y: number, w: number, h: number) => {
        ctx.setLineDash([]);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.roundRect(x - w/2 - 5, y - h/2 - 5, w + 10, h + 50, 2);
        ctx.stroke();

        ctx.fillStyle = '#1e3a8a';
        ctx.font = 'italic bold 12px Arial';
        ctx.fillText(name, x - w/2, y + h/2 + 30);
    };

    renderBox('ÁREA BRANCA', 150, 700, 140, 60);
    renderBox('FUNILARIA', 350, 700, 140, 60);
    renderBox('FET', 550, 700, 140, 60);

    // Render Stations with Status Indicators
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      // Custom handling for Water and Noise zones for standard display
      if (s.name === 'ÁGUA' || s.name === 'RUIDO') return;

      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let status: 'Idle' | 'Processing' | 'Blocked' | 'Occupied' = "Idle";
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = "Processing";
        else if (vehicleAtStation.isBlocked) status = "Blocked";
        else status = "Occupied";
      }

      let baseColor = COLORS.STATION;
      let ledColor = '#64748b'; // Idle grey

      if (status === "Processing") {
        baseColor = COLORS.STATION_PROCESSING;
        ledColor = '#22c55e'; // Green
        // Pulse effect for processing
        const pulse = (Math.sin(frameCountRef.current / 10) + 1) / 2;
        ctx.fillStyle = `rgba(34, 197, 94, ${0.1 * pulse})`;
        ctx.beginPath();
        ctx.roundRect(x - 5, y - 5, w + 10, h + 10, 8);
        ctx.fill();
      } else if (status === "Blocked") {
        baseColor = '#991b1b'; // Dark Red
        ledColor = '#ef4444'; // Bright Red
      } else if (status === "Occupied") {
        baseColor = COLORS.STATION_HOLDING;
        ledColor = '#f59e0b'; // Amber
      }

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      // Status LED
      ctx.fillStyle = ledColor;
      ctx.beginPath();
      ctx.arc(x + 12, y + 12, 4, 0, Math.PI * 2);
      ctx.fill();
      if (status !== 'Idle') {
         ctx.shadowBlur = 8;
         ctx.shadowColor = ledColor;
         ctx.stroke();
         ctx.shadowBlur = 0;
      }

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter, sans-serif';
      ctx.fillText(s.name, x + 22, y + 15);

      // Status Label
      ctx.font = '8px Inter, sans-serif';
      ctx.fillStyle = 'rgba(255,255,255,0.6)';
      ctx.fillText(status.toUpperCase(), x + 22, y + 25);
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const vx = v.pos.x - vw / 2;
      const vy = v.pos.y - vh / 2;

      // Draw vehicle shadow if moving
      if (!v.isBlocked && v.waitingTimer === 0) {
        ctx.fillStyle = 'rgba(0,0,0,0.2)';
        ctx.beginPath();
        ctx.roundRect(vx + 2, vy + 4, vw, vh, 4);
        ctx.fill();
      }

      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(vx, vy, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = v.isBlocked ? '#ef4444' : '#ffffff';
      ctx.lineWidth = v.isBlocked ? 2 : 1;
      ctx.stroke();

      if (v.waitingTimer > 0) {
        const totalWait = [...Object.values(STATIONS), ...PARALLEL_ROLL_STATIONS, ...Object.values(REPAIR_STATIONS)].find(
            s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5
        )?.wait || 100;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(vx, vy - 8, vw * prog, 4);
      }

      // Blocked Indicator
      if (v.isBlocked) {
        ctx.fillStyle = '#ef4444';
        ctx.font = 'bold 10px Arial';
        ctx.fillText('!', vx + vw/2 - 2, vy + vh/2 + 4);
      }
    });

    // Final UI overlay
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.5', 50, 40);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 col-span-2">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active Units</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Conveyor Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">FAI QC Defect Rate <span>{Math.round(defectRate * 100)}%</span></label>
            <input type="range" min="0" max="1" step="0.01" value={defectRate} onChange={(e) => setDefectRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Zap,
  MapPin,
  Cpu,
  Gauge
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      isBlocked: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        v.isBlocked = false;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const dx = other.pos.x - v.pos.x;
        const dy = other.pos.y - v.pos.y;
        const distSq = dx * dx + dy * dy;
        return distSq < 48 * 48 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        v.isBlocked = true;
        continue;
      }
      v.isBlocked = false;

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 30;
    // Background arc
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 6;
    ctx.stroke();

    // Value arc
    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 6;
    ctx.stroke();

    // Numerical text
    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 12px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)}`, x, y - 5);
    ctx.font = '8px Arial';
    ctx.fillText('km/h', x, y + 8);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Base Conveyor
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    // DRAW SPECIAL QUALITY TUNNEL (ÁGUA)
    const agua = STATIONS[21];
    if (agua) {
        const tunnelW = agua.width || 300;
        const tunnelH = agua.height || 80;
        const x = agua.pos.x - tunnelW / 2;
        const y = agua.pos.y - tunnelH / 2;
        const vehicleAtTunnel = vehiclesRef.current.some(v => v.pos.x >= x && v.pos.x <= x + tunnelW && Math.abs(v.pos.y - agua.pos.y) < 20);
        ctx.fillStyle = vehicleAtTunnel ? 'rgba(56, 189, 248, 0.2)' : 'rgba(191, 219, 254, 0.4)';
        ctx.fillRect(x, y, tunnelW, tunnelH);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 3;
        ctx.strokeRect(x, y, tunnelW, tunnelH);
    }

    // Render Stations with Status Indicators
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      if (s.name === 'ÁGUA' || s.name === 'RUIDO') return;

      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let status: 'Idle' | 'Processing' | 'Blocked' | 'Occupied' = "Idle";
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = "Processing";
        else if (vehicleAtStation.isBlocked) status = "Blocked";
        else status = "Occupied";
      }

      let baseColor = COLORS.STATION;
      let ledColor = '#64748b'; 

      if (status === "Processing") {
        baseColor = COLORS.STATION_PROCESSING;
        ledColor = '#22c55e';
        const pulse = (Math.sin(frameCountRef.current / 10) + 1) / 2;
        ctx.fillStyle = `rgba(34, 197, 94, ${0.1 * pulse})`;
        ctx.beginPath();
        ctx.roundRect(x - 5, y - 5, w + 10, h + 10, 8);
        ctx.fill();

        // Speedometer for Roll Test
        if (s.name.includes('Teste Rolo')) {
          const totalWait = s.wait;
          const prog = 1 - (vehicleAtStation!.waitingTimer / totalWait);
          // Speed ramps up from 0 to ~95 and fluctuates
          let virtualSpeed = 0;
          if (prog < 0.6) {
            virtualSpeed = prog * 150; // Ramp up to 90
          } else {
            virtualSpeed = 90 + Math.sin(frameCountRef.current / 3) * 5; // Fluctuate around 90
          }
          drawSpeedometer(ctx, s.pos.x, s.pos.y - 40, Math.min(100, virtualSpeed));
        }
      } else if (status === "Blocked") {
        baseColor = '#991b1b';
        ledColor = '#ef4444';
      } else if (status === "Occupied") {
        baseColor = COLORS.STATION_HOLDING;
        ledColor = '#f59e0b';
      }

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.fillStyle = ledColor;
      ctx.beginPath();
      ctx.arc(x + 12, y + 12, 4, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter, sans-serif';
      ctx.fillText(s.name, x + 22, y + 15);

      ctx.font = '8px Inter, sans-serif';
      ctx.fillStyle = 'rgba(255,255,255,0.6)';
      ctx.fillText(status.toUpperCase(), x + 22, y + 25);
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const vx = v.pos.x - vw / 2;
      const vy = v.pos.y - vh / 2;

      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(vx, vy, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = v.isBlocked ? '#ef4444' : '#ffffff';
      ctx.lineWidth = v.isBlocked ? 2 : 1;
      ctx.stroke();

      if (v.waitingTimer > 0) {
        const totalWait = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5)?.wait || 100;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(vx, vy - 8, vw * prog, 4);
      }

      if (v.isBlocked) {
        ctx.fillStyle = '#ef4444';
        ctx.font = 'bold 10px Arial';
        ctx.fillText('!', vx + vw/2 - 2, vy + vh/2 + 4);
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.6', 50, 40);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 col-span-2">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active Units</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Conveyor Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">FAI QC Defect Rate <span>{Math.round(defectRate * 100)}%</span></label>
            <input type="range" min="0" max="1" step="0.01" value={defectRate} onChange={(e) => setDefectRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

