import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Zap,
  MapPin,
  Cpu,
  Gauge
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      isBlocked: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        v.isBlocked = false;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const dx = other.pos.x - v.pos.x;
        const dy = other.pos.y - v.pos.y;
        const distSq = dx * dx + dy * dy;
        return distSq < 48 * 48 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        v.isBlocked = true;
        continue;
      }
      v.isBlocked = false;

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 30;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 6;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 6;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 12px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)}`, x, y - 5);
    ctx.font = '8px Arial';
    ctx.fillText('km/h', x, y + 8);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Base Conveyor
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    // DRAW SPECIAL QUALITY TUNNEL (ÁGUA)
    const agua = STATIONS[21];
    if (agua) {
        const tunnelW = agua.width || 300;
        const tunnelH = agua.height || 80;
        const x = agua.pos.x - tunnelW / 2;
        const y = agua.pos.y - tunnelH / 2;
        const vehicleAtTunnel = vehiclesRef.current.some(v => v.pos.x >= x && v.pos.x <= x + tunnelW && Math.abs(v.pos.y - agua.pos.y) < 20);
        ctx.fillStyle = vehicleAtTunnel ? 'rgba(56, 189, 248, 0.2)' : 'rgba(191, 219, 254, 0.4)';
        ctx.fillRect(x, y, tunnelW, tunnelH);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 3;
        ctx.strokeRect(x, y, tunnelW, tunnelH);
    }

    // DRAW STATION BOXES (Production standard)
    const renderBox = (name: string, x: number, y: number, w: number, h: number) => {
        ctx.setLineDash([]);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.roundRect(x - w/2 - 5, y - h/2 - 5, w + 10, h + 50, 2);
        ctx.stroke();

        ctx.fillStyle = '#1e3a8a';
        ctx.font = 'italic bold 11px Arial';
        ctx.fillText(name, x - w/2, y + h/2 + 30);
    };

    renderBox('ÁREA BRANCA', MAIN_PATH_POINTS[18].x, MAIN_PATH_POINTS[18].y, 110, 45);
    renderBox('FUNILARIA', MAIN_PATH_POINTS[19].x, MAIN_PATH_POINTS[19].y, 110, 45);
    renderBox('FET', MAIN_PATH_POINTS[20].x, MAIN_PATH_POINTS[20].y, 110, 45);

    const fcpa = REPAIR_STATIONS[1];
    renderBox('FCPA / 4 POSTER', fcpa.pos.x, fcpa.pos.y, 110, 45);

    // Render Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      if (s.name === 'ÁGUA' || s.name === 'RUIDO') return;

      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let status: 'Idle' | 'Processing' | 'Blocked' | 'Occupied' = "Idle";
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = "Processing";
        else if (vehicleAtStation.isBlocked) status = "Blocked";
        else status = "Occupied";
      }

      let baseColor = COLORS.STATION;
      let ledColor = '#64748b'; 

      if (status === "Processing") {
        baseColor = COLORS.STATION_PROCESSING;
        ledColor = '#22c55e';
        const pulse = (Math.sin(frameCountRef.current / 10) + 1) / 2;
        ctx.fillStyle = `rgba(34, 197, 94, ${0.1 * pulse})`;
        ctx.beginPath();
        ctx.roundRect(x - 5, y - 5, w + 10, h + 10, 8);
        ctx.fill();

        if (s.name.includes('Teste Rolo')) {
          const totalWait = s.wait;
          const prog = 1 - (vehicleAtStation!.waitingTimer / totalWait);
          let virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
          drawSpeedometer(ctx, s.pos.x, s.pos.y - 40, Math.min(100, virtualSpeed));
        }
      } else if (status === "Blocked") {
        baseColor = '#991b1b';
        ledColor = '#ef4444';
      } else if (status === "Occupied") {
        baseColor = COLORS.STATION_HOLDING;
        ledColor = '#f59e0b';
      }

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.fillStyle = ledColor;
      ctx.beginPath();
      ctx.arc(x + 12, y + 12, 4, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter, sans-serif';
      ctx.fillText(s.name, x + 22, y + 15);

      ctx.font = '8px Inter, sans-serif';
      ctx.fillStyle = 'rgba(255,255,255,0.6)';
      ctx.fillText(status.toUpperCase(), x + 22, y + 25);
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const vx = v.pos.x - vw / 2;
      const vy = v.pos.y - vh / 2;

      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(vx, vy, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = v.isBlocked ? '#ef4444' : '#ffffff';
      ctx.lineWidth = v.isBlocked ? 2 : 1;
      ctx.stroke();

      if (v.waitingTimer > 0) {
        const totalWait = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5)?.wait || 100;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(vx, vy - 8, vw * prog, 4);
      }

      if (v.isBlocked) {
        ctx.fillStyle = '#ef4444';
        ctx.font = 'bold 10px Arial';
        ctx.fillText('!', vx + vw/2 - 2, vy + vh/2 + 4);
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.7', 50, 40);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 col-span-2">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active Units</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Conveyor Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">FAI QC Defect Rate <span>{Math.round(defectRate * 100)}%</span></label>
            <input type="range" min="0" max="1" step="0.01" value={defectRate} onChange={(e) => setDefectRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Zap,
  MapPin,
  Cpu,
  Gauge,
  Wifi,
  Terminal
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.5);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const mousePosRef = useRef<Point | null>(null);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = SIM_WIDTH / rect.width;
    const scaleY = SIM_HEIGHT / rect.height;
    mousePosRef.current = {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      isBlocked: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    let j = currentVehicles.length;
    while(j--) {
      const v = currentVehicles[j];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        v.isBlocked = false;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(j, 1);
        continue;
      }

      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const dx = other.pos.x - v.pos.x;
        const dy = other.pos.y - v.pos.y;
        const distSq = dx * dx + dy * dy;
        return distSq < 48 * 48 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        v.isBlocked = true;
        continue;
      }
      v.isBlocked = false;

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 350 : lIdx === 1 ? 420 : 490))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));

           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        let station: Station | undefined;
        if (v.inRepair) {
          station = REPAIR_STATIONS[v.pathIdx];
        } else {
          station = STATIONS[v.pathIdx];
          if (!station) {
            station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
          }
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 30;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 6;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 6;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 12px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)}`, x, y - 5);
    ctx.font = '8px Arial';
    ctx.fillText('km/h', x, y + 8);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Base Conveyor
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 26;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    const drawLine = (pts: Point[]) => {
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    drawLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    drawLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    ROLL_TEST_BRANCHES.forEach(branch => drawLine(branch));
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 22;
    drawLine(REPAIR_PATH_POINTS);

    // DRAW SPECIAL QUALITY TUNNEL (ÁGUA)
    const agua = STATIONS[21];
    if (agua) {
        const tunnelW = agua.width || 300;
        const tunnelH = agua.height || 80;
        const x = agua.pos.x - tunnelW / 2;
        const y = agua.pos.y - tunnelH / 2;
        const vehicleAtTunnel = vehiclesRef.current.some(v => v.pos.x >= x && v.pos.x <= x + tunnelW && Math.abs(v.pos.y - agua.pos.y) < 20);
        ctx.fillStyle = vehicleAtTunnel ? 'rgba(56, 189, 248, 0.2)' : 'rgba(191, 219, 254, 0.4)';
        ctx.fillRect(x, y, tunnelW, tunnelH);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 3;
        ctx.strokeRect(x, y, tunnelW, tunnelH);
    }

    // DRAW STATION BOXES
    const renderBox = (name: string, x: number, y: number, w: number, h: number) => {
        ctx.setLineDash([]);
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.roundRect(x - w/2 - 5, y - h/2 - 5, w + 10, h + 50, 2);
        ctx.stroke();

        ctx.fillStyle = '#1e3a8a';
        ctx.font = 'italic bold 11px Arial';
        ctx.fillText(name, x - w/2, y + h/2 + 30);
    };

    renderBox('ÁREA BRANCA', MAIN_PATH_POINTS[18].x, MAIN_PATH_POINTS[18].y, 110, 45);
    renderBox('FUNILARIA', MAIN_PATH_POINTS[19].x, MAIN_PATH_POINTS[19].y, 110, 45);
    renderBox('FET', MAIN_PATH_POINTS[20].x, MAIN_PATH_POINTS[20].y, 110, 45);

    const fcpa = REPAIR_STATIONS[1];
    renderBox('FCPA / 4 POSTER', fcpa.pos.x, fcpa.pos.y, 110, 45);

    // Render Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      if (s.name === 'ÁGUA' || s.name === 'RUIDO') return;

      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => 
        Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5
      );

      let status: 'Idle' | 'Processing' | 'Blocked' | 'Occupied' = "Idle";
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = "Processing";
        else if (vehicleAtStation.isBlocked) status = "Blocked";
        else status = "Occupied";
      }

      let baseColor = COLORS.STATION;
      let ledColor = '#64748b'; 

      if (status === "Processing") {
        baseColor = COLORS.STATION_PROCESSING;
        ledColor = '#22c55e';
        const pulse = (Math.sin(frameCountRef.current / 10) + 1) / 2;
        ctx.fillStyle = `rgba(34, 197, 94, ${0.1 * pulse})`;
        ctx.beginPath();
        ctx.roundRect(x - 5, y - 5, w + 10, h + 10, 8);
        ctx.fill();

        if (s.name.includes('Teste Rolo')) {
          const totalWait = s.wait;
          const prog = 1 - (vehicleAtStation!.waitingTimer / totalWait);
          let virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
          drawSpeedometer(ctx, s.pos.x, s.pos.y - 40, Math.min(100, virtualSpeed));
        }
      } else if (status === "Blocked") {
        baseColor = '#991b1b';
        ledColor = '#ef4444';
      } else if (status === "Occupied") {
        baseColor = COLORS.STATION_HOLDING;
        ledColor = '#f59e0b';
      }

      ctx.fillStyle = baseColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.fillStyle = ledColor;
      ctx.beginPath();
      ctx.arc(x + 12, y + 12, 4, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter, sans-serif';
      ctx.fillText(s.name, x + 22, y + 15);

      ctx.font = '8px Inter, sans-serif';
      ctx.fillStyle = 'rgba(255,255,255,0.6)';
      ctx.fillText(status.toUpperCase(), x + 22, y + 25);
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      const vw = 38;
      const vh = 24;
      const vx = v.pos.x - vw / 2;
      const vy = v.pos.y - vh / 2;

      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(vx, vy, vw, vh, 4);
      ctx.fill();
      ctx.strokeStyle = v.isBlocked ? '#ef4444' : '#ffffff';
      ctx.lineWidth = v.isBlocked ? 2 : 1;
      ctx.stroke();

      if (v.waitingTimer > 0) {
        const totalWait = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5)?.wait || 100;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(vx, vy - 8, vw * prog, 4);
      }

      if (v.isBlocked) {
        ctx.fillStyle = '#ef4444';
        ctx.font = 'bold 10px Arial';
        ctx.fillText('!', vx + vw/2 - 2, vy + vh/2 + 4);
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 24px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V5.7', 50, 40);

  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(station => {
      const v = vehiclesRef.current.find(veh => 
        Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5
      );

      let speedVal = 0;
      let progress = 0;
      let ecuStatus = 'OFFLINE';

      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
        ecuStatus = progress > 0.1 ? 'CONNECTED' : 'LINKING';
      }

      return {
        name: station.name,
        unit: v ? v.id.toUpperCase() : '---',
        speed: speedVal,
        ecu: ecuStatus,
        progress
      };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 col-span-2">
            <div className="flex items-center gap-2 text-green-400 mb-1"><Zap className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Active Units</span></div>
            <p className="text-2xl font-black">{stats.active}</p>
          </div>
        </div>

        {/* ECATs Dashboard Section */}
        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-widest"><Cpu className="w-4 h-4" /> ECATs Dashboard</div>
          <div className="flex flex-col gap-3">
            {ecatDashboard.map((rolo, idx) => (
              <div key={idx} className="bg-black/30 border border-slate-800 rounded-xl p-3 flex flex-col gap-2">
                <div className="flex justify-between items-center">
                  <span className="text-[11px] font-bold text-slate-300">{rolo.name}</span>
                  <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-bold ${rolo.ecu === 'CONNECTED' ? 'bg-green-500/20 text-green-400' : rolo.ecu === 'LINKING' ? 'bg-amber-500/20 text-amber-400 animate-pulse' : 'bg-slate-800 text-slate-500'}`}>
                    {rolo.ecu}
                  </span>
                </div>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Terminal className="w-3 h-3 text-blue-400" />
                    <span className="text-[11px] font-mono text-blue-400">{rolo.unit}</span>
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Gauge className="w-3 h-3 text-slate-400" />
                    <span className={`text-sm font-black ${rolo.speed > 85 ? 'text-red-400' : rolo.speed > 0 ? 'text-green-400' : 'text-slate-600'}`}>
                      {Math.round(rolo.speed)} <span className="text-[9px] opacity-50">km/h</span>
                    </span>
                  </div>
                </div>
                <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                  <div 
                    className={`h-full transition-all duration-300 ${rolo.speed > 0 ? 'bg-blue-500' : 'bg-transparent'}`}
                    style={{ width: `${rolo.progress * 100}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Conveyor Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">FAI QC Defect Rate <span>{Math.round(defectRate * 100)}%</span></label>
            <input type="range" min="0" max="1" step="0.01" value={defectRate} onChange={(e) => setDefectRate(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-red-500" />
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Activity className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[11px] space-y-2 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-50">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative overflow-auto bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><MapPin className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Delivery Target</p><p className="text-lg font-bold text-blue-400">Patio Final</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  finished: boolean;
  progress: number;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  CheckCircle2, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Droplets,
  Volume2
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS 
} from './constants';
import { Vehicle, Point, SimulationStats } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: MAIN_PATH_POINTS,
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Rotation
      if (dist > 0.1) {
        v.rotation = Math.atan2(dy, dx);
      }

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        const station = currentMap[v.pathIdx];

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = REPAIR_PATH_POINTS;
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = MAIN_PATH_POINTS;
            v.pathIdx = 18; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 25;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 5;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 5;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 10px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)} km/h`, x, y - 5);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Draw Main Conveyor
    ctx.beginPath();
    ctx.setLineDash([]);
    ctx.strokeStyle = COLORS.CONVEYOR;
    ctx.lineWidth = 32;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.moveTo(MAIN_PATH_POINTS[0].x, MAIN_PATH_POINTS[0].y);
    MAIN_PATH_POINTS.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.stroke();

    // Flow Dots
    ctx.lineWidth = 2;
    ctx.strokeStyle = COLORS.YELLOW_PATH;
    for (let i = 0; i < MAIN_PATH_POINTS.length - 1; i++) {
      const p1 = MAIN_PATH_POINTS[i];
      const p2 = MAIN_PATH_POINTS[i+1];
      const dx = p2.x - p1.x;
      const dy = p2.y - p1.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist === 0) continue;
      for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
        ctx.beginPath();
        ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2.5, 0, Math.PI * 2);
        ctx.fillStyle = COLORS.YELLOW_PATH;
        ctx.fill();
      }
    }

    // Repair Path
    ctx.beginPath();
    ctx.strokeStyle = '#450a0a';
    ctx.lineWidth = 28;
    ctx.moveTo(REPAIR_PATH_POINTS[0].x, REPAIR_PATH_POINTS[0].y);
    REPAIR_PATH_POINTS.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.stroke();

    // Highlights for Agua and Ruido
    const drawSpecialZone = (x: number, y: number, w: number, h: number, color: string, label: string) => {
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.roundRect(x - w/2, y - h/2, w, h, 10);
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.font = 'bold 9px Arial';
      ctx.fillStyle = '#ffffff';
      ctx.fillText(label, x - w/2 + 5, y - h/2 + 15);
    };

    drawSpecialZone(MAIN_PATH_POINTS[20].x, MAIN_PATH_POINTS[20].y, 180, 70, 'rgba(59, 130, 246, 0.15)', 'WATER SYSTEM');
    drawSpecialZone(MAIN_PATH_POINTS[21].x, MAIN_PATH_POINTS[21].y, 140, 60, 'rgba(139, 92, 246, 0.15)', 'NOISE CHAMBER');

    // Draw Stations
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS)].forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const atStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5);
      const isProcessing = atStation && atStation.waitingTimer > 0;

      ctx.fillStyle = isProcessing ? '#059669' : (s.type === 'REPAIR' ? '#7f1d1d' : COLORS.STATION);
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 6);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = isProcessing ? 3 : 2;
      ctx.stroke();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 11px Inter, sans-serif';
      ctx.fillText(s.name, x + 8, y + 20);

      // Roll Test Speedometer
      if (isProcessing && s.name.includes('Teste Rolo')) {
        const prog = 1 - (atStation.waitingTimer / s.wait);
        const virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        drawSpeedometer(ctx, s.pos.x, s.pos.y - 35, Math.min(100, virtualSpeed));
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      const vw = 45;
      const vh = 24;

      ctx.save();
      ctx.translate(v.pos.x, v.pos.y);
      ctx.rotate(v.rotation);

      // Shadow
      ctx.shadowBlur = 6;
      ctx.shadowColor = 'rgba(0,0,0,0.5)';

      // Image Tint logic (Draw white sprite then color overlay)
      ctx.globalCompositeOperation = 'source-over';
      ctx.drawImage(vehicleImage.current, -vw/2, -vh/2, vw, vh);

      // Color Overlay
      ctx.globalCompositeOperation = 'multiply';
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(-vw/2, -vh/2, vw, vh, 4);
      ctx.fill();

      ctx.globalCompositeOperation = 'source-over';
      ctx.restore();

      // Progress bar if waiting
      if (v.waitingTimer > 0) {
        const totalWait = (v.inRepair ? REPAIR_STATIONS : STATIONS)[v.pathIdx]?.wait || 60;
        const prog = 1 - (v.waitingTimer / totalWait);
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(v.pos.x - 20, v.pos.y - 20, 40, 4);
        ctx.fillStyle = COLORS.PROGRESS;
        ctx.fillRect(v.pos.x - 20, v.pos.y - 20, 40 * prog, 4);
      }
    });

    // Title Overlay
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 26px Inter, sans-serif';
    ctx.fillText('INDUSTRIAL PRODUCTION LINE V4.0', 50, 40);
  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    const rollIndices = [13, 15, 16];
    return rollIndices.map(idx => {
      const station = STATIONS[idx];
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5);
      let speedVal = 0;
      let progress = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
      }
      return { name: station.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
        </div>

        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Cpu className="w-4 h-4" /> ECATs Dashboard</div>
          {ecatDashboard.map((rolo, i) => (
            <div key={i} className="bg-black/30 rounded-xl p-3 border border-slate-800 flex flex-col gap-2">
              <div className="flex justify-between items-center text-[11px] font-bold text-slate-400">
                <span>{rolo.name}</span>
                <span className="text-blue-400 font-mono">{rolo.unit}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2"><Gauge className="w-4 h-4 text-slate-500" /><span className={`text-lg font-black ${rolo.speed > 80 ? 'text-red-400' : 'text-green-400'}`}>{Math.round(rolo.speed)} <small className="text-[10px] opacity-50">km/h</small></span></div>
                <div className="w-16 h-1 bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-blue-500" style={{ width: `${rolo.progress * 100}%` }} /></div>
              </div>
            </div>
          ))}
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>{isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}{isRunning ? 'PAUSE' : 'RESUME'}</button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Terminal className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[10px] space-y-1 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-30">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><Truck className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Global Status</p><p className="text-lg font-bold text-blue-400">Production Live</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

