           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];

           // Construct new path: prefix + branch + suffix
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];

        // Check for parallel stations by position if not in main record
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => 
             Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5
           );
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 17; // Index of Area Branca in MAIN_PATH_POINTS
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 22;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 4;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 4;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 9px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)} km/h`, x, y - 5);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Conveyors
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath();
      ctx.setLineDash([]);
      ctx.strokeStyle = color;
      ctx.lineWidth = width;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    // Spine 1
    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    // Branches
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    // Spine 2
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    // Repair
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow Dots for Main Spine
    const drawDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i]; const p2 = pts[i+1];
        const dx = p2.x - p1.x; const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
          ctx.beginPath();
          ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawDots(MAIN_PATH_POINTS);

    // Highlights for Agua and Ruido
    const drawSpecialZone = (x: number, y: number, w: number, h: number, color: string, label: string) => {
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.roundRect(x - w/2, y - h/2, w, h, 10);
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,255,255,0.2)';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.font = 'bold 9px Inter';
      ctx.fillStyle = '#ffffff';
      ctx.fillText(label, x - w/2 + 8, y - h/2 + 18);
    };

    const sAgua = STATIONS[19];
    const sRuido = STATIONS[20];
    if (sAgua) drawSpecialZone(sAgua.pos.x, sAgua.pos.y, sAgua.width!, sAgua.height!, 'rgba(59, 130, 246, 0.1)', 'WATER TREATMENT');
    if (sRuido) drawSpecialZone(sRuido.pos.x, sRuido.pos.y, sRuido.width!, sRuido.height!, 'rgba(168, 85, 247, 0.1)', 'ACOUSTIC LAB');

    // Draw Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const atStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 5 && Math.abs(v.pos.y - s.pos.y) < 5);
      const isProcessing = atStation && atStation.waitingTimer > 0;

      // Fix for line 285 error: StationType is now imported
      ctx.fillStyle = isProcessing ? '#059669' : (s.type === StationType.REPAIR ? '#7f1d1d' : COLORS.STATION);
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 4);
      ctx.fill();
      ctx.strokeStyle = COLORS.STATION_BORDER;
      ctx.lineWidth = 1.5;
      ctx.stroke();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter';
      ctx.fillText(s.name, x + 6, y + 18);

      if (isProcessing && s.name.includes('Teste Rolo')) {
        const prog = 1 - (atStation.waitingTimer / s.wait);
        const virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        drawSpeedometer(ctx, s.pos.x, s.pos.y - 30, Math.min(100, virtualSpeed));
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      const vw = 45;
      const vh = 24;

      ctx.save();
      ctx.translate(v.pos.x, v.pos.y);
      ctx.rotate(v.rotation);

      ctx.shadowBlur = 4;
      ctx.shadowColor = 'rgba(0,0,0,0.4)';

      ctx.globalCompositeOperation = 'source-over';
      ctx.drawImage(vehicleImage.current, -vw/2, -vh/2, vw, vh);

      ctx.globalCompositeOperation = 'multiply';
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(-vw/2, -vh/2, vw, vh, 4);
      ctx.fill();

      ctx.globalCompositeOperation = 'source-over';
      ctx.restore();

      if (v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36, 3);
        ctx.fillStyle = COLORS.PROGRESS;
        const station = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5);
        const prog = 1 - (v.waitingTimer / (station?.wait || 60));
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36 * prog, 3);
      }
    });

    // Title
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 22px Inter';
    ctx.fillText('INDUSTRIAL LINE V4.1 - PARALLEL ROLL TEST', 50, 40);
  }, []);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(station => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5);
      let speedVal = 0;
      let progress = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
      }
      return { name: station.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
        </div>

        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-widest"><Cpu className="w-4 h-4" /> Parallel ECATs</div>
          {ecatDashboard.map((rolo, i) => (
            <div key={i} className="bg-black/30 rounded-xl p-3 border border-slate-800 flex flex-col gap-2">
              <div className="flex justify-between items-center text-[10px] font-bold text-slate-400">
                <span>{rolo.name}</span>
                <span className="text-blue-400 font-mono">{rolo.unit}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2"><Gauge className="w-4 h-4 text-slate-500" /><span className={`text-lg font-black ${rolo.speed > 80 ? 'text-red-400' : 'text-green-400'}`}>{Math.round(rolo.speed)} <small className="text-[9px] opacity-50">km/h</small></span></div>
                <div className="w-16 h-1 bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-blue-500" style={{ width: `${rolo.progress * 100}%` }} /></div>
              </div>
            </div>
          ))}
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Line Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>{isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}{isRunning ? 'PAUSE' : 'RESUME'}</button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Terminal className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[10px] space-y-1 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-30">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} className="cursor-crosshair" />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><Truck className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Global Status</p><p className="text-lg font-bold text-blue-400">Production Live</p></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Simple Collision / Blocking Logic
      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        // Only block if other is further along the path or very close
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        continue; // Stay in place if blocked
      }

      if (dist > 0.1) {
        v.rotation = Math.atan2(dy, dx);
      }

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // Handle Parallel Branching at Fork
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];

           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];

        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => 
             Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5
           );
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 17; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));

    // Update hovered station
    if (mousePosRef.current) {
      const allStations = [
        ...Object.values(STATIONS), 
        ...Object.values(REPAIR_STATIONS),
        ...PARALLEL_ROLL_STATIONS
      ];
      const found = allStations.find(s => {
        const w = s.width || 110;
        const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && 
               mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && 
               mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 22;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 4;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 4;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 9px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)} km/h`, x, y - 5);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Render Conveyors
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath();
      ctx.setLineDash([]);
      ctx.strokeStyle = color;
      ctx.lineWidth = width;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow Dots
    const drawDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i]; const p2 = pts[i+1];
        const dx = p2.x - p1.x; const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
          ctx.beginPath();
          ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawDots(MAIN_PATH_POINTS);

    // Draw Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);

      let status: 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED' = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          // Check if vehicle's next move is blocked
          const target = vehicleAtStation.targetPath[vehicleAtStation.pathIdx + 1];
          if (target) {
            const isBlocked = vehiclesRef.current.some(other => {
              if (other.id === vehicleAtStation.id) return false;
              const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
              return distToOther < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
            });
            status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
          } else {
            status = 'OCCUPIED';
          }
        }
      }

      // Visual Status Logic
      let statusColor = '#475569';
      let ledColor = '#1e293b';
      let glow = false;

      switch(status) {
        case 'PROCESSING': 
          statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': 
          statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': 
          statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
        default: 
          statusColor = COLORS.STATION; ledColor = '#1e293b'; break;
      }

      // Hover Effect
      const isHovered = hoveredStationId === s.id;
      if (isHovered) {
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 3;
      } else {
        ctx.strokeStyle = COLORS.STATION_BORDER;
        ctx.lineWidth = 1.5;
      }

      // Glow effect for processing or blocked
      if (glow) {
        ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 5;
        ctx.shadowColor = ledColor;
      } else {
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = statusColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 4);
      ctx.fill();
      ctx.stroke();
      ctx.shadowBlur = 0;

      // Status LED
      ctx.fillStyle = ledColor;
      ctx.beginPath();
      ctx.arc(x + w - 12, y + 12, 4, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter';
      ctx.fillText(s.name, x + 6, y + 18);

      if (status === 'PROCESSING' && s.name.includes('Teste Rolo') && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        const virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        drawSpeedometer(ctx, s.pos.x, s.pos.y - 30, Math.min(100, virtualSpeed));
      }

      // Hover Tooltip on Canvas
      if (isHovered) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';
        ctx.beginPath();
        ctx.roundRect(s.pos.x - 60, s.pos.y - 95, 120, 65, 8);
        ctx.fill();
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 1;
        ctx.stroke();

        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 11px Inter';
        ctx.fillText(s.name, s.pos.x - 50, s.pos.y - 78);

        ctx.font = '9px Inter';
        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`STATUS:`, s.pos.x - 50, s.pos.y - 62);
        ctx.fillStyle = ledColor;
        ctx.fillText(status, s.pos.x - 5, s.pos.y - 62);

        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`UNIT:`, s.pos.x - 50, s.pos.y - 50);
        ctx.fillStyle = '#3b82f6';
        ctx.fillText(vehicleAtStation ? vehicleAtStation.id.toUpperCase() : 'NONE', s.pos.x - 5, s.pos.y - 50);

        if (status === 'PROCESSING' && vehicleAtStation) {
          const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
          ctx.fillStyle = '#1e293b';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100, 3);
          ctx.fillStyle = '#10b981';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100 * prog, 3);
        }
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      const vw = 45;
      const vh = 24;

      ctx.save();
      ctx.translate(v.pos.x, v.pos.y);
      ctx.rotate(v.rotation);

      ctx.shadowBlur = 4;
      ctx.shadowColor = 'rgba(0,0,0,0.4)';

      ctx.globalCompositeOperation = 'source-over';
      ctx.drawImage(vehicleImage.current, -vw/2, -vh/2, vw, vh);

      ctx.globalCompositeOperation = 'multiply';
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(-vw/2, -vh/2, vw, vh, 4);
      ctx.fill();

      ctx.globalCompositeOperation = 'source-over';
      ctx.restore();

      if (v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36, 3);
        ctx.fillStyle = COLORS.PROGRESS;
        const station = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5);
        const prog = 1 - (v.waitingTimer / (station?.wait || 60));
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36 * prog, 3);
      }
    });

    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 22px Inter';
    ctx.fillText('INDUSTRIAL LINE V4.2 - SMART STATIONS', 50, 40);
  }, [hoveredStationId]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(station => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5);
      let speedVal = 0;
      let progress = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
      }
      return { name: station.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
        </div>

        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-widest"><Cpu className="w-4 h-4" /> Parallel ECATs</div>
          {ecatDashboard.map((rolo, i) => (
            <div key={i} className="bg-black/30 rounded-xl p-3 border border-slate-800 flex flex-col gap-2">
              <div className="flex justify-between items-center text-[10px] font-bold text-slate-400">
                <span>{rolo.name}</span>
                <span className="text-blue-400 font-mono">{rolo.unit}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2"><Gauge className="w-4 h-4 text-slate-500" /><span className={`text-lg font-black ${rolo.speed > 80 ? 'text-red-400' : 'text-green-400'}`}>{Math.round(rolo.speed)} <small className="text-[9px] opacity-50">km/h</small></span></div>
                <div className="w-16 h-1 bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-blue-500" style={{ width: `${rolo.progress * 100}%` }} /></div>
              </div>
            </div>
          ))}
        </div>

        <div className="space-y-6 shrink-0">
          <div className="space-y-3">
            <label className="text-xs font-bold text-slate-500 uppercase flex justify-between">Line Speed <span>{speed.toFixed(1)}x</span></label>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700'}`}>{isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}{isRunning ? 'PAUSE' : 'RESUME'}</button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        <div className="flex-1 flex flex-col gap-2 min-h-[150px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase"><Terminal className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[10px] space-y-1 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400' : 'text-slate-500'}`}>
                <span className="opacity-30">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="flex-1 relative bg-[#1e293b] flex items-center justify-center">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">
          <div className="absolute top-4 left-4 flex gap-4 pointer-events-none z-10">
            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 bg-slate-900/80 px-2 py-1 rounded">
              <div className="w-2 h-2 rounded-full bg-slate-600"></div> IDLE
            </div>
            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 bg-slate-900/80 px-2 py-1 rounded">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> PROCESSING
            </div>
            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 bg-slate-900/80 px-2 py-1 rounded">
              <div className="w-2 h-2 rounded-full bg-amber-500"></div> OCCUPIED
            </div>
            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 bg-slate-900/80 px-2 py-1 rounded">
              <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div> BLOCKED
            </div>
          </div>
          <canvas 
            ref={canvasRef} 
            width={SIM_WIDTH} 
            height={SIM_HEIGHT} 
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className="cursor-crosshair" 
          />
        </div>
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><Truck className="w-6 h-6 text-blue-400" /></div>
            <div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Global Status</p><p className="text-lg font-bold text-blue-400">Production Live</p></div>
          </div>
          {hoveredStationId && (
            <div className="bg-blue-600/20 backdrop-blur-md p-3 rounded-xl border border-blue-500/30 animate-in fade-in slide-in-from-top-2">
              <div className="flex items-center gap-2 text-blue-400 font-bold text-xs">
                <Info className="w-3 h-3" /> Station Details Active
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info,
  Layout
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Simple Collision / Blocking Logic
      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        continue; 
      }

      if (dist > 0.1) {
        v.rotation = Math.atan2(dy, dx);
      }

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];

           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];

        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => 
             Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5
           );
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 17; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));

    if (mousePosRef.current) {
      const allStations = [
        ...Object.values(STATIONS), 
        ...Object.values(REPAIR_STATIONS),
        ...PARALLEL_ROLL_STATIONS
      ];
      const found = allStations.find(s => {
        const w = s.width || 110;
        const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && 
               mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && 
               mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawBlueprintGrid = (ctx: CanvasRenderingContext2D) => {
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
    ctx.lineWidth = 1;
    const spacing = 50;

    for (let x = 0; x <= SIM_WIDTH; x += spacing) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, SIM_HEIGHT);
      ctx.stroke();
    }
    for (let y = 0; y <= SIM_HEIGHT; y += spacing) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(SIM_WIDTH, y);
      ctx.stroke();
    }
  };

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 22;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 4;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 4;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 9px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)} km/h`, x, y - 5);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    drawBlueprintGrid(ctx);

    // Render Conveyors
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath();
      ctx.setLineDash([]);
      ctx.strokeStyle = color;
      ctx.lineWidth = width;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow Dots
    const drawDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i]; const p2 = pts[i+1];
        const dx = p2.x - p1.x; const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
          ctx.beginPath();
          ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawDots(MAIN_PATH_POINTS);

    // Draw Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);

      let status: 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED' = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const target = vehicleAtStation.targetPath[vehicleAtStation.pathIdx + 1];
          if (target) {
            const isBlocked = vehiclesRef.current.some(other => {
              if (other.id === vehicleAtStation.id) return false;
              const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
              return distToOther < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
            });
            status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
          } else {
            status = 'OCCUPIED';
          }
        }
      }

      let statusColor = '#475569';
      let ledColor = '#1e293b';
      let glow = false;

      switch(status) {
        case 'PROCESSING': 
          statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': 
          statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': 
          statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
        default: 
          statusColor = COLORS.STATION; ledColor = '#1e293b'; break;
      }

      const isHovered = hoveredStationId === s.id;
      if (isHovered) {
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 3;
      } else {
        ctx.strokeStyle = COLORS.STATION_BORDER;
        ctx.lineWidth = 1.5;
      }

      if (glow) {
        ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 5;
        ctx.shadowColor = ledColor;
      } else {
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = statusColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 4);
      ctx.fill();
      ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = ledColor;
      ctx.beginPath();
      ctx.arc(x + w - 12, y + 12, 4, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter';
      ctx.fillText(s.name, x + 6, y + 18);

      if (status === 'PROCESSING' && s.name.includes('Teste Rolo') && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        const virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        drawSpeedometer(ctx, s.pos.x, s.pos.y - 30, Math.min(100, virtualSpeed));
      }

      if (isHovered) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';
        ctx.beginPath();
        ctx.roundRect(s.pos.x - 60, s.pos.y - 95, 120, 65, 8);
        ctx.fill();
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 1;
        ctx.stroke();

        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 11px Inter';
        ctx.fillText(s.name, s.pos.x - 50, s.pos.y - 78);

        ctx.font = '9px Inter';
        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`STATUS:`, s.pos.x - 50, s.pos.y - 62);
        ctx.fillStyle = ledColor;
        ctx.fillText(status, s.pos.x - 5, s.pos.y - 62);

        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`UNIT:`, s.pos.x - 50, s.pos.y - 50);
        ctx.fillStyle = '#3b82f6';
        ctx.fillText(vehicleAtStation ? vehicleAtStation.id.toUpperCase() : 'NONE', s.pos.x - 5, s.pos.y - 50);

        if (status === 'PROCESSING' && vehicleAtStation) {
          const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
          ctx.fillStyle = '#1e293b';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100, 3);
          ctx.fillStyle = '#10b981';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100 * prog, 3);
        }
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      const vw = 45;
      const vh = 24;

      ctx.save();
      ctx.translate(v.pos.x, v.pos.y);
      ctx.rotate(v.rotation);

      ctx.shadowBlur = 4;
      ctx.shadowColor = 'rgba(0,0,0,0.4)';

      ctx.globalCompositeOperation = 'source-over';
      ctx.drawImage(vehicleImage.current, -vw/2, -vh/2, vw, vh);

      ctx.globalCompositeOperation = 'multiply';
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(-vw/2, -vh/2, vw, vh, 4);
      ctx.fill();

      ctx.globalCompositeOperation = 'source-over';
      ctx.restore();

      if (v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36, 3);
        ctx.fillStyle = COLORS.PROGRESS;
        const station = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5);
        const prog = 1 - (v.waitingTimer / (station?.wait || 60));
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36 * prog, 3);
      }
    });

    // Dashboard HUD Overlay (Inside Canvas but away from controls)
    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.font = 'bold 24px Inter';
    ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 45);
    ctx.font = '10px Inter';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.fillText('SMART STATION NETWORK V4.2 // LIVE TELEMETRY', 50, 62);
  }, [hoveredStationId]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(station => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5);
      let speedVal = 0;
      let progress = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
      }
      return { name: station.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      {/* Sidebar */}
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0 z-20">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/20"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 backdrop-blur-sm">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 backdrop-blur-sm">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
        </div>

        {/* Parallel Monitor */}
        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-widest"><Cpu className="w-4 h-4" /> Parallel ECATs</div>
          {ecatDashboard.map((rolo, i) => (
            <div key={i} className="bg-black/30 rounded-xl p-3 border border-slate-800 flex flex-col gap-2 hover:bg-black/40 transition-colors">
              <div className="flex justify-between items-center text-[10px] font-bold text-slate-400">
                <span>{rolo.name}</span>
                <span className="text-blue-400 font-mono">{rolo.unit}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Gauge className="w-4 h-4 text-slate-500" />
                  <span className={`text-lg font-black tabular-nums ${rolo.speed > 80 ? 'text-red-400' : 'text-green-400'}`}>
                    {Math.round(rolo.speed)} <small className="text-[9px] opacity-50 font-medium tracking-normal">km/h</small>
                  </span>
                </div>
                <div className="w-16 h-1 bg-slate-800 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${rolo.progress * 100}%` }} />
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Controls */}
        <div className="space-y-6 shrink-0 mt-auto">
          <div className="space-y-3">
            <div className="flex justify-between items-center">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Line Speed</label>
              <span className="bg-slate-800 text-blue-400 px-2 py-0.5 rounded text-[10px] font-bold font-mono">{speed.toFixed(1)}x</span>
            </div>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700 shadow-lg shadow-green-900/20'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        {/* Logs */}
        <div className="flex flex-col gap-2 min-h-[140px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-wider"><Terminal className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[10px] space-y-1 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400 animate-in fade-in slide-in-from-left-2' : 'text-slate-500 opacity-80'}`}>
                <span className="opacity-30">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main View Area */}
      <div className="flex-1 relative bg-[#1e293b] flex items-center justify-center overflow-hidden">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">

          {/* Status Legend - Moved to Bottom Left to avoid clashing with Title */}
          <div className="absolute bottom-4 left-4 flex gap-3 pointer-events-none z-10 p-2 rounded-lg bg-slate-950/40 backdrop-blur-sm border border-white/5">
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase tracking-tighter">
              <div className="w-1.5 h-1.5 rounded-full bg-slate-600"></div> IDLE
            </div>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div> PROCESSING
            </div>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div> OCCUPIED
            </div>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse"></div> BLOCKED
            </div>
          </div>

          <canvas 
            ref={canvasRef} 
            width={SIM_WIDTH} 
            height={SIM_HEIGHT} 
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className="cursor-crosshair bg-[#1a2333]" 
          />
        </div>

        {/* Global HUD Widgets */}
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4 animate-in slide-in-from-right-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><Truck className="w-6 h-6 text-blue-400" /></div>
            <div>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Global Status</p>
              <p className="text-lg font-bold text-blue-400 tracking-tight">Production Live</p>
            </div>
          </div>

          {hoveredStationId && (
            <div className="bg-blue-600/10 backdrop-blur-md p-3 rounded-xl border border-blue-500/30 animate-in fade-in slide-in-from-top-2 flex items-center gap-3">
              <Info className="w-4 h-4 text-blue-400" />
              <div className="text-xs font-bold text-blue-300 uppercase tracking-wider">Telemetric focus active</div>
            </div>
          )}
        </div>

        <div className="absolute bottom-8 right-8 bg-slate-900/50 backdrop-blur-sm px-4 py-2 rounded-full border border-slate-700/50 flex items-center gap-2 pointer-events-none opacity-40">
           <Layout className="w-3 h-3 text-slate-400" />
           <span className="text-[10px] font-bold tracking-widest uppercase text-slate-400">Layout Engine 4.2</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info,
  Layout
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0
    };
    vehiclesRef.current.push(newVehicle);
  }, [defectRate]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`Unit ${v.id.toUpperCase()} produced and shipped.`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Simple Collision / Blocking Logic
      const isBlocked = currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        continue; 
      }

      if (dist > 0.1) {
        v.rotation = Math.atan2(dy, dx);
      }

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];

           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];

        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => 
             Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5
           );
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 17; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));

    if (mousePosRef.current) {
      const allStations = [
        ...Object.values(STATIONS), 
        ...Object.values(REPAIR_STATIONS),
        ...PARALLEL_ROLL_STATIONS
      ];
      const found = allStations.find(s => {
        const w = s.width || 110;
        const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && 
               mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && 
               mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawBlueprintGrid = (ctx: CanvasRenderingContext2D) => {
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
    ctx.lineWidth = 1;
    const spacing = 50;

    for (let x = 0; x <= SIM_WIDTH; x += spacing) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, SIM_HEIGHT);
      ctx.stroke();
    }
    for (let y = 0; y <= SIM_HEIGHT; y += spacing) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(SIM_WIDTH, y);
      ctx.stroke();
    }
  };

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    const size = 6;
    ctx.save();
    ctx.translate(cx, cy);

    // Draw LED Circle Base
    ctx.fillStyle = ledColor;
    ctx.beginPath();
    ctx.arc(0, 0, 7, 0, Math.PI * 2);
    ctx.fill();

    // Draw Interior Icon
    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 1.5;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    switch (status) {
      case 'IDLE':
        // Hollow Circle
        ctx.beginPath();
        ctx.arc(0, 0, 3, 0, Math.PI * 2);
        ctx.stroke();
        break;
      case 'PROCESSING':
        // Play Triangle
        ctx.fillStyle = '#ffffff';
        ctx.beginPath();
        ctx.moveTo(-2, -3);
        ctx.lineTo(4, 0);
        ctx.lineTo(-2, 3);
        ctx.closePath();
        ctx.fill();
        break;
      case 'OCCUPIED':
        // Small Square
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(-2.5, -2.5, 5, 5);
        break;
      case 'BLOCKED':
        // Cross (X)
        ctx.beginPath();
        ctx.moveTo(-3, -3);
        ctx.lineTo(3, 3);
        ctx.moveTo(3, -3);
        ctx.lineTo(-3, 3);
        ctx.stroke();
        break;
    }

    ctx.restore();
  };

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 22;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 4;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 4;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 9px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)} km/h`, x, y - 5);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    drawBlueprintGrid(ctx);

    // Render Conveyors
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath();
      ctx.setLineDash([]);
      ctx.strokeStyle = color;
      ctx.lineWidth = width;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow Dots
    const drawDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i]; const p2 = pts[i+1];
        const dx = p2.x - p1.x; const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
          ctx.beginPath();
          ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawDots(MAIN_PATH_POINTS);

    // Draw Stations
    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const target = vehicleAtStation.targetPath[vehicleAtStation.pathIdx + 1];
          if (target) {
            const isBlocked = vehiclesRef.current.some(other => {
              if (other.id === vehicleAtStation.id) return false;
              const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
              return distToOther < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
            });
            status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
          } else {
            status = 'OCCUPIED';
          }
        }
      }

      let statusColor = '#475569';
      let ledColor = '#1e293b';
      let glow = false;

      switch(status) {
        case 'PROCESSING': 
          statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': 
          statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': 
          statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
        default: 
          statusColor = COLORS.STATION; ledColor = '#1e293b'; break;
      }

      const isHovered = hoveredStationId === s.id;
      if (isHovered) {
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 3;
      } else {
        ctx.strokeStyle = COLORS.STATION_BORDER;
        ctx.lineWidth = 1.5;
      }

      if (glow) {
        ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 5;
        ctx.shadowColor = ledColor;
      } else {
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = statusColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 4);
      ctx.fill();
      ctx.stroke();
      ctx.shadowBlur = 0;

      // Status LED with Icon
      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter';
      ctx.fillText(s.name, x + 6, y + 18);

      if (status === 'PROCESSING' && s.name.includes('Teste Rolo') && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        const virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        drawSpeedometer(ctx, s.pos.x, s.pos.y - 30, Math.min(100, virtualSpeed));
      }

      if (isHovered) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';
        ctx.beginPath();
        ctx.roundRect(s.pos.x - 60, s.pos.y - 95, 120, 65, 8);
        ctx.fill();
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 1;
        ctx.stroke();

        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 11px Inter';
        ctx.fillText(s.name, s.pos.x - 50, s.pos.y - 78);

        ctx.font = '9px Inter';
        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`STATUS:`, s.pos.x - 50, s.pos.y - 62);
        ctx.fillStyle = ledColor;
        ctx.fillText(status, s.pos.x - 5, s.pos.y - 62);

        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`UNIT:`, s.pos.x - 50, s.pos.y - 50);
        ctx.fillStyle = '#3b82f6';
        ctx.fillText(vehicleAtStation ? vehicleAtStation.id.toUpperCase() : 'NONE', s.pos.x - 5, s.pos.y - 50);

        if (status === 'PROCESSING' && vehicleAtStation) {
          const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
          ctx.fillStyle = '#1e293b';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100, 3);
          ctx.fillStyle = '#10b981';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100 * prog, 3);
        }
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      const vw = 45;
      const vh = 24;

      ctx.save();
      ctx.translate(v.pos.x, v.pos.y);
      ctx.rotate(v.rotation);

      ctx.shadowBlur = 4;
      ctx.shadowColor = 'rgba(0,0,0,0.4)';

      ctx.globalCompositeOperation = 'source-over';
      ctx.drawImage(vehicleImage.current, -vw/2, -vh/2, vw, vh);

      ctx.globalCompositeOperation = 'multiply';
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(-vw/2, -vh/2, vw, vh, 4);
      ctx.fill();

      ctx.globalCompositeOperation = 'source-over';
      ctx.restore();

      if (v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36, 3);
        ctx.fillStyle = COLORS.PROGRESS;
        const station = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5);
        const prog = 1 - (v.waitingTimer / (station?.wait || 60));
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36 * prog, 3);
      }
    });

    // Dashboard HUD Overlay
    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.font = 'bold 24px Inter';
    ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 45);
    ctx.font = '10px Inter';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.fillText('SMART STATION NETWORK V4.2 // LIVE TELEMETRY', 50, 62);
  }, [hoveredStationId, drawStatusIcon]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ produced: 0, defects: 0, active: 0, cycleTime: 0 });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(station => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5);
      let speedVal = 0;
      let progress = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
      }
      return { name: station.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      {/* Sidebar */}
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0 z-20">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/20"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Factory Control</h1>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 backdrop-blur-sm">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Produced</span></div>
            <p className="text-2xl font-black">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50 backdrop-blur-sm">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Defects</span></div>
            <p className="text-2xl font-black">{stats.defects}</p>
          </div>
        </div>

        {/* Parallel Monitor */}
        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-widest"><Cpu className="w-4 h-4" /> Parallel ECATs</div>
          {ecatDashboard.map((rolo, i) => (
            <div key={i} className="bg-black/30 rounded-xl p-3 border border-slate-800 flex flex-col gap-2 hover:bg-black/40 transition-colors">
              <div className="flex justify-between items-center text-[10px] font-bold text-slate-400">
                <span>{rolo.name}</span>
                <span className="text-blue-400 font-mono">{rolo.unit}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Gauge className="w-4 h-4 text-slate-500" />
                  <span className={`text-lg font-black tabular-nums ${rolo.speed > 80 ? 'text-red-400' : 'text-green-400'}`}>
                    {Math.round(rolo.speed)} <small className="text-[9px] opacity-50 font-medium tracking-normal">km/h</small>
                  </span>
                </div>
                <div className="w-16 h-1 bg-slate-800 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${rolo.progress * 100}%` }} />
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Controls */}
        <div className="space-y-6 shrink-0 mt-auto">
          <div className="space-y-3">
            <div className="flex justify-between items-center">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Line Speed</label>
              <span className="bg-slate-800 text-blue-400 px-2 py-0.5 rounded text-[10px] font-bold font-mono">{speed.toFixed(1)}x</span>
            </div>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-blue-500" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-bold transition-all ${isRunning ? 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20' : 'bg-green-600 text-white hover:bg-green-700 shadow-lg shadow-green-900/20'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={resetSimulation} className="p-3 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>

        {/* Logs */}
        <div className="flex flex-col gap-2 min-h-[140px]">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-wider"><Terminal className="w-3 h-3" /> System Logs</div>
          <div className="flex-1 bg-black/40 rounded-xl p-4 overflow-y-auto font-mono text-[10px] space-y-1 border border-slate-800">
            {logs.map((log, i) => (
              <div key={i} className={`flex gap-2 ${i === 0 ? 'text-blue-400 animate-in fade-in slide-in-from-left-2' : 'text-slate-500 opacity-80'}`}>
                <span className="opacity-30">[{new Date().toLocaleTimeString([], { hour12: false })}]</span>
                <span>{log}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main View Area */}
      <div className="flex-1 relative bg-[#1e293b] flex items-center justify-center overflow-hidden">
        <div className="relative shadow-2xl rounded-lg overflow-hidden border-8 border-slate-900 bg-slate-800">

          {/* Status Legend */}
          <div className="absolute bottom-4 left-4 flex gap-3 pointer-events-none z-10 p-2 rounded-lg bg-slate-950/40 backdrop-blur-sm border border-white/5">
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase tracking-tighter">
              <div className="w-4 h-4 rounded-full bg-slate-600 flex items-center justify-center">
                <div className="w-1.5 h-1.5 rounded-full border border-white/50"></div>
              </div> IDLE
            </div>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-4 h-4 rounded-full bg-emerald-500 flex items-center justify-center animate-pulse">
                <div className="w-0 h-0 border-t-[2px] border-t-transparent border-b-[2px] border-b-transparent border-l-[3px] border-l-white ml-0.5"></div>
              </div> PROCESSING
            </div>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-4 h-4 rounded-full bg-amber-500 flex items-center justify-center">
                <div className="w-2 h-2 bg-white"></div>
              </div> OCCUPIED
            </div>
            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-4 h-4 rounded-full bg-red-500 flex items-center justify-center animate-pulse">
                <div className="text-[8px] font-bold text-white">×</div>
              </div> BLOCKED
            </div>
          </div>

          <canvas 
            ref={canvasRef} 
            width={SIM_WIDTH} 
            height={SIM_HEIGHT} 
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className="cursor-crosshair bg-[#1a2333]" 
          />
        </div>

        {/* Global HUD Widgets */}
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none">
          <div className="bg-slate-900/90 backdrop-blur-md p-4 rounded-2xl border border-slate-700 shadow-xl flex items-center gap-4 animate-in slide-in-from-right-4">
            <div className="p-3 bg-blue-500/20 rounded-full"><Truck className="w-6 h-6 text-blue-400" /></div>
            <div>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Global Status</p>
              <p className="text-lg font-bold text-blue-400 tracking-tight">Production Live</p>
            </div>
          </div>

          {hoveredStationId && (
            <div className="bg-blue-600/10 backdrop-blur-md p-3 rounded-xl border border-blue-500/30 animate-in fade-in slide-in-from-top-2 flex items-center gap-3">
              <Info className="w-4 h-4 text-blue-400" />
              <div className="text-xs font-bold text-blue-300 uppercase tracking-wider">Telemetric focus active</div>
            </div>
          )}
        </div>

        <div className="absolute bottom-8 right-8 bg-slate-900/50 backdrop-blur-sm px-4 py-2 rounded-full border border-slate-700/50 flex items-center gap-2 pointer-events-none opacity-40">
           <Layout className="w-3 h-3 text-slate-400" />
           <span className="text-[10px] font-bold tracking-widest uppercase text-slate-400">Layout Engine 4.2</span>
        </div>
      </div>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  finished: boolean;
  progress: number;
  // Added for tracking and unblocking
  everRepaired: boolean;
  ignoreCollisionTimer: number;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  // Added industrial metrics
  totalStarted: number;
  passedFirstTime: number;
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info,
  Layout,
  Unlock,
  BarChart3,
  CheckCircle2
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL RELEASE: Nudging blocked vehicles...");
    vehiclesRef.current.forEach(v => {
      // Find vehicles that would be blocked
      const isActuallyBlocked = vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 65 && (other.pathIdx >= v.pathIdx);
      });

      if (isActuallyBlocked) {
        v.ignoreCollisionTimer = 120; // 2 seconds of ghosting
      }
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime
        }));
        addLog(`Unit ${v.id.toUpperCase()} produced. FTT: ${passedFtt ? 'YES' : 'NO'}`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Simple Collision / Blocking Logic
      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) {
        continue; 
      }

      if (dist > 0.1) {
        v.rotation = Math.atan2(dy, dx);
      }

      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];

           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];

        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => 
             Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5
           );
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;

          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true;
            v.everRepaired = true;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }

          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false;
            v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS];
            v.pathIdx = 17; 
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio;
        v.pos.y += dy * ratio;
      }
    }

    setStats(s => ({ ...s, active: currentVehicles.length }));

    if (mousePosRef.current) {
      const allStations = [
        ...Object.values(STATIONS), 
        ...Object.values(REPAIR_STATIONS),
        ...PARALLEL_ROLL_STATIONS
      ];
      const found = allStations.find(s => {
        const w = s.width || 110;
        const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && 
               mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && 
               mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawBlueprintGrid = (ctx: CanvasRenderingContext2D) => {
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
    ctx.lineWidth = 1;
    const spacing = 50;

    for (let x = 0; x <= SIM_WIDTH; x += spacing) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, SIM_HEIGHT);
      ctx.stroke();
    }
    for (let y = 0; y <= SIM_HEIGHT; y += spacing) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(SIM_WIDTH, y);
      ctx.stroke();
    }
  };

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save();
    ctx.translate(cx, cy);

    ctx.fillStyle = ledColor;
    ctx.beginPath();
    ctx.arc(0, 0, 7, 0, Math.PI * 2);
    ctx.fill();

    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 1.5;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    switch (status) {
      case 'IDLE':
        ctx.beginPath();
        ctx.arc(0, 0, 3, 0, Math.PI * 2);
        ctx.stroke();
        break;
      case 'PROCESSING':
        ctx.fillStyle = '#ffffff';
        ctx.beginPath();
        ctx.moveTo(-2, -3);
        ctx.lineTo(4, 0);
        ctx.lineTo(-2, 3);
        ctx.closePath();
        ctx.fill();
        break;
      case 'OCCUPIED':
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(-2.5, -2.5, 5, 5);
        break;
      case 'BLOCKED':
        ctx.beginPath();
        ctx.moveTo(-3, -3);
        ctx.lineTo(3, 3);
        ctx.moveTo(3, -3);
        ctx.lineTo(-3, 3);
        ctx.stroke();
        break;
    }

    ctx.restore();
  };

  const drawSpeedometer = (ctx: CanvasRenderingContext2D, x: number, y: number, value: number) => {
    const radius = 22;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, 0);
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 4;
    ctx.stroke();

    const endAngle = Math.PI + (value / 100) * Math.PI;
    ctx.beginPath();
    ctx.arc(x, y, radius, Math.PI, endAngle);
    ctx.strokeStyle = value > 80 ? '#ef4444' : '#22c55e';
    ctx.lineWidth = 4;
    ctx.stroke();

    ctx.fillStyle = COLORS.TEXT;
    ctx.font = 'bold 9px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`${Math.round(value)} km/h`, x, y - 5);
    ctx.textAlign = 'start';
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    drawBlueprintGrid(ctx);

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath();
      ctx.setLineDash([]);
      ctx.strokeStyle = color;
      ctx.lineWidth = width;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y);
      pts.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    const drawDots = (pts: Point[]) => {
      for (let i = 0; i < pts.length - 1; i++) {
        const p1 = pts[i]; const p2 = pts[i+1];
        const dx = p2.x - p1.x; const dy = p2.y - p1.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist === 0) continue;
        for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
          ctx.beginPath();
          ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
          ctx.fillStyle = COLORS.YELLOW_PATH;
          ctx.fill();
        }
      }
    };
    drawDots(MAIN_PATH_POINTS);

    const allStations = [
      ...Object.values(STATIONS), 
      ...Object.values(REPAIR_STATIONS),
      ...PARALLEL_ROLL_STATIONS
    ];

    allStations.forEach(s => {
      const w = s.width || 110;
      const h = s.height || 45;
      const x = s.pos.x - w / 2;
      const y = s.pos.y - h / 2;

      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const target = vehicleAtStation.targetPath[vehicleAtStation.pathIdx + 1];
          if (target) {
            const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
              if (other.id === vehicleAtStation.id) return false;
              const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
              return distToOther < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
            });
            status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
          } else {
            status = 'OCCUPIED';
          }
        }
      }

      let statusColor = '#475569';
      let ledColor = '#1e293b';
      let glow = false;

      switch(status) {
        case 'PROCESSING': 
          statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': 
          statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': 
          statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
        default: 
          statusColor = COLORS.STATION; ledColor = '#1e293b'; break;
      }

      const isHovered = hoveredStationId === s.id;
      if (isHovered) {
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 3;
      } else {
        ctx.strokeStyle = COLORS.STATION_BORDER;
        ctx.lineWidth = 1.5;
      }

      if (glow) {
        ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 5;
        ctx.shadowColor = ledColor;
      } else {
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = statusColor;
      ctx.beginPath();
      ctx.roundRect(x, y, w, h, 4);
      ctx.fill();
      ctx.stroke();
      ctx.shadowBlur = 0;

      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);

      ctx.fillStyle = COLORS.TEXT;
      ctx.font = 'bold 10px Inter';
      ctx.fillText(s.name, x + 6, y + 18);

      if (status === 'PROCESSING' && s.name.includes('Teste Rolo') && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        const virtualSpeed = prog < 0.6 ? prog * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        drawSpeedometer(ctx, s.pos.x, s.pos.y - 30, Math.min(100, virtualSpeed));
      }

      if (isHovered) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.95)';
        ctx.beginPath();
        ctx.roundRect(s.pos.x - 60, s.pos.y - 95, 120, 65, 8);
        ctx.fill();
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 1;
        ctx.stroke();

        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 11px Inter';
        ctx.fillText(s.name, s.pos.x - 50, s.pos.y - 78);

        ctx.font = '9px Inter';
        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`STATUS:`, s.pos.x - 50, s.pos.y - 62);
        ctx.fillStyle = ledColor;
        ctx.fillText(status, s.pos.x - 5, s.pos.y - 62);

        ctx.fillStyle = '#94a3b8';
        ctx.fillText(`UNIT:`, s.pos.x - 50, s.pos.y - 50);
        ctx.fillStyle = '#3b82f6';
        ctx.fillText(vehicleAtStation ? vehicleAtStation.id.toUpperCase() : 'NONE', s.pos.x - 5, s.pos.y - 50);

        if (status === 'PROCESSING' && vehicleAtStation) {
          const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
          ctx.fillStyle = '#1e293b';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100, 3);
          ctx.fillStyle = '#10b981';
          ctx.fillRect(s.pos.x - 50, s.pos.y - 42, 100 * prog, 3);
        }
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      const vw = 45;
      const vh = 24;

      ctx.save();
      ctx.translate(v.pos.x, v.pos.y);
      ctx.rotate(v.rotation);

      if (v.ignoreCollisionTimer > 0) {
        ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      }

      ctx.shadowBlur = 4;
      ctx.shadowColor = 'rgba(0,0,0,0.4)';

      ctx.globalCompositeOperation = 'source-over';
      ctx.drawImage(vehicleImage.current, -vw/2, -vh/2, vw, vh);

      ctx.globalCompositeOperation = 'multiply';
      ctx.fillStyle = v.color;
      ctx.beginPath();
      ctx.roundRect(-vw/2, -vh/2, vw, vh, 4);
      ctx.fill();

      ctx.globalCompositeOperation = 'source-over';
      ctx.restore();

      if (v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36, 3);
        ctx.fillStyle = COLORS.PROGRESS;
        const station = allStations.find(s => Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5);
        const prog = 1 - (v.waitingTimer / (station?.wait || 60));
        ctx.fillRect(v.pos.x - 18, v.pos.y - 20, 36 * prog, 3);
      }
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.font = 'bold 24px Inter';
    ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 45);
    ctx.font = '10px Inter';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
    ctx.fillText('SMART STATION NETWORK V4.3 // TELEMETRY & QUALITY CONTROL', 50, 62);
  }, [hoveredStationId, drawStatusIcon]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const resetSimulation = () => {
    vehiclesRef.current = [];
    setStats({ 
      produced: 0, 
      defects: 0, 
      active: 0, 
      cycleTime: 0, 
      totalStarted: 0, 
      passedFirstTime: 0 
    });
    setLogs(['Simulation reset.']);
    frameCountRef.current = 0;
  };

  const ecatDashboard = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(station => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - station.pos.x) < 5 && Math.abs(veh.pos.y - station.pos.y) < 5);
      let speedVal = 0;
      let progress = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / station.wait);
        speedVal = progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5;
        speedVal = Math.min(100, speedVal);
      }
      return { name: station.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const frtRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  return (
    <div className="flex h-screen w-screen bg-[#0f172a] text-slate-100 overflow-hidden font-sans">
      {/* Sidebar */}
      <div className="w-80 bg-slate-900 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl overflow-y-auto shrink-0 z-20">
        <div className="flex items-center gap-3 mb-2 shrink-0">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/20"><Settings className="w-6 h-6 text-white" /></div>
          <h1 className="text-xl font-bold tracking-tight">Line Control</h1>
        </div>

        {/* Quality Metrics - FTT and FRT */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/80 p-3 rounded-xl border border-blue-500/20 backdrop-blur-sm">
            <div className="flex items-center gap-2 text-blue-400 mb-1"><CheckCircle2 className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">FTT Rate</span></div>
            <p className="text-2xl font-black text-white">{fttRate.toFixed(1)}<span className="text-xs opacity-50 ml-1">%</span></p>
            <div className="h-1 w-full bg-slate-700 rounded-full mt-2 overflow-hidden"><div className="h-full bg-blue-500" style={{ width: `${fttRate}%` }} /></div>
          </div>
          <div className="bg-slate-800/80 p-3 rounded-xl border border-emerald-500/20 backdrop-blur-sm">
            <div className="flex items-center gap-2 text-emerald-400 mb-1"><BarChart3 className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">FRT Yield</span></div>
            <p className="text-2xl font-black text-white">{frtRate.toFixed(1)}<span className="text-xs opacity-50 ml-1">%</span></p>
            <div className="h-1 w-full bg-slate-700 rounded-full mt-2 overflow-hidden"><div className="h-full bg-emerald-500" style={{ width: `${frtRate}%` }} /></div>
          </div>
        </div>

        {/* Traditional Stats Grid */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-slate-400 mb-1"><Activity className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">Finished</span></div>
            <p className="text-2xl font-black tabular-nums">{stats.produced}</p>
          </div>
          <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
            <div className="flex items-center gap-2 text-red-400 mb-1"><AlertTriangle className="w-4 h-4" /><span className="text-[10px] font-bold uppercase tracking-wider">QC Fail</span></div>
            <p className="text-2xl font-black tabular-nums">{stats.defects}</p>
          </div>
        </div>

        {/* Release Button - NEW */}
        <div className="shrink-0 p-4 bg-red-950/20 border border-red-500/20 rounded-2xl">
          <button 
            onClick={releaseBlocked}
            className="w-full flex items-center justify-center gap-3 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-bold transition-all shadow-lg shadow-red-900/20 active:scale-95 group"
          >
            <Unlock className="w-5 h-5 group-hover:rotate-12 transition-transform" />
            LIBERAÇÃO DE BLOQUEIO
          </button>
          <p className="text-[10px] text-red-400/60 text-center mt-2 font-medium tracking-wide">Forces vehicles to bypass collision checks temporarily</p>
        </div>

        {/* Parallel Monitor */}
        <div className="shrink-0 flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-bold text-slate-500 uppercase tracking-widest"><Cpu className="w-4 h-4" /> Parallel ECATs</div>
          {ecatDashboard.map((rolo, i) => (
