            <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-tighter">
              <div className="w-4 h-4 rounded-full bg-emerald-500 flex items-center justify-center animate-pulse">
                <div className="w-0 h-0 border-t-[2px] border-t-transparent border-b-[2px] border-b-transparent border-l-[3px] border-l-white ml-0.5"></div>
              </div> PROCESSING
