import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info,
  Layout,
  Unlock,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Responsive Scaling Logic
  const updateScale = useCallback(() => {
    if (!containerRef.current || !isFitToScreen) {
      setScale(1);
      return;
    }
    const { clientWidth, clientHeight } = containerRef.current;
    const padding = 40;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.2, s));
  }, [isFitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL RELEASE: Nudging blocked vehicles...");
    vehiclesRef.current.forEach(v => {
      const isActuallyBlocked = vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 65 && (other.pathIdx >= v.pathIdx);
      });
      if (isActuallyBlocked) v.ignoreCollisionTimer = 120;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }
      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime
        }));
        addLog(`Unit ${v.id.toUpperCase()} produced. FTT: ${passedFtt ? 'YES' : 'NO'}`);
        currentVehicles.splice(i, 1);
        continue;
      }
      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) continue; 
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }
          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false; v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18;
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    // Grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow
    MAIN_PATH_POINTS.forEach((p, i) => {
      if (i === MAIN_PATH_POINTS.length - 1) return;
      const p1 = p; const p2 = MAIN_PATH_POINTS[i+1];
      const dx = p2.x - p1.x; const dy = p2.y - p1.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
        ctx.beginPath(); ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
        ctx.fillStyle = COLORS.YELLOW_PATH; ctx.fill();
      }
    });

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const target = vehicleAtStation.targetPath[vehicleAtStation.pathIdx + 1];
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            return Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2)) < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }
      if (hoveredStationId === s.id) { ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; } else { ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; }
      if (glow) { ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 5; ctx.shadowColor = ledColor; } else { ctx.shadowBlur = 0; }
      ctx.fillStyle = statusColor; ctx.beginPath(); ctx.roundRect(x, y, w, h, 4); ctx.fill(); ctx.stroke(); ctx.shadowBlur = 0;
      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 10px Inter'; ctx.fillText(s.name, x + 6, y + 18);
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.4)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)'; ctx.font = 'bold 24px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 45);
    ctx.font = '10px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.4)'; ctx.fillText('V4.4 // AUTO-ADJUST ENGINE // SMART FACTORY MONITOR', 50, 62);
  }, [hoveredStationId, drawStatusIcon]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const frtRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  const ecatItems = useMemo(() => PARALLEL_ROLL_STATIONS.map(s => {
    const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
    let speedVal = 0; let progress = 0;
    if (v && v.waitingTimer > 0) {
      progress = 1 - (v.waitingTimer / s.wait);
      speedVal = Math.min(100, progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5);
    }
    return { name: s.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
  }), [vehiclesRef.current, frameCountRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar - Flexible Grid System */}
      <div className="w-[320px] lg:w-[380px] bg-slate-950 border-r border-slate-800 p-6 flex flex-col gap-5 shadow-2xl shrink-0 z-20 overflow-y-auto custom-scrollbar">
        <div className="flex items-center justify-between shrink-0 mb-2">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/40"><Settings className="w-5 h-5 text-white" /></div>
            <h1 className="text-xl font-black tracking-tighter uppercase italic">Control.IO</h1>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`p-2 rounded-lg border transition-all ${isFitToScreen ? 'bg-blue-500/20 border-blue-500/50 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
            title="Toggle Auto Fit Layout"
          >
            {isFitToScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>

        {/* Dynamic Stats Grid */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-800 group hover:border-blue-500/30 transition-colors">
            <div className="flex items-center gap-2 text-blue-400 mb-2"><CheckCircle2 className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest opacity-60">FTT Yield</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{fttRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
          <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-800 group hover:border-emerald-500/30 transition-colors">
            <div className="flex items-center gap-2 text-emerald-400 mb-2"><BarChart3 className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest opacity-60">FRT Overall</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{frtRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex justify-between items-center col-span-2">
             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Started Units</span>
             <span className="text-lg font-black font-mono text-slate-200">{stats.totalStarted}</span>
          </div>
        </div>

        {/* Release Button */}
        <div className="shrink-0">
          <button 
            onClick={releaseBlocked}
            className="w-full flex items-center justify-center gap-3 py-4 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-black tracking-widest uppercase transition-all shadow-xl shadow-red-900/20 active:scale-95 group relative overflow-hidden"
          >
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
            <Unlock className="w-5 h-5" />
            UNBLOCK LINE
          </button>
        </div>

        {/* Parallel ECAT Monitor Grid */}
        <div className="flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-black text-slate-600 uppercase tracking-widest mb-1"><Cpu className="w-3.5 h-3.5" /> ECAT Telemetry</div>
          <div className="grid grid-cols-1 gap-2.5">
            {ecatItems.map((rolo, i) => (
              <div key={i} className="bg-black/40 rounded-2xl p-4 border border-slate-800 hover:bg-black/60 transition-colors group">
                <div className="flex justify-between items-center mb-3">
                  <span className="text-[11px] font-bold text-slate-500 uppercase tracking-tighter">{rolo.name}</span>
                  <span className="bg-blue-600/20 text-blue-400 px-2 py-0.5 rounded-md text-[10px] font-black font-mono tracking-tighter">{rolo.unit}</span>
                </div>
                <div className="flex items-end justify-between">
                  <div className="flex items-center gap-2.5">
                    <Gauge className={`w-5 h-5 ${rolo.speed > 80 ? 'text-red-500 animate-pulse' : 'text-slate-600'}`} />
                    <span className={`text-2xl font-black tabular-nums tracking-tighter ${rolo.speed > 80 ? 'text-red-400' : 'text-slate-200'}`}>
                      {Math.round(rolo.speed)} <small className="text-[10px] opacity-30 font-bold uppercase tracking-normal">km/h</small>
                    </span>
                  </div>
                  <div className="w-20 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${rolo.progress * 100}%` }} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Simulation Settings */}
        <div className="mt-auto space-y-5 pt-4 border-t border-slate-800/50">
          <div className="space-y-3">
            <div className="flex justify-between items-center">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Flow Velocity</label>
              <span className="text-blue-500 font-mono text-xs font-bold">{speed.toFixed(1)}x</span>
            </div>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-600" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3.5 rounded-xl font-black tracking-widest text-[11px] uppercase transition-all ${isRunning ? 'bg-slate-800 text-amber-500 hover:bg-slate-700' : 'bg-green-600 text-white hover:bg-green-500 shadow-lg shadow-green-900/30'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'HALT' : 'INIT'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setLogs(['System Rebooted.']); }} className="px-4 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>
      </div>

      {/* Simulation View Area - With Auto-Adjust Wrapper */}
      <div className="flex-1 relative bg-slate-900 flex flex-col overflow-hidden" ref={containerRef}>
        {/* Dynamic Scale Wrapper */}
        <div className="flex-1 flex items-center justify-center relative">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center',
              transition: 'transform 0.4s cubic-bezier(0.2, 0, 0, 1)' 
            }}
            className="relative shadow-[0_0_100px_rgba(0,0,0,0.8)] border-[12px] border-slate-950 bg-[#1a2333] rounded-3xl overflow-hidden"
          >
            <canvas 
              ref={canvasRef} 
              width={SIM_WIDTH} 
              height={SIM_HEIGHT} 
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="cursor-crosshair" 
            />

            {/* Status Legend */}
            <div className="absolute bottom-6 left-6 flex gap-5 pointer-events-none z-10 p-4 rounded-2xl bg-slate-950/60 backdrop-blur-md border border-white/5 shadow-2xl">
              {['IDLE', 'PROCESSING', 'OCCUPIED', 'BLOCKED'].map(s => (
                <div key={s} className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center ${
                    s === 'IDLE' ? 'bg-slate-700' : 
                    s === 'PROCESSING' ? 'bg-emerald-500 animate-pulse' : 
                    s === 'OCCUPIED' ? 'bg-amber-500' : 'bg-red-600 animate-pulse'
                  }`}>
                    {s === 'IDLE' ? <div className="w-2 h-2 rounded-full border border-white/40" /> : 
                     s === 'PROCESSING' ? <div className="w-0 h-0 border-t-[3px] border-t-transparent border-b-[3px] border-b-transparent border-l-[4px] border-l-white ml-0.5" /> :
                     s === 'OCCUPIED' ? <div className="w-2 h-2 bg-white" /> : <div className="text-[12px] font-bold text-white leading-none">×</div>}
                  </div>
                  {s}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Global HUD Overlays */}
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none items-end">
          <div className="bg-slate-950/80 backdrop-blur-xl p-5 rounded-3xl border border-slate-800 shadow-2xl flex items-center gap-5">
            <div className="p-3.5 bg-blue-600/20 rounded-2xl"><Truck className="w-7 h-7 text-blue-500" /></div>
            <div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-1">Global Throughput</p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-black text-white">{stats.produced}</span>
                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">Units / SHIFT</span>
              </div>
            </div>
          </div>

          <div className="bg-slate-950/40 backdrop-blur-md px-4 py-2 rounded-full border border-slate-800 text-[10px] font-black tracking-widest uppercase text-slate-500">
             Canvas View: {Math.round(scale * 100)}%
          </div>
        </div>

        {/* Bottom Log Strip */}
        <div className="h-10 bg-slate-950 border-t border-slate-800 flex items-center px-6 gap-6 overflow-hidden shrink-0">
          <div className="flex items-center gap-2 shrink-0">
             <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Live Stream:</span>
          </div>
          <div className="flex-1 whitespace-nowrap overflow-hidden">
            <div className="flex gap-8 animate-marquee">
              {logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-400 uppercase tracking-tight flex gap-2 items-center">
                  <span className="opacity-30">[{i}]</span> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
        .animate-marquee { display: flex; animation: marquee 30s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
      `}</style>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  finished: boolean;
  progress: number;
  // Added for tracking and unblocking
  everRepaired: boolean;
  ignoreCollisionTimer: number;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  // Added industrial metrics
  totalStarted: number;
  passedFirstTime: number;
  totalRepaired: number;
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info,
  Layout,
  Unlock,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Responsive Scaling Logic
  const updateScale = useCallback(() => {
    if (!containerRef.current || !isFitToScreen) {
      setScale(1);
      return;
    }
    const { clientWidth, clientHeight } = containerRef.current;
    const padding = 40;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.2, s));
  }, [isFitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL RELEASE: Nudging blocked vehicles...");
    vehiclesRef.current.forEach(v => {
      const isActuallyBlocked = vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 65 && (other.pathIdx >= v.pathIdx);
      });
      if (isActuallyBlocked) v.ignoreCollisionTimer = 120;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }
      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`Unit ${v.id.toUpperCase()} produced. FTT: ${passedFtt ? 'YES' : 'NO'}`);
        currentVehicles.splice(i, 1);
        continue;
      }
      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) continue; 
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }
          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false; v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18;
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    // Grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow
    MAIN_PATH_POINTS.forEach((p, i) => {
      if (i === MAIN_PATH_POINTS.length - 1) return;
      const p1 = p; const p2 = MAIN_PATH_POINTS[i+1];
      const dx = p2.x - p1.x; const dy = p2.y - p1.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
        ctx.beginPath(); ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
        ctx.fillStyle = COLORS.YELLOW_PATH; ctx.fill();
      }
    });

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const target = vehicleAtStation.targetPath[vehicleAtStation.pathIdx + 1];
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            return Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2)) < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }
      if (hoveredStationId === s.id) { ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; } else { ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; }
      if (glow) { ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 5; ctx.shadowColor = ledColor; } else { ctx.shadowBlur = 0; }
      ctx.fillStyle = statusColor; ctx.beginPath(); ctx.roundRect(x, y, w, h, 4); ctx.fill(); ctx.stroke(); ctx.shadowBlur = 0;
      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 10px Inter'; ctx.fillText(s.name, x + 6, y + 18);
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.4)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)'; ctx.font = 'bold 24px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 45);
    ctx.font = '10px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.4)'; ctx.fillText('V4.4 // AUTO-ADJUST ENGINE // SMART FACTORY MONITOR', 50, 62);
  }, [hoveredStationId, drawStatusIcon]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const frtRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  const ecatItems = useMemo(() => PARALLEL_ROLL_STATIONS.map(s => {
    const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
    let speedVal = 0; let progress = 0;
    if (v && v.waitingTimer > 0) {
      progress = 1 - (v.waitingTimer / s.wait);
      speedVal = Math.min(100, progress < 0.6 ? progress * 150 : 90 + Math.sin(frameCountRef.current / 3) * 5);
    }
    return { name: s.name, unit: v ? v.id.toUpperCase() : '---', speed: speedVal, progress };
  }), [vehiclesRef.current, frameCountRef.current]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar - Flexible Grid System */}
      <div className="w-[320px] lg:w-[380px] bg-slate-950 border-r border-slate-800 p-6 flex flex-col gap-5 shadow-2xl shrink-0 z-20 overflow-y-auto custom-scrollbar">
        <div className="flex items-center justify-between shrink-0 mb-2">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/40"><Settings className="w-5 h-5 text-white" /></div>
            <h1 className="text-xl font-black tracking-tighter uppercase italic">Control.IO</h1>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`p-2 rounded-lg border transition-all ${isFitToScreen ? 'bg-blue-500/20 border-blue-500/50 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
            title="Toggle Auto Fit Layout"
          >
            {isFitToScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>

        {/* Dynamic Stats Grid */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-800 group hover:border-blue-500/30 transition-colors">
            <div className="flex items-center gap-2 text-blue-400 mb-2"><CheckCircle2 className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest opacity-60">FTT Yield</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{fttRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
          <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-800 group hover:border-emerald-500/30 transition-colors">
            <div className="flex items-center gap-2 text-emerald-400 mb-2"><BarChart3 className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest opacity-60">FRT Overall</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{frtRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
        </div>

        {/* Quality Hub Grid */}
        <div className="grid grid-cols-2 gap-2.5 shrink-0">
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-slate-500 mb-1"><Activity className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Finished</span></div>
             <span className="text-lg font-black font-mono text-slate-200 tabular-nums">{stats.produced}</span>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-red-500 mb-1"><AlertTriangle className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Defects</span></div>
             <span className="text-lg font-black font-mono text-red-400 tabular-nums">{stats.defects}</span>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-amber-500 mb-1"><Clock className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">In Repair</span></div>
             <span className="text-lg font-black font-mono text-amber-400 tabular-nums">{inRepairCount}</span>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-emerald-500 mb-1"><Wrench className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Repaired</span></div>
             <span className="text-lg font-black font-mono text-emerald-400 tabular-nums">{stats.totalRepaired}</span>
          </div>
          <div className="bg-slate-900/30 p-2 rounded-lg border border-slate-800/50 flex justify-between items-center col-span-2">
             <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">Started Units</span>
             <span className="text-xs font-black font-mono text-slate-400">{stats.totalStarted}</span>
          </div>
        </div>

        {/* Release Button */}
        <div className="shrink-0">
          <button 
            onClick={releaseBlocked}
            className="w-full flex items-center justify-center gap-3 py-4 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-black tracking-widest uppercase transition-all shadow-xl shadow-red-900/20 active:scale-95 group relative overflow-hidden"
          >
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
            <Unlock className="w-5 h-5" />
            UNBLOCK LINE
          </button>
        </div>

        {/* Parallel ECAT Monitor Grid */}
        <div className="flex flex-col gap-3">
          <div className="flex items-center gap-2 text-xs font-black text-slate-600 uppercase tracking-widest mb-1"><Cpu className="w-3.5 h-3.5" /> ECAT Telemetry</div>
          <div className="grid grid-cols-1 gap-2.5">
            {ecatItems.map((rolo, i) => (
              <div key={i} className="bg-black/40 rounded-2xl p-4 border border-slate-800 hover:bg-black/60 transition-colors group">
                <div className="flex justify-between items-center mb-3">
                  <span className="text-[11px] font-bold text-slate-500 uppercase tracking-tighter">{rolo.name}</span>
                  <span className="bg-blue-600/20 text-blue-400 px-2 py-0.5 rounded-md text-[10px] font-black font-mono tracking-tighter">{rolo.unit}</span>
                </div>
                <div className="flex items-end justify-between">
                  <div className="flex items-center gap-2.5">
                    <Gauge className={`w-5 h-5 ${rolo.speed > 80 ? 'text-red-500 animate-pulse' : 'text-slate-600'}`} />
                    <span className={`text-2xl font-black tabular-nums tracking-tighter ${rolo.speed > 80 ? 'text-red-400' : 'text-slate-200'}`}>
                      {Math.round(rolo.speed)} <small className="text-[10px] opacity-30 font-bold uppercase tracking-normal">km/h</small>
                    </span>
                  </div>
                  <div className="w-20 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${rolo.progress * 100}%` }} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Simulation Settings */}
        <div className="mt-auto space-y-5 pt-4 border-t border-slate-800/50">
          <div className="space-y-3">
            <div className="flex justify-between items-center">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Flow Velocity</label>
              <span className="text-blue-500 font-mono text-xs font-bold">{speed.toFixed(1)}x</span>
            </div>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-600" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3.5 rounded-xl font-black tracking-widest text-[11px] uppercase transition-all ${isRunning ? 'bg-slate-800 text-amber-500 hover:bg-slate-700' : 'bg-green-600 text-white hover:bg-green-500 shadow-lg shadow-green-900/30'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'HALT' : 'INIT'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setLogs(['System Rebooted.']); }} className="px-4 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
        </div>
      </div>

      {/* Simulation View Area - With Auto-Adjust Wrapper */}
      <div className="flex-1 relative bg-slate-900 flex flex-col overflow-hidden" ref={containerRef}>
        {/* Dynamic Scale Wrapper */}
        <div className="flex-1 flex items-center justify-center relative">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center',
              transition: 'transform 0.4s cubic-bezier(0.2, 0, 0, 1)' 
            }}
            className="relative shadow-[0_0_100px_rgba(0,0,0,0.8)] border-[12px] border-slate-950 bg-[#1a2333] rounded-3xl overflow-hidden"
          >
            <canvas 
              ref={canvasRef} 
              width={SIM_WIDTH} 
              height={SIM_HEIGHT} 
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="cursor-crosshair" 
            />

            {/* Status Legend */}
            <div className="absolute bottom-6 left-6 flex gap-5 pointer-events-none z-10 p-4 rounded-2xl bg-slate-950/60 backdrop-blur-md border border-white/5 shadow-2xl">
              {['IDLE', 'PROCESSING', 'OCCUPIED', 'BLOCKED'].map(s => (
                <div key={s} className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center ${
                    s === 'IDLE' ? 'bg-slate-700' : 
                    s === 'PROCESSING' ? 'bg-emerald-500 animate-pulse' : 
                    s === 'OCCUPIED' ? 'bg-amber-500' : 'bg-red-600 animate-pulse'
                  }`}>
                    {s === 'IDLE' ? <div className="w-2 h-2 rounded-full border border-white/40" /> : 
                     s === 'PROCESSING' ? <div className="w-0 h-0 border-t-[3px] border-t-transparent border-b-[3px] border-b-transparent border-l-[4px] border-l-white ml-0.5" /> :
                     s === 'OCCUPIED' ? <div className="w-2 h-2 bg-white" /> : <div className="text-[12px] font-bold text-white leading-none">×</div>}
                  </div>
                  {s}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Global HUD Overlays */}
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none items-end">
          <div className="bg-slate-950/80 backdrop-blur-xl p-5 rounded-3xl border border-slate-800 shadow-2xl flex items-center gap-5">
            <div className="p-3.5 bg-blue-600/20 rounded-2xl"><Truck className="w-7 h-7 text-blue-500" /></div>
            <div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-1">Global Throughput</p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-black text-white">{stats.produced}</span>
                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">Units / SHIFT</span>
              </div>
            </div>
          </div>

          <div className="bg-slate-950/40 backdrop-blur-md px-4 py-2 rounded-full border border-slate-800 text-[10px] font-black tracking-widest uppercase text-slate-500">
             Canvas View: {Math.round(scale * 100)}%
          </div>
        </div>

        {/* Bottom Log Strip */}
        <div className="h-10 bg-slate-950 border-t border-slate-800 flex items-center px-6 gap-6 overflow-hidden shrink-0">
          <div className="flex items-center gap-2 shrink-0">
             <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Live Stream:</span>
          </div>
          <div className="flex-1 whitespace-nowrap overflow-hidden">
            <div className="flex gap-8 animate-marquee">
              {logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-400 uppercase tracking-tight flex gap-2 items-center">
                  <span className="opacity-30">[{i}]</span> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
        .animate-marquee { display: flex; animation: marquee 30s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Zap,
  Gauge,
  Cpu,
  Terminal,
  Info,
  Layout,
  Unlock,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  ListFilter
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate, setDefectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Responsive Scaling Logic
  const updateScale = useCallback(() => {
    if (!containerRef.current || !isFitToScreen) {
      setScale(1);
      return;
    }
    const { clientWidth, clientHeight } = containerRef.current;
    const padding = 40;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.2, s));
  }, [isFitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  // Pre-load vehicle image
  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 10));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL RELEASE: Nudging blocked vehicles...");
    vehiclesRef.current.forEach(v => {
      const isActuallyBlocked = vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 65 && (other.pathIdx >= v.pathIdx);
      });
      if (isActuallyBlocked) v.ignoreCollisionTimer = 120;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + 2) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }
      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`Unit ${v.id.toUpperCase()} produced. FTT: ${passedFtt ? 'YES' : 'NO'}`);
        currentVehicles.splice(i, 1);
        continue;
      }
      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return distToOther < 60 && (other.pathIdx >= v.pathIdx);
      });

      if (isBlocked) continue; 
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name.includes('MGR')) v.hasEngine = true;
          if (station.name === 'Flat Top') v.hasWheels = true;
          if (station.name === 'Abastecimento') v.hasFluids = true;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`FAI QC FAIL: Unit ${v.id.toUpperCase()} to FCPA.`);
          }
          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false; v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18;
            v.color = COLORS.VEHICLE;
            addLog(`Repair Complete: Unit ${v.id.toUpperCase()} returned.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    // Grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Flow dots
    MAIN_PATH_POINTS.forEach((p, i) => {
      if (i === MAIN_PATH_POINTS.length - 1) return;
      const p1 = p; const p2 = MAIN_PATH_POINTS[i+1];
      const dx = p2.x - p1.x; const dy = p2.y - p1.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      for (let d = (animOffsetRef.current % 40); d < dist; d += 40) {
        ctx.beginPath(); ctx.arc(p1.x + (dx/dist)*d, p1.y + (dy/dist)*d, 2, 0, Math.PI * 2);
        ctx.fillStyle = COLORS.YELLOW_PATH; ctx.fill();
      }
    });

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            return Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2)) < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }

      if (hoveredStationId === s.id) { ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; } else { ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; }
      if (glow) { 
        ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 8; 
        ctx.shadowColor = ledColor; 
      } else { ctx.shadowBlur = 0; }

      ctx.fillStyle = statusColor; 
      ctx.beginPath(); 
      ctx.roundRect(x, y, w, h, 6); 
      ctx.fill(); 
      ctx.stroke(); 
      ctx.shadowBlur = 0;

      // Labels inside the station
      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; 
      ctx.font = 'bold 10px Inter'; 
      ctx.fillText(s.name, x + 8, y + 16);

      ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
      ctx.font = '700 8px Inter';
      ctx.fillText(status, x + 8, y + 28);

      // Progress bar if processing
      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(0,0,0,0.3)';
        ctx.fillRect(x + 8, y + h - 8, w - 16, 3);
        ctx.fillStyle = '#10b981';
        ctx.fillRect(x + 8, y + h - 8, (w - 16) * prog, 3);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.4)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)'; ctx.font = 'bold 24px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 45);
    ctx.font = '10px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.4)'; ctx.fillText('V4.5 // TELEMETRIC MONITOR // MULTI-STATUS ENGINE', 50, 62);
  }, [hoveredStationId, drawStatusIcon]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const frtRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  const stationMonitorData = useMemo(() => {
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    return allStations.map(s => {
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 8 && Math.abs(v.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            return Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2)) < 60 && (other.pathIdx >= vehicleAtStation.pathIdx);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, unit: vehicleAtStation?.id || null };
    });
  }, [vehiclesRef.current]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar - Reorganized for better status visibility */}
      <div className="w-[340px] lg:w-[400px] bg-slate-950 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl shrink-0 z-20 overflow-y-auto custom-scrollbar">
        <div className="flex items-center justify-between shrink-0 mb-2">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-900/40"><Settings className="w-5 h-5 text-white" /></div>
            <h1 className="text-xl font-black tracking-tighter uppercase italic">Control.IO</h1>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`p-2 rounded-lg border transition-all ${isFitToScreen ? 'bg-blue-500/20 border-blue-500/50 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'}`}
            title="Toggle Auto Fit Layout"
          >
            {isFitToScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>

        {/* Efficiency KPIs */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-800 flex flex-col items-center">
            <div className="flex items-center gap-2 text-blue-400 mb-2"><CheckCircle2 className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest opacity-60">FTT Rate</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{fttRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
          <div className="bg-slate-900/80 p-4 rounded-2xl border border-slate-800 flex flex-col items-center">
            <div className="flex items-center gap-2 text-emerald-400 mb-2"><BarChart3 className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest opacity-60">Yield</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{frtRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
        </div>

        {/* Quality Metrics Grid */}
        <div className="grid grid-cols-2 gap-2.5 shrink-0">
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-slate-500 mb-1"><Activity className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Finished</span></div>
             <span className="text-lg font-black font-mono text-slate-200 tabular-nums">{stats.produced}</span>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-red-500 mb-1"><AlertTriangle className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Defects</span></div>
             <span className="text-lg font-black font-mono text-red-400 tabular-nums">{stats.defects}</span>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-amber-500 mb-1"><Clock className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">In Repair</span></div>
             <span className="text-lg font-black font-mono text-amber-400 tabular-nums">{inRepairCount}</span>
          </div>
          <div className="bg-slate-900/50 p-3 rounded-xl border border-slate-800/50 flex flex-col">
             <div className="flex items-center gap-2 text-emerald-500 mb-1"><Wrench className="w-3.5 h-3.5" /><span className="text-[9px] font-bold uppercase tracking-widest">Repaired</span></div>
             <span className="text-lg font-black font-mono text-emerald-400 tabular-nums">{stats.totalRepaired}</span>
          </div>
        </div>

        {/* Station Live Monitor Section */}
        <div className="flex flex-col gap-3 flex-1 overflow-hidden min-h-0">
          <div className="flex items-center gap-2 text-xs font-black text-slate-600 uppercase tracking-widest mb-1"><ListFilter className="w-3.5 h-3.5" /> Station Monitor</div>
          <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col gap-1 pr-1">
            {stationMonitorData.map((s) => (
              <div key={s.id} className="bg-slate-900/30 border border-slate-800/50 px-3 py-2 rounded-lg flex items-center justify-between hover:bg-slate-800/30 transition-colors group">
                <div className="flex flex-col gap-0.5">
                  <span className="text-[10px] font-bold text-slate-300 group-hover:text-white transition-colors uppercase tracking-tighter truncate w-32">{s.name}</span>
                  {s.unit && <span className="text-[8px] font-mono text-blue-500 font-black">UNIT: {s.unit.toUpperCase()}</span>}
                </div>
                <div className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest ${
                  s.status === 'IDLE' ? 'bg-slate-800 text-slate-500 border border-slate-700' :
                  s.status === 'PROCESSING' ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' :
                  s.status === 'OCCUPIED' ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30' :
                  'bg-red-500/20 text-red-400 border border-red-500/30 animate-pulse'
                }`}>
                  {s.status}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Controls */}
        <div className="space-y-4 shrink-0 border-t border-slate-800/50 pt-4">
          <div className="space-y-3">
            <div className="flex justify-between items-center">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Throughput Speed</label>
              <span className="text-blue-500 font-mono text-xs font-bold">{speed.toFixed(1)}x</span>
            </div>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-600" />
          </div>
          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-black tracking-widest text-[11px] uppercase transition-all ${isRunning ? 'bg-slate-800 text-amber-500 hover:bg-slate-700' : 'bg-green-600 text-white hover:bg-green-500 shadow-lg shadow-green-900/30'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'HALT' : 'INIT'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setLogs(['System Rebooted.']); }} className="px-4 bg-slate-800 text-slate-400 rounded-xl hover:bg-slate-700 transition-colors"><RotateCcw className="w-5 h-5" /></button>
          </div>
          <button 
            onClick={releaseBlocked}
            className="w-full py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/20 rounded-xl text-[10px] font-black tracking-widest uppercase transition-all"
          >
            NUDGE BLOCKED UNITS
          </button>
        </div>
      </div>

      {/* Main Simulation View Area */}
      <div className="flex-1 relative bg-slate-900 flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center',
              transition: 'transform 0.4s cubic-bezier(0.2, 0, 0, 1)' 
            }}
            className="relative shadow-[0_0_100px_rgba(0,0,0,0.8)] border-[12px] border-slate-950 bg-[#1a2333] rounded-3xl overflow-hidden"
          >
            <canvas 
              ref={canvasRef} 
              width={SIM_WIDTH} 
              height={SIM_HEIGHT} 
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="cursor-crosshair" 
            />

            {/* Legend Overlay */}
            <div className="absolute bottom-6 left-6 flex gap-4 pointer-events-none z-10 p-4 rounded-2xl bg-slate-950/70 backdrop-blur-md border border-white/5 shadow-2xl">
              {['IDLE', 'PROCESSING', 'OCCUPIED', 'BLOCKED'].map(s => (
                <div key={s} className="flex items-center gap-2.5 text-[9px] font-black text-slate-400 uppercase tracking-widest">
                  <div className={`w-5 h-5 rounded-full flex items-center justify-center ${
                    s === 'IDLE' ? 'bg-slate-700' : 
                    s === 'PROCESSING' ? 'bg-emerald-500' : 
                    s === 'OCCUPIED' ? 'bg-amber-500' : 'bg-red-600 animate-pulse'
                  }`}>
                    {s === 'IDLE' ? <div className="w-1.5 h-1.5 rounded-full border border-white/40" /> : 
                     s === 'PROCESSING' ? <div className="w-0 h-0 border-t-[3px] border-t-transparent border-b-[3px] border-b-transparent border-l-[4px] border-l-white ml-0.5" /> :
                     s === 'OCCUPIED' ? <div className="w-2 h-2 bg-white" /> : <div className="text-[10px] font-bold text-white">×</div>}
                  </div>
                  {s}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* HUD Overlay */}
        <div className="absolute top-8 right-8 flex flex-col gap-4 pointer-events-none items-end">
          <div className="bg-slate-950/80 backdrop-blur-xl p-5 rounded-3xl border border-slate-800 shadow-2xl flex items-center gap-5">
            <div className="p-3.5 bg-blue-600/20 rounded-2xl"><Truck className="w-7 h-7 text-blue-500" /></div>
            <div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-1">Shift Throughput</p>
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-black text-white">{stats.produced}</span>
                <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">Units</span>
              </div>
            </div>
          </div>
          <div className="bg-slate-950/40 backdrop-blur-md px-4 py-2 rounded-full border border-slate-800 text-[9px] font-black tracking-widest uppercase text-slate-500">
             Viewport Scale: {Math.round(scale * 100)}%
          </div>
        </div>

        {/* Marquee Ticker */}
        <div className="h-10 bg-slate-950 border-t border-slate-800 flex items-center px-6 gap-6 overflow-hidden shrink-0">
          <div className="flex items-center gap-2 shrink-0">
             <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Factory Event Stream:</span>
          </div>
          <div className="flex-1 whitespace-nowrap overflow-hidden">
            <div className="flex gap-8 animate-marquee">
              {logs.length > 0 ? logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-400 uppercase tracking-tight flex gap-2 items-center">
                  <span className="opacity-30">[{i}]</span> {log}
                </span>
              )) : <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest italic">Standing by for production telemetry...</span>}
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
        .animate-marquee { display: flex; animation: marquee 35s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
      `}</style>
    </div>
  );
};

export default App;

