          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, unit: v?.id || null };
    });
  }, [vehiclesRef.current]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar - Auto-Adjusting Dashboard */}
      <div className="w-[360px] lg:w-[420px] bg-slate-950 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl shrink-0 z-20 overflow-hidden relative">
