// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current || !isFitToScreen) {
      setScale(1);
      return;
    }
    const { clientWidth, clientHeight } = containerRef.current;
    const padding = 60;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.15, s));
  }, [isFitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL OVERRIDE: Advancing line flow...");
    vehiclesRef.current.forEach(v => {
      v.ignoreCollisionTimer = 240;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`Unit ${v.id.toUpperCase()} completed cycle. Status: ${passedFtt ? 'FTT OK' : 'REPAIRED'}`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Refined context-aware blocking logic
      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;

        // If they are on different paths (repair vs main), only block if they are close to a merge point
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));

        if (onSamePath) {
          // Normal sequential blocking
          return distToOther < 65 && (other.pathIdx >= v.pathIdx);
        } else {
          // Block only if physically colliding at intersection points
          return distToOther < 45;
        }
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1 }));
            addLog(`QUALITY ALERT: ${v.id.toUpperCase()} failed QC. Routing to REPAIR.`);
          }
          if (station.name === 'ÁREA BRANCA' && v.inRepair) {
            v.inRepair = false; v.isRepaired = true;
            v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18;
            v.color = COLORS.VEHICLE;
            addLog(`REPAIR OK: ${v.id.toUpperCase()} cleared and returned to line.`);
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));

    // Dynamic Hover Detection
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Station Rendering
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isActuallyBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isActuallyBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }

      if (hoveredStationId === s.id) { 
        ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; 
        ctx.setLineDash([5, 5]); // Dashed highlight for hover
      } else { 
        ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; 
        ctx.setLineDash([]);
      }

      if (glow) { ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 8; ctx.shadowColor = ledColor; } else { ctx.shadowBlur = 0; }

      ctx.fillStyle = statusColor; ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke(); ctx.shadowBlur = 0;
      ctx.setLineDash([]);

      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 10px Inter'; ctx.fillText(s.name, x + 8, y + 16);

      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(0,0,0,0.3)'; ctx.fillRect(x + 8, y + h - 8, w - 16, 3);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 8, y + h - 8, (w - 16) * prog, 3);
      }
    });

    // Vehicle Rendering
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isBlocked = v.waitingTimer === 0 && v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
      });

      if (isBlocked) {
        ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(0, 0, 25, 0, Math.PI * 2); ctx.stroke();
      }

      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 5; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.95)'; ctx.font = 'bold 28px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 48);
    ctx.font = '11px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.5)'; ctx.fillText('V4.7 // SMART BLOCKING // REPAIR CYCLE MONITOR', 50, 68);
  }, [hoveredStationId, drawStatusIcon, speed]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const yieldRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  const ecatTelemetry = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
      let progress = 0; let curSpeed = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / s.wait);
        curSpeed = Math.min(100, progress < 0.2 ? progress * 500 : (90 + Math.random() * 5));
      }
      return { id: s.id, name: s.name, unit: v?.id.toUpperCase() || '---', speed: curSpeed, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  const stationMonitorData = useMemo(() => {
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    return allStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, unit: v?.id || null };
    });
  }, [vehiclesRef.current]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar */}
      <div className="w-[360px] lg:w-[420px] bg-slate-950 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl shrink-0 z-20 overflow-hidden relative">
        <div className="absolute inset-0 bg-gradient-to-b from-blue-600/5 to-transparent pointer-events-none" />

        <div className="flex items-center justify-between shrink-0 mb-2 relative">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2.5 rounded-xl shadow-lg shadow-blue-900/40 border border-blue-400/30"><Cpu className="w-5 h-5 text-white" /></div>
            <div>
              <h1 className="text-xl font-black tracking-tighter uppercase italic leading-none">Control.HQ</h1>
              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Digital Twin v4.7</span>
            </div>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`p-2.5 rounded-xl border transition-all ${isFitToScreen ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
          >
            {isFitToScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>

        {/* Global KPIs */}
        <div className="grid grid-cols-2 gap-3 shrink-0">
          <div className="bg-slate-900/60 p-4 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-blue-500/50 transition-colors">
            <div className="flex items-center gap-2 text-blue-400 mb-2"><CheckCircle2 className="w-3.5 h-3.5" /><span className="text-[10px] font-black uppercase tracking-[0.15em] opacity-60">FTT Yield</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{fttRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
          <div className="bg-slate-900/60 p-4 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-emerald-500/50 transition-colors">
            <div className="flex items-center gap-2 text-emerald-400 mb-2"><BarChart3 className="w-3.5 h-3.5" /><span className="text-[10px] font-black uppercase tracking-[0.15em] opacity-60">Availability</span></div>
            <p className="text-3xl font-black tabular-nums tracking-tighter">{yieldRate.toFixed(1)}<span className="text-sm opacity-30 ml-1">%</span></p>
          </div>
        </div>

        {/* Telemetry Grid (ECAT) */}
        <div className="flex flex-col gap-3 shrink-0">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-widest"><Gauge className="w-3.5 h-3.5" /> ECAT Telemetry</div>
            <div className="flex gap-1">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
            </div>
          </div>
          <div className="grid grid-cols-1 gap-2">
            {ecatTelemetry.map((ecat) => (
              <div key={ecat.id} className="bg-slate-900/40 border border-slate-800 p-4 rounded-2xl flex flex-col gap-3 group hover:bg-slate-800/40 transition-all border-l-4 border-l-blue-600/50">
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-black text-slate-300 uppercase truncate w-32 tracking-tighter">{ecat.name}</span>
                  <span className="bg-slate-800 text-blue-400 px-2 py-0.5 rounded text-[9px] font-mono font-black">{ecat.unit}</span>
                </div>
                <div className="flex items-end justify-between">
                   <div className="flex flex-col">
                      <div className="flex items-baseline gap-1">
                        <span className={`text-2xl font-black tabular-nums tracking-tighter transition-colors ${ecat.speed > 80 ? 'text-blue-400' : 'text-slate-200'}`}>{Math.round(ecat.speed)}</span>
                        <span className="text-[10px] font-bold text-slate-700">km/h</span>
                      </div>
                   </div>
                   <div className="flex-1 px-4 mb-1.5">
                      <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden">
                        <div className="h-full bg-blue-500 transition-all duration-300 shadow-[0_0_10px_rgba(59,130,246,0.5)]" style={{ width: `${ecat.progress * 100}%` }} />
                      </div>
                   </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Status Hub (Station Monitor) */}
        <div className="flex flex-col gap-3 flex-1 min-h-0 overflow-hidden">
          <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-widest"><ListFilter className="w-3.5 h-3.5" /> Sector Status</div>
          <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col gap-1.5 pr-1">
            {stationMonitorData.map((s) => (
              <div key={s.id} className="bg-slate-900/20 border border-slate-800/40 px-3.5 py-2.5 rounded-xl flex items-center justify-between hover:bg-slate-800/30 transition-colors group">
                <div className="flex flex-col gap-0.5">
                  <span className="text-[10px] font-bold text-slate-400 group-hover:text-white transition-colors uppercase tracking-tight truncate w-36">{s.name}</span>
                  {s.unit && <span className="text-[8px] font-mono text-blue-500/70 font-black">ID: {s.unit.toUpperCase()}</span>}
                </div>
                <div className={`px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                  s.status === 'IDLE' ? 'bg-slate-900/50 text-slate-600 border-slate-800' :
                  s.status === 'PROCESSING' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                  s.status === 'OCCUPIED' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
                  'bg-red-500/10 text-red-400 border-red-500/20 animate-pulse'
                }`}>
                  {s.status}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Actions */}
        <div className="space-y-4 shrink-0 border-t border-slate-800/60 pt-5 mt-auto relative">
          <div className="grid grid-cols-2 gap-2">
            <div className="bg-slate-900/40 p-3 rounded-xl border border-slate-800/50 flex flex-col">
              <span className="text-[8px] font-bold text-slate-600 uppercase mb-1">Rework Units</span>
              <span className="text-base font-black font-mono text-amber-500 tabular-nums">{inRepairCount}</span>
            </div>
            <div className="bg-slate-900/40 p-3 rounded-xl border border-slate-800/50 flex flex-col">
              <span className="text-[8px] font-bold text-slate-600 uppercase mb-1">Defects Logged</span>
              <span className="text-base font-black font-mono text-red-400 tabular-nums">{stats.defects}</span>
            </div>
          </div>

          <div className="flex gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2.5 py-3 rounded-xl font-black tracking-widest text-[10px] uppercase transition-all shadow-lg active:scale-95 ${isRunning ? 'bg-slate-800 text-amber-500 hover:bg-slate-700' : 'bg-blue-600 text-white hover:bg-blue-500 shadow-blue-900/30'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'Line Halt' : 'Line Init'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("System reset complete."); }} className="px-4 bg-slate-800 text-slate-500 rounded-xl hover:bg-slate-700 transition-colors border border-slate-800"><RotateCcw className="w-5 h-5" /></button>
          </div>

          <button 
            onClick={releaseBlocked}
            className="w-full flex items-center justify-center gap-2 py-2.5 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/20 rounded-xl text-[9px] font-black tracking-widest uppercase transition-all"
          >
            <ShieldAlert className="w-3.5 h-3.5" />
            FORCED LINE ADVANCE
          </button>
        </div>
      </div>

      {/* Canvas View */}
      <div className="flex-1 relative bg-[#0a0f1a] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center',
              transition: 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' 
            }}
            className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[14px] border-slate-950 bg-[#111827] rounded-[2.5rem] overflow-hidden"
          >
            <canvas 
              ref={canvasRef} 
              width={SIM_WIDTH} 
              height={SIM_HEIGHT} 
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="cursor-crosshair" 
            />
          </div>
        </div>

        {/* HUD */}
        <div className="absolute top-10 right-10 flex flex-col gap-5 pointer-events-none items-end">
          <div className="bg-slate-950/90 backdrop-blur-2xl p-6 rounded-[2rem] border border-slate-800 shadow-2xl flex items-center gap-6">
            <div className="p-4 bg-blue-600/10 rounded-2xl border border-blue-500/20"><Truck className="w-8 h-8 text-blue-500" /></div>
            <div>
              <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.25em] mb-1">Production</p>
              <div className="flex items-baseline gap-2">
                <span className="text-3xl font-black text-white">{stats.produced}</span>
                <span className="text-[11px] font-bold text-slate-600 uppercase tracking-widest">Units</span>
              </div>
            </div>
          </div>
        </div>

        {/* Ticker */}
        <div className="h-12 bg-slate-950 border-t border-slate-800 flex items-center px-8 gap-8 overflow-hidden shrink-0">
          <div className="flex items-center gap-3 shrink-0 z-20">
             <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse shadow-[0_0_8px_rgba(59,130,246,0.8)]" />
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] whitespace-nowrap">Factory Feed</span>
          </div>
          <div className="flex-1 whitespace-nowrap overflow-hidden">
            <div className="flex gap-12 animate-marquee py-1">
              {logs.map((log, i) => (
                <span key={i} className="text-[10px] font-bold text-slate-300 uppercase tracking-tight flex gap-3 items-center">
                  <span className="opacity-20 font-mono text-xs">#{logs.length - i}</span> 
                  <span className="text-blue-400/80">{log}</span>
                </span>
              ))}
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 20px; border: 1px solid #020617; }
        .animate-marquee { display: flex; animation: marquee 40s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
      `}</style>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  finished: boolean;
  progress: number;
  // Added for tracking and unblocking
  everRepaired: boolean;
  ignoreCollisionTimer: number;
  pendingRepairs: number; // Number of repair stages needed
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  // Added industrial metrics
  totalStarted: number;
  passedFirstTime: number;
  totalRepaired: number;
  repairAttempts: number; // Total units sent to repair
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Gauge,
  Cpu,
  Unlock,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  ListFilter,
  Layers,
  Zap,
  ShieldAlert,
  Target,
  TrendingUp
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current || !isFitToScreen) {
      setScale(1);
      return;
    }
    const { clientWidth, clientHeight } = containerRef.current;
    const padding = 60;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.15, s));
  }, [isFitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL OVERRIDE: Advancing line flow...");
    vehiclesRef.current.forEach(v => {
      v.ignoreCollisionTimer = 240;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`Unit ${v.id.toUpperCase()} completed cycle. Yield: ${passedFtt ? 'FTT OK' : 'REPAIRED'}`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Refined context-aware blocking logic
      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;

        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));

        if (onSamePath) {
          return distToOther < 65 && (other.pathIdx >= v.pathIdx);
        } else {
          // Intersection/Merge Point Blocking
          return distToOther < 45;
        }
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // Parallel branching for ECAT
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }

        if (station) {
          v.waitingTimer = station.wait;

          // Multi-stage defect detection at FAI QC
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; 
            v.everRepaired = true;
            // Determine defect intensity (1 or 2 stages)
            v.pendingRepairs = Math.random() < 0.4 ? 2 : 1; 
            v.targetPath = [...REPAIR_PATH_POINTS]; 
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`REWORK START: ${v.id.toUpperCase()} failed QC. Stages needed: ${v.pendingRepairs}`);
          }

          // Multi-stage repair handling
          if (v.inRepair) {
            if (station.name === 'FUNILARIA' || station.name === 'FCPA') {
              if (v.pendingRepairs > 0) {
                v.pendingRepairs--;
                addLog(`REPAIR STEP: ${v.id.toUpperCase()} stage at ${station.name} clear. Remaining: ${v.pendingRepairs}`);
              }
            }

            if (station.name === 'ÁREA BRANCA') {
              v.inRepair = false; 
              v.isRepaired = true;
              v.targetPath = [...MAIN_PATH_POINTS]; 
              v.pathIdx = 18;
              v.color = COLORS.VEHICLE;
              addLog(`REPAIR COMPLETE: ${v.id.toUpperCase()} returned to line.`);
            }
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));

    // Dynamic Hover Detection
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Station Rendering
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isActuallyBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isActuallyBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }

      const isHovered = hoveredStationId === s.id;
      if (isHovered) { 
        ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; 
        ctx.setLineDash([5, 5]);
      } else { 
        ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; 
        ctx.setLineDash([]);
      }

      if (glow) { ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 8; ctx.shadowColor = ledColor; } else { ctx.shadowBlur = 0; }

      ctx.fillStyle = statusColor; ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke(); ctx.shadowBlur = 0;
      ctx.setLineDash([]);

      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 10px Inter'; ctx.fillText(s.name, x + 8, y + 16);

      // Detailed status info on hover for repair points
      if (isHovered && s.type === StationType.REPAIR) {
         ctx.fillStyle = 'rgba(255,255,255,0.9)'; ctx.font = '800 8px Inter';
         ctx.fillText('CRITICAL REWORK POINT', x + 8, y + 28);
      }

      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(0,0,0,0.3)'; ctx.fillRect(x + 8, y + h - 8, w - 16, 3);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 8, y + h - 8, (w - 16) * prog, 3);
      }
    });

    // Vehicle Rendering
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isBlocked = v.waitingTimer === 0 && v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
      });

      if (isBlocked) {
        ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(0, 0, 25, 0, Math.PI * 2); ctx.stroke();
      }

      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 5; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();

      // Defect marker for rework units
      if (v.inRepair && v.pendingRepairs > 0) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = '#ffffff'; ctx.font = 'bold 9px Inter';
        ctx.fillText(`! ${v.pendingRepairs}`, -5, 5);
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.95)'; ctx.font = 'bold 28px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 48);
    ctx.font = '11px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.5)'; ctx.fillText('V4.8 // MULTI-STAGE REPAIR // EFFICIENCY TRACKER', 50, 68);
  }, [hoveredStationId, drawStatusIcon, speed]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const yieldRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;
  const repairEfficiency = stats.repairAttempts > 0 ? (stats.totalRepaired / stats.repairAttempts) * 100 : 0;

  const ecatTelemetry = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
      let progress = 0; let curSpeed = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / s.wait);
        curSpeed = Math.min(100, progress < 0.2 ? progress * 500 : (90 + Math.random() * 5));
      }
      return { id: s.id, name: s.name, unit: v?.id.toUpperCase() || '---', speed: curSpeed, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  const stationMonitorData = useMemo(() => {
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    return allStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
