import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Gauge,
  Cpu,
  Unlock,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  ListFilter,
  Layers,
  Zap,
  ShieldAlert,
  Target,
  TrendingUp
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
// Added StationType to imports to fix the error on line 350
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current || !isFitToScreen) {
      setScale(1);
      return;
    }
    const { clientWidth, clientHeight } = containerRef.current;
    const padding = 60;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.15, s));
  }, [isFitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL OVERRIDE: Advancing line flow...");
    vehiclesRef.current.forEach(v => {
      v.ignoreCollisionTimer = 240;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`Unit ${v.id.toUpperCase()} completed cycle. Yield: ${passedFtt ? 'FTT OK' : 'REPAIRED'}`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      // Refined context-aware blocking logic
      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;

        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));

        if (onSamePath) {
          return distToOther < 65 && (other.pathIdx >= v.pathIdx);
        } else {
          // Intersection/Merge Point Blocking
          return distToOther < 45;
        }
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // Parallel branching for ECAT
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }

        if (station) {
          v.waitingTimer = station.wait;

          // Multi-stage defect detection at FAI QC
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; 
            v.everRepaired = true;
            // Determine defect intensity (1 or 2 stages)
            v.pendingRepairs = Math.random() < 0.4 ? 2 : 1; 
            v.targetPath = [...REPAIR_PATH_POINTS]; 
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`REWORK START: ${v.id.toUpperCase()} failed QC. Stages needed: ${v.pendingRepairs}`);
          }

          // Multi-stage repair handling
          if (v.inRepair) {
            if (station.name === 'FUNILARIA' || station.name === 'FCPA') {
              if (v.pendingRepairs > 0) {
                v.pendingRepairs--;
                addLog(`REPAIR STEP: ${v.id.toUpperCase()} stage at ${station.name} clear. Remaining: ${v.pendingRepairs}`);
              }
            }

            if (station.name === 'ÁREA BRANCA') {
              v.inRepair = false; 
              v.isRepaired = true;
              v.targetPath = [...MAIN_PATH_POINTS]; 
              v.pathIdx = 18;
              v.color = COLORS.VEHICLE;
              addLog(`REPAIR COMPLETE: ${v.id.toUpperCase()} returned to line.`);
            }
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));

    // Dynamic Hover Detection
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    // Station Rendering
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isActuallyBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isActuallyBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }

      const isHovered = hoveredStationId === s.id;
      if (isHovered) { 
        ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; 
        ctx.setLineDash([5, 5]);
      } else { 
        ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; 
        ctx.setLineDash([]);
      }

      if (glow) { ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 8; ctx.shadowColor = ledColor; } else { ctx.shadowBlur = 0; }

      ctx.fillStyle = statusColor; ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke(); ctx.shadowBlur = 0;
      ctx.setLineDash([]);

      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 10px Inter'; ctx.fillText(s.name, x + 8, y + 16);

      // Detailed status info on hover for repair points
      if (isHovered && s.type === StationType.REPAIR) {
         ctx.fillStyle = 'rgba(255,255,255,0.9)'; ctx.font = '800 8px Inter';
         ctx.fillText('CRITICAL REWORK POINT', x + 8, y + 28);
      }

      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(0,0,0,0.3)'; ctx.fillRect(x + 8, y + h - 8, w - 16, 3);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 8, y + h - 8, (w - 16) * prog, 3);
      }
    });

    // Vehicle Rendering
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isBlocked = v.waitingTimer === 0 && v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
      });

      if (isBlocked) {
        ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(0, 0, 25, 0, Math.PI * 2); ctx.stroke();
      }

      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 5; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();

      // Defect marker for rework units
      if (v.inRepair && v.pendingRepairs > 0) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = '#ffffff'; ctx.font = 'bold 9px Inter';
        ctx.fillText(`! ${v.pendingRepairs}`, -5, 5);
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.95)'; ctx.font = 'bold 28px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 48);
    ctx.font = '11px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.5)'; ctx.fillText('V4.8 // MULTI-STAGE REPAIR // EFFICIENCY TRACKER', 50, 68);
  }, [hoveredStationId, drawStatusIcon, speed]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const yieldRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;
  const repairEfficiency = stats.repairAttempts > 0 ? (stats.totalRepaired / stats.repairAttempts) * 100 : 0;

  const ecatTelemetry = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
      let progress = 0; let curSpeed = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / s.wait);
        curSpeed = Math.min(100, progress < 0.2 ? progress * 500 : (90 + Math.random() * 5));
      }
      return { id: s.id, name: s.name, unit: v?.id.toUpperCase() || '---', speed: curSpeed, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  const stationMonitorData = useMemo(() => {
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    return allStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, unit: v?.id || null };
    });
  }, [vehiclesRef.current]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar - Enhanced with Efficiency Tracking */}
      <div className="w-[380px] lg:w-[440px] bg-slate-950 border-r border-slate-800 p-6 flex flex-col gap-6 shadow-2xl shrink-0 z-20 overflow-hidden relative">
        <div className="absolute inset-0 bg-gradient-to-b from-blue-600/5 to-transparent pointer-events-none" />

        <div className="flex items-center justify-between shrink-0 mb-2 relative">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2.5 rounded-xl shadow-lg shadow-blue-900/40 border border-blue-400/30"><Cpu className="w-5 h-5 text-white" /></div>
            <div>
              <h1 className="text-xl font-black tracking-tighter uppercase italic leading-none text-blue-50">Control.HQ</h1>
              <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Digital Twin v4.8</span>
            </div>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`p-2.5 rounded-xl border transition-all ${isFitToScreen ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
          >
            {isFitToScreen ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
          </button>
        </div>

        {/* Efficiency KPIs */}
        <div className="grid grid-cols-3 gap-2.5 shrink-0">
          <div className="bg-slate-900/60 p-3.5 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-blue-500/50 transition-colors">
            <div className="flex items-center gap-1.5 text-blue-400 mb-2"><CheckCircle2 className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.1em] opacity-60">FTT Yield</span></div>
            <p className="text-xl font-black tabular-nums tracking-tighter">{fttRate.toFixed(1)}%</p>
          </div>
          <div className="bg-slate-900/60 p-3.5 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-emerald-500/50 transition-colors">
            <div className="flex items-center gap-1.5 text-emerald-400 mb-2"><TrendingUp className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.1em] opacity-60">Availability</span></div>
            <p className="text-xl font-black tabular-nums tracking-tighter">{yieldRate.toFixed(1)}%</p>
          </div>
          <div className="bg-slate-900/60 p-3.5 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-amber-500/50 transition-colors">
            <div className="flex items-center gap-1.5 text-amber-400 mb-2"><Target className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.1em] opacity-60">Repair Eff.</span></div>
            <p className="text-xl font-black tabular-nums tracking-tighter">{repairEfficiency.toFixed(1)}%</p>
          </div>
        </div>

        {/* Telemetry (ECAT) */}
        <div className="flex flex-col gap-3 shrink-0">
          <div className="flex items-center justify-between px-1">
            <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-widest"><Gauge className="w-3.5 h-3.5" /> ECAT Telemetry</div>
            <div className="flex gap-1.5 items-center">
              <span className="text-[8px] font-bold text-slate-600 uppercase">Live Pulse</span>
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)]" />
            </div>
          </div>
          <div className="grid grid-cols-1 gap-2">
            {ecatTelemetry.map((ecat) => (
              <div key={ecat.id} className="bg-slate-900/40 border border-slate-800 p-4 rounded-2xl flex flex-col gap-3 group hover:bg-slate-800/40 transition-all border-l-4 border-l-blue-600/50">
                <div className="flex justify-between items-center">
                  <span className="text-[10px] font-black text-slate-300 uppercase truncate w-32 tracking-tighter">{ecat.name}</span>
                  <span className="bg-slate-800 text-blue-400 px-2.5 py-1 rounded text-[9px] font-mono font-black border border-slate-700/50">{ecat.unit}</span>
                </div>
                <div className="flex items-end justify-between">
                   <div className="flex flex-col">
                      <div className="flex items-baseline gap-1">
                        <span className={`text-2xl font-black tabular-nums tracking-tighter transition-colors ${ecat.speed > 80 ? 'text-blue-400' : 'text-slate-200'}`}>{Math.round(ecat.speed)}</span>
                        <span className="text-[10px] font-bold text-slate-700">km/h</span>
                      </div>
                   </div>
                   <div className="flex-1 px-4 mb-1.5">
                      <div className="h-2 bg-slate-800 rounded-full overflow-hidden border border-slate-700/30">
                        <div className="h-full bg-blue-500 transition-all duration-300 shadow-[0_0_12px_rgba(59,130,246,0.6)]" style={{ width: `${ecat.progress * 100}%` }} />
                      </div>
                   </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Sector Status Hub */}
        <div className="flex flex-col gap-3 flex-1 min-h-0 overflow-hidden">
          <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-widest px-1"><ListFilter className="w-3.5 h-3.5" /> Sector Diagnostics</div>
          <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col gap-1.5 pr-1">
            {stationMonitorData.map((s) => (
              <div key={s.id} className="bg-slate-900/20 border border-slate-800/40 px-3.5 py-3 rounded-xl flex items-center justify-between hover:bg-slate-800/30 transition-colors group">
                <div className="flex flex-col gap-0.5">
                  <span className="text-[10px] font-bold text-slate-400 group-hover:text-blue-50 transition-colors uppercase tracking-tight truncate w-36">{s.name}</span>
                  {s.unit && <span className="text-[8px] font-mono text-blue-500/80 font-black">ACTIVE UNIT: {s.unit.toUpperCase()}</span>}
                </div>
                <div className={`px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                  s.status === 'IDLE' ? 'bg-slate-900/50 text-slate-600 border-slate-800' :
                  s.status === 'PROCESSING' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20 shadow-[0_0_10px_rgba(16,185,129,0.1)]' :
                  s.status === 'OCCUPIED' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
                  'bg-red-500/10 text-red-400 border-red-500/20 animate-pulse'
                }`}>
                  {s.status}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Control Center */}
        <div className="space-y-4 shrink-0 border-t border-slate-800/60 pt-5 mt-auto relative">
          <div className="grid grid-cols-2 gap-2">
            <div className="bg-slate-900/40 p-3 rounded-xl border border-slate-800/50 flex flex-col items-center">
              <span className="text-[8px] font-black text-amber-500 uppercase mb-1 flex items-center gap-1"><Wrench className="w-3 h-3" /> In Rework</span>
              <span className="text-xl font-black font-mono text-slate-200 tabular-nums">{inRepairCount}</span>
            </div>
            <div className="bg-slate-900/40 p-3 rounded-xl border border-slate-800/50 flex flex-col items-center">
              <span className="text-[8px] font-black text-red-400 uppercase mb-1 flex items-center gap-1"><AlertTriangle className="w-3 h-3" /> Defect Log</span>
              <span className="text-xl font-black font-mono text-slate-200 tabular-nums">{stats.defects}</span>
            </div>
          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-center px-1">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Line Cadence</label>
              <span className="text-blue-400 font-mono text-[10px] font-black bg-blue-500/10 px-2.5 py-1 rounded-md border border-blue-500/20">{speed.toFixed(1)}x</span>
            </div>
            <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-600 border border-slate-700/50" />
          </div>

          <div className="flex gap-2.5">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex-1 flex items-center justify-center gap-2.5 py-3.5 rounded-xl font-black tracking-widest text-[11px] uppercase transition-all shadow-xl active:scale-95 border ${isRunning ? 'bg-slate-800 text-amber-500 border-amber-500/20 hover:bg-slate-700' : 'bg-blue-600 text-white border-blue-400/30 hover:bg-blue-500 shadow-blue-900/40'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
              {isRunning ? 'HALT PRODUCTION' : 'RESUME LINE'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("Line cleared. Production data reset."); }} className="px-4 bg-slate-800 text-slate-500 rounded-xl hover:bg-slate-700 transition-colors border border-slate-800 active:scale-95"><RotateCcw className="w-5 h-5" /></button>
          </div>

          <button 
            onClick={releaseBlocked}
            className="w-full flex items-center justify-center gap-2.5 py-3 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/30 rounded-xl text-[10px] font-black tracking-widest uppercase transition-all shadow-sm active:scale-95 group"
          >
            <ShieldAlert className="w-4 h-4 group-hover:scale-110 transition-transform" />
            BYPASS FLOW RESTRICTIONS
          </button>
        </div>
      </div>

      {/* Main Viewport */}
      <div className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center',
              transition: 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)' 
            }}
            className="relative shadow-[0_0_150px_rgba(0,0,0,1)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] overflow-hidden"
          >
            <canvas 
              ref={canvasRef} 
              width={SIM_WIDTH} 
              height={SIM_HEIGHT} 
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="cursor-crosshair" 
            />

            {/* Status Legend Overlay */}
            <div className="absolute bottom-10 right-10 flex flex-col gap-3.5 pointer-events-none z-10 p-6 rounded-[2rem] bg-slate-950/80 backdrop-blur-2xl border border-white/5 shadow-2xl">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 pb-2 border-b border-white/5">System Identifiers</span>
              {['IDLE', 'PROCESSING', 'OCCUPIED', 'BLOCKED'].map(s => (
                <div key={s} className="flex items-center gap-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center border-2 border-white/5 ${
                    s === 'IDLE' ? 'bg-slate-800' : 
                    s === 'PROCESSING' ? 'bg-emerald-500/80 shadow-[0_0_12px_rgba(16,185,129,0.4)]' : 
                    s === 'OCCUPIED' ? 'bg-amber-500/80 shadow-[0_0_12px_rgba(245,158,11,0.4)]' : 
                    'bg-red-600/80 shadow-[0_0_12px_rgba(220,38,38,0.4)] animate-pulse'
                  }`}>
                    {s === 'IDLE' ? <div className="w-1.5 h-1.5 rounded-full border border-white/30" /> : 
                     s === 'PROCESSING' ? <div className="w-0 h-0 border-t-[3px] border-t-transparent border-b-[3px] border-b-transparent border-l-[4px] border-l-white ml-0.5" /> :
                     s === 'OCCUPIED' ? <div className="w-2 h-2 bg-white rounded-sm" /> : <div className="text-[11px] font-bold text-white">!</div>}
                  </div>
                  {s}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Global Performance HUD */}
        <div className="absolute top-12 right-12 flex flex-col gap-5 pointer-events-none items-end">
          <div className="bg-slate-950/90 backdrop-blur-3xl p-7 rounded-[2.5rem] border border-slate-800 shadow-2xl flex items-center gap-7 group transition-all hover:scale-105 border-b-4 border-b-blue-600/40">
            <div className="p-5 bg-blue-600/10 rounded-2xl border border-blue-500/20 group-hover:bg-blue-600/20 transition-colors shadow-inner"><Truck className="w-9 h-9 text-blue-500" /></div>
            <div>
              <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em] mb-1.5">Total Throughput</p>
              <div className="flex items-baseline gap-2.5">
                <span className="text-4xl font-black text-white leading-none">{stats.produced}</span>
                <span className="text-[12px] font-bold text-slate-600 uppercase tracking-widest">Units Out</span>
              </div>
            </div>
          </div>

          <div className="flex gap-2.5">
            <div className="bg-slate-950/60 backdrop-blur-md px-6 py-3 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest uppercase text-slate-400 flex items-center gap-3">
               <Layers className="w-4 h-4 text-blue-500" /> Scale: {Math.round(scale * 100)}%
            </div>
            <div className="bg-slate-950/60 backdrop-blur-md px-6 py-3 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest uppercase text-slate-400 flex items-center gap-3">
               <Activity className="w-4 h-4 text-emerald-500" /> Active Line: {stats.active}
            </div>
          </div>
        </div>

        {/* System Event Marquee */}
        <div className="h-14 bg-slate-950 border-t border-slate-800 flex items-center px-10 gap-10 overflow-hidden shrink-0 relative">
          <div className="absolute inset-y-0 left-0 w-40 bg-gradient-to-r from-slate-950 via-slate-950/80 to-transparent z-10" />
          <div className="absolute inset-y-0 right-0 w-40 bg-gradient-to-l from-slate-950 via-slate-950/80 to-transparent z-10" />

          <div className="flex items-center gap-4 shrink-0 z-20">
             <div className="w-2.5 h-2.5 rounded-full bg-blue-500 animate-pulse shadow-[0_0_12px_rgba(59,130,246,0.9)]" />
             <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] whitespace-nowrap">Factory Event Telemetry</span>
          </div>

          <div className="flex-1 whitespace-nowrap overflow-hidden">
            <div className="flex gap-16 animate-marquee py-2">
              {logs.length > 0 ? logs.map((log, i) => (
                <span key={i} className="text-[11px] font-bold text-slate-300 uppercase tracking-tight flex gap-4 items-center">
                  <span className="opacity-30 font-mono text-xs text-blue-400">#{stats.totalStarted - i}</span> 
                  <span className="text-blue-50/90">{log}</span>
                </span>
              )) : (
                <span className="text-[11px] font-bold text-slate-600 uppercase tracking-[0.2em] italic">System initialized. Awaiting production flow signals...</span>
              )}
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 30px; border: 2px solid #020617; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #334155; }

        .animate-marquee { display: flex; animation: marquee 50s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 16px;
          height: 16px;
          background: #3b82f6;
          border-radius: 50%;
          cursor: pointer;
          box-shadow: 0 0 12px rgba(59,130,246,0.6);
          border: 2px solid #fff;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Settings, 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  AlertTriangle, 
  Truck,
  Gauge,
  Cpu,
  Unlock,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  ListFilter,
  Layers,
  Zap,
  ShieldAlert,
  Target,
  TrendingUp,
  Search,
  ZoomIn,
  ZoomOut
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  // Scaling logic for simulation view
  const updateScale = useCallback(() => {
    if (!containerRef.current) return;

    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 80;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      const finalScale = Math.max(0.15, s);
      setScale(finalScale);
      setManualScale(finalScale); // Sync manual scale when auto-fitting
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const releaseBlocked = () => {
    addLog("MANUAL OVERRIDE: Advancing line flow...");
    vehiclesRef.current.forEach(v => {
      v.ignoreCollisionTimer = 240;
    });
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;

    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;

    if (frameCountRef.current % spawnRate === 0) {
      spawnVehicle();
    }

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue;
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`Unit ${v.id.toUpperCase()} completed cycle. Yield: ${passedFtt ? 'FTT OK' : 'REPAIRED'}`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        if (onSamePath) {
          return distToOther < 65 && (other.pathIdx >= v.pathIdx);
        } else {
          return distToOther < 45;
        }
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           const branch = ROLL_TEST_BRANCHES[bestLaneIdx];
           const newPath = [
             ...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1),
             ...branch.slice(1),
             ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)
           ];
           v.targetPath = newPath;
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx];
        if (!station && !v.inRepair) {
           station = PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        }

        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; 
            v.everRepaired = true;
            v.pendingRepairs = Math.random() < 0.4 ? 2 : 1; 
            v.targetPath = [...REPAIR_PATH_POINTS]; 
            v.pathIdx = 0;
            v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`REWORK START: ${v.id.toUpperCase()} failed QC. Stages: ${v.pendingRepairs}`);
          }
          if (v.inRepair) {
            if (station.name === 'FUNILARIA' || station.name === 'FCPA') {
              if (v.pendingRepairs > 0) {
                v.pendingRepairs--;
                addLog(`REPAIR STEP: ${v.id.toUpperCase()} at ${station.name}. Remaining: ${v.pendingRepairs}`);
              }
            }
            if (station.name === 'ÁREA BRANCA') {
              v.inRepair = false; 
              v.isRepaired = true;
              v.targetPath = [...MAIN_PATH_POINTS]; 
              v.pathIdx = 18;
              v.color = COLORS.VEHICLE;
              addLog(`REPAIR OK: ${v.id.toUpperCase()} cleared and merged.`);
            }
          }
        }
      } else {
        const ratio = speed / dist;
        v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));

    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && 
               mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 &&
               mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const drawStatusIcon = (ctx: CanvasRenderingContext2D, cx: number, cy: number, status: StationStatus, ledColor: string) => {
    ctx.save(); ctx.translate(cx, cy);
    ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(0, 0, 7, 0, Math.PI * 2); ctx.fill();
    ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 1.5; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    switch (status) {
      case 'IDLE': ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.stroke(); break;
      case 'PROCESSING': ctx.fillStyle = '#ffffff'; ctx.beginPath(); ctx.moveTo(-2, -3); ctx.lineTo(4, 0); ctx.lineTo(-2, 3); ctx.closePath(); ctx.fill(); break;
      case 'OCCUPIED': ctx.fillStyle = '#ffffff'; ctx.fillRect(-2.5, -2.5, 5, 5); break;
      case 'BLOCKED': ctx.beginPath(); ctx.moveTo(-3, -3); ctx.lineTo(3, 3); ctx.moveTo(3, -3); ctx.lineTo(-3, 3); ctx.stroke(); break;
    }
    ctx.restore();
  };

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 32) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#2d3a4d', 28));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#450a0a', 26);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 45;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isActuallyBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isActuallyBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let statusColor = COLORS.STATION; let ledColor = '#1e293b'; let glow = false;
      switch(status) {
        case 'PROCESSING': statusColor = '#065f46'; ledColor = '#10b981'; glow = true; break;
        case 'OCCUPIED': statusColor = '#92400e'; ledColor = '#fbbf24'; break;
        case 'BLOCKED': statusColor = '#7f1d1d'; ledColor = '#ef4444'; glow = true; break;
      }

      const isHovered = hoveredStationId === s.id;
      if (isHovered) { 
        ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 3; 
        ctx.setLineDash([5, 5]);
      } else { 
        ctx.strokeStyle = COLORS.STATION_BORDER; ctx.lineWidth = 1.5; 
        ctx.setLineDash([]);
      }

      if (glow) { ctx.shadowBlur = (Math.sin(frameCountRef.current / 5) + 1) * 8; ctx.shadowColor = ledColor; } else { ctx.shadowBlur = 0; }

      ctx.fillStyle = statusColor; ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke(); ctx.shadowBlur = 0;
      ctx.setLineDash([]);

      drawStatusIcon(ctx, x + w - 15, y + 15, status, ledColor);
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 10px Inter'; ctx.fillText(s.name, x + 8, y + 16);

      if (isHovered && s.type === StationType.REPAIR) {
         ctx.fillStyle = 'rgba(255,255,255,0.9)'; ctx.font = '800 8px Inter';
         ctx.fillText('CRITICAL REWORK POINT', x + 8, y + 28);
      }

      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(0,0,0,0.3)'; ctx.fillRect(x + 8, y + h - 8, w - 16, 3);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 8, y + h - 8, (w - 16) * prog, 3);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isBlocked = v.waitingTimer === 0 && v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
      });

      if (isBlocked) {
        ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(0, 0, 25, 0, Math.PI * 2); ctx.stroke();
      }

      if (v.ignoreCollisionTimer > 0) ctx.globalAlpha = 0.5 + Math.sin(frameCountRef.current / 4) * 0.2;
      ctx.shadowBlur = 5; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.drawImage(vehicleImage.current, -22.5, -12, 45, 24);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-22.5, -12, 45, 24, 4); ctx.fill();

      if (v.inRepair && v.pendingRepairs > 0) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = '#ffffff'; ctx.font = 'bold 9px Inter';
        ctx.fillText(`! ${v.pendingRepairs}`, -5, 5);
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.95)'; ctx.font = 'bold 28px Inter'; ctx.fillText('INDUSTRIAL ASSEMBLY LINE', 50, 48);
    ctx.font = '11px Inter'; ctx.fillStyle = 'rgba(255, 255, 255, 0.5)'; ctx.fillText('V4.9 // SMART DASHBOARD // PROCESS DIMENSIONING', 50, 68);
  }, [hoveredStationId, drawStatusIcon, speed]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) {
      mousePosRef.current = {
        x: (e.clientX - rect.left) / scale,
        y: (e.clientY - rect.top) / scale
      };
    }
  };

  const handleMouseLeave = () => {
    mousePosRef.current = null;
    setHoveredStationId(null);
  };

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const yieldRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;
  const repairEfficiency = stats.repairAttempts > 0 ? (stats.totalRepaired / stats.repairAttempts) * 100 : 0;

  const ecatTelemetry = useMemo(() => {
    return PARALLEL_ROLL_STATIONS.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 5 && Math.abs(veh.pos.y - s.pos.y) < 5);
      let progress = 0; let curSpeed = 0;
      if (v && v.waitingTimer > 0) {
        progress = 1 - (v.waitingTimer / s.wait);
        curSpeed = Math.min(100, progress < 0.2 ? progress * 500 : (90 + Math.random() * 5));
      }
      return { id: s.id, name: s.name, unit: v?.id.toUpperCase() || '---', speed: curSpeed, progress };
    });
  }, [vehiclesRef.current, frameCountRef.current]);

  const stationMonitorData = useMemo(() => {
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    return allStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, unit: v?.id || null };
    });
  }, [vehiclesRef.current]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Dashboard - Full Scroll Capability */}
      <div className="w-[380px] lg:w-[460px] bg-slate-950 border-r border-slate-800 flex flex-col shadow-2xl shrink-0 z-20 overflow-hidden relative">
        <div className="absolute inset-0 bg-gradient-to-b from-blue-600/5 to-transparent pointer-events-none" />

        {/* Header - Fixed */}
        <div className="p-6 border-b border-slate-800/60 bg-slate-950/80 backdrop-blur-md z-30 shrink-0">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2.5 rounded-xl shadow-lg shadow-blue-900/40 border border-blue-400/30"><Cpu className="w-5 h-5 text-white" /></div>
              <div>
                <h1 className="text-xl font-black tracking-tighter uppercase italic leading-none text-blue-50">Control.HQ</h1>
                <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Digital Twin v4.9</span>
              </div>
            </div>
            <div className="flex items-center gap-2">
               <button 
                 onClick={() => setIsFitToScreen(!isFitToScreen)}
                 className={`flex items-center gap-2 px-3 py-2 rounded-xl border transition-all text-[9px] font-black uppercase tracking-wider ${isFitToScreen ? 'bg-blue-500/20 border-blue-500/40 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
               >
                 {isFitToScreen ? <Maximize2 className="w-3.5 h-3.5" /> : <Minimize2 className="w-3.5 h-3.5" />}
                 {isFitToScreen ? 'Auto-Fit' : 'Manual'}
               </button>
            </div>
          </div>
        </div>

        {/* Scrollable Dashboard Body */}
        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">

          {/* Main KPI Matrix */}
          <section className="space-y-4">
            <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-[0.2em] px-1"><BarChart3 className="w-3.5 h-3.5" /> Performance Hub</div>
            <div className="grid grid-cols-3 gap-2.5">
              <div className="bg-slate-900/60 p-3.5 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-blue-500/50 transition-colors">
                <div className="flex items-center gap-1.5 text-blue-400 mb-2"><CheckCircle2 className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.1em] opacity-60">FTT</span></div>
                <p className="text-xl font-black tabular-nums tracking-tighter">{fttRate.toFixed(1)}%</p>
              </div>
              <div className="bg-slate-900/60 p-3.5 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-emerald-500/50 transition-colors">
                <div className="flex items-center gap-1.5 text-emerald-400 mb-2"><TrendingUp className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.1em] opacity-60">OEE</span></div>
                <p className="text-xl font-black tabular-nums tracking-tighter">{yieldRate.toFixed(1)}%</p>
              </div>
              <div className="bg-slate-900/60 p-3.5 rounded-2xl border border-slate-800 flex flex-col items-center justify-center backdrop-blur-sm group hover:border-amber-500/50 transition-colors">
                <div className="flex items-center gap-1.5 text-amber-400 mb-2"><Target className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.1em] opacity-60">REPAIR</span></div>
                <p className="text-xl font-black tabular-nums tracking-tighter">{repairEfficiency.toFixed(1)}%</p>
              </div>
            </div>
          </section>

          {/* ECAT Telemetry Center */}
          <section className="space-y-4">
            <div className="flex items-center justify-between px-1">
              <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-[0.2em]"><Gauge className="w-3.5 h-3.5" /> ECAT Real-Time</div>
              <div className="flex gap-1.5 items-center">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)]" />
              </div>
            </div>
            <div className="grid grid-cols-1 gap-2.5">
              {ecatTelemetry.map((ecat) => (
                <div key={ecat.id} className="bg-slate-900/40 border border-slate-800 p-4 rounded-2xl flex flex-col gap-3 group hover:bg-slate-800/50 transition-all border-l-4 border-l-blue-600/50">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black text-slate-300 uppercase truncate w-32 tracking-tighter">{ecat.name}</span>
                    <span className="bg-slate-800 text-blue-400 px-2.5 py-1 rounded text-[9px] font-mono font-black border border-slate-700/50">{ecat.unit}</span>
                  </div>
                  <div className="flex items-end justify-between">
                     <div className="flex flex-col">
                        <div className="flex items-baseline gap-1">
                          <span className={`text-2xl font-black tabular-nums tracking-tighter transition-colors ${ecat.speed > 80 ? 'text-blue-400' : 'text-slate-200'}`}>{Math.round(ecat.speed)}</span>
                          <span className="text-[10px] font-bold text-slate-700">km/h</span>
                        </div>
                     </div>
                     <div className="flex-1 px-4 mb-1.5">
                        <div className="h-2 bg-slate-800 rounded-full overflow-hidden border border-slate-700/30">
                          <div className="h-full bg-blue-500 transition-all duration-300 shadow-[0_0_12px_rgba(59,130,246,0.6)]" style={{ width: `${ecat.progress * 100}%` }} />
                        </div>
                     </div>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Sector Diagnostics - Embedded List */}
          <section className="space-y-4">
            <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-[0.2em] px-1"><ListFilter className="w-3.5 h-3.5" /> Status Monitor</div>
            <div className="space-y-2">
              {stationMonitorData.map((s) => (
                <div key={s.id} className="bg-slate-900/20 border border-slate-800/40 px-3.5 py-3 rounded-xl flex items-center justify-between hover:bg-slate-800/30 transition-colors group">
                  <div className="flex flex-col gap-0.5">
                    <span className="text-[10px] font-bold text-slate-400 group-hover:text-blue-50 transition-colors uppercase tracking-tight truncate w-36">{s.name}</span>
                    {s.unit && <span className="text-[8px] font-mono text-blue-500/80 font-black tracking-tight">ACTIVE: {s.unit.toUpperCase()}</span>}
                  </div>
                  <div className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase tracking-widest border ${
                    s.status === 'IDLE' ? 'bg-slate-900/50 text-slate-600 border-slate-800' :
                    s.status === 'PROCESSING' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' :
                    s.status === 'OCCUPIED' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
                    'bg-red-500/10 text-red-400 border-red-500/20 animate-pulse'
                  }`}>
                    {s.status}
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Process Controls & Dimensioning */}
          <section className="space-y-6 pt-4 border-t border-slate-800/60 pb-10">
            <div className="flex items-center gap-2 text-xs font-black text-slate-500 uppercase tracking-[0.2em] px-1"><Settings className="w-3.5 h-3.5" /> Command Center</div>

            {/* Dimensioning Control */}
            <div className="space-y-4 bg-slate-900/30 p-4 rounded-2xl border border-slate-800/50">
              <div className="flex justify-between items-center">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Layers className="w-3 h-3 text-blue-500" /> Process Scale
                </label>
                <span className="text-blue-400 font-mono text-[10px] font-black bg-blue-500/10 px-2.5 py-1 rounded-md border border-blue-500/20">
                  {Math.round(scale * 100)}%
                </span>
              </div>
              <div className="flex items-center gap-4">
                <ZoomOut className="w-4 h-4 text-slate-600" />
                <input 
                  type="range" 
                  min="0.15" 
                  max="1.5" 
                  step="0.01" 
                  value={manualScale} 
                  disabled={isFitToScreen}
                  onChange={(e) => setManualScale(parseFloat(e.target.value))} 
                  className={`flex-1 h-2 rounded-lg appearance-none cursor-pointer border border-slate-700/50 ${isFitToScreen ? 'bg-slate-800/50 cursor-not-allowed opacity-30' : 'bg-slate-800 accent-blue-600'}`} 
                />
                <ZoomIn className="w-4 h-4 text-slate-600" />
              </div>
              {isFitToScreen && (
                <p className="text-[8px] font-bold text-slate-600 uppercase italic">Scale is managed by 'Auto-Fit' mode</p>
              )}
            </div>

            {/* Line Cadence Control */}
            <div className="space-y-4 bg-slate-900/30 p-4 rounded-2xl border border-slate-800/50">
              <div className="flex justify-between items-center">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Clock className="w-3 h-3 text-emerald-500" /> Line Cadence
                </label>
                <span className="text-emerald-400 font-mono text-[10px] font-black bg-emerald-500/10 px-2.5 py-1 rounded-md border border-emerald-500/20">{speed.toFixed(1)}x</span>
              </div>
              <input type="range" min="0.5" max="8" step="0.1" value={speed} onChange={(e) => setSpeed(parseFloat(e.target.value))} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-emerald-600 border border-slate-700/50" />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2.5 py-4 rounded-xl font-black tracking-widest text-[11px] uppercase transition-all shadow-xl active:scale-95 border ${isRunning ? 'bg-slate-800 text-amber-500 border-amber-500/20 hover:bg-slate-700' : 'bg-blue-600 text-white border-blue-400/30 hover:bg-blue-500 shadow-blue-900/40'}`}>
                {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
                {isRunning ? 'Halt' : 'Resume'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; addLog("Line cleared. Production data reset."); }} className="flex items-center justify-center gap-2 bg-slate-800 text-slate-500 rounded-xl hover:bg-slate-700 transition-colors border border-slate-800 active:scale-95 py-4 font-black text-[11px] uppercase">
                <RotateCcw className="w-4 h-4" /> Reset
              </button>
            </div>

            <button 
              onClick={releaseBlocked}
              className="w-full flex items-center justify-center gap-2.5 py-3.5 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-500/30 rounded-xl text-[10px] font-black tracking-widest uppercase transition-all shadow-sm active:scale-95 group"
            >
              <ShieldAlert className="w-4 h-4 group-hover:scale-110 transition-transform" />
              FORCE LINE ADVANCE
            </button>
          </section>
        </div>
      </div>

      {/* Main Process Viewport */}
      <div className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center',
              transition: isFitToScreen ? 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' 
            }}
            className="relative shadow-[0_0_150px_rgba(0,0,0,1)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0"
          >
            <canvas 
              ref={canvasRef} 
              width={SIM_WIDTH} 
              height={SIM_HEIGHT} 
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
              className="cursor-crosshair" 
            />

            {/* Status Legend Overlay */}
            <div className="absolute bottom-10 right-10 flex flex-col gap-3.5 pointer-events-none z-10 p-6 rounded-[2rem] bg-slate-950/80 backdrop-blur-2xl border border-white/5 shadow-2xl">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 pb-2 border-b border-white/5">System Identifiers</span>
              {['IDLE', 'PROCESSING', 'OCCUPIED', 'BLOCKED'].map(s => (
                <div key={s} className="flex items-center gap-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <div className={`w-6 h-6 rounded-full flex items-center justify-center border-2 border-white/5 ${
                    s === 'IDLE' ? 'bg-slate-800' : 
                    s === 'PROCESSING' ? 'bg-emerald-500/80 shadow-[0_0_12px_rgba(16,185,129,0.4)]' : 
                    s === 'OCCUPIED' ? 'bg-amber-500/80 shadow-[0_0_12px_rgba(245,158,11,0.4)]' : 
                    'bg-red-600/80 shadow-[0_0_12px_rgba(220,38,38,0.4)] animate-pulse'
                  }`}>
                    {s === 'IDLE' ? <div className="w-1.5 h-1.5 rounded-full border border-white/30" /> : 
                     s === 'PROCESSING' ? <div className="w-0 h-0 border-t-[3px] border-t-transparent border-b-[3px] border-b-transparent border-l-[4px] border-l-white ml-0.5" /> :
                     s === 'OCCUPIED' ? <div className="w-2 h-2 bg-white rounded-sm" /> : <div className="text-[11px] font-bold text-white">!</div>}
                  </div>
                  {s}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* HUD Performance Layer */}
        <div className="absolute top-12 right-12 flex flex-col gap-5 pointer-events-none items-end">
          <div className="bg-slate-950/90 backdrop-blur-3xl p-7 rounded-[2.5rem] border border-slate-800 shadow-2xl flex items-center gap-7 group transition-all hover:scale-105 border-b-4 border-b-blue-600/40">
            <div className="p-5 bg-blue-600/10 rounded-2xl border border-blue-500/20 group-hover:bg-blue-600/20 transition-colors shadow-inner"><Truck className="w-9 h-9 text-blue-500" /></div>
            <div>
              <p className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em] mb-1.5">Total Throughput</p>
              <div className="flex items-baseline gap-2.5">
                <span className="text-4xl font-black text-white leading-none">{stats.produced}</span>
                <span className="text-[12px] font-bold text-slate-600 uppercase tracking-widest">Units Out</span>
              </div>
