          </div>

          <div className="flex gap-2.5">
            <div className="bg-slate-950/60 backdrop-blur-md px-6 py-3 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest uppercase text-slate-400 flex items-center gap-3">
               <Layers className="w-4 h-4 text-blue-50" /> Scale: {Math.round(scale * 100)}%
            </div>
            <div className="bg-slate-950/60 backdrop-blur-md px-6 py-3 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest uppercase text-slate-400 flex items-center gap-3">
               <Activity className="w-4 h-4 text-emerald-500" /> Active: {stats.active}
            </div>
          </div>
        </div>

        {/* Ticker Marquee */}
        <div className="h-14 bg-slate-950 border-t border-slate-800 flex items-center px-10 gap-10 overflow-hidden shrink-0 relative">
          <div className="absolute inset-y-0 left-0 w-40 bg-gradient-to-r from-slate-950 via-slate-950/80 to-transparent z-10" />
          <div className="absolute inset-y-0 right-0 w-40 bg-gradient-to-l from-slate-950 via-slate-950/80 to-transparent z-10" />

          <div className="flex items-center gap-4 shrink-0 z-20">
             <div className="w-2.5 h-2.5 rounded-full bg-blue-500 animate-pulse shadow-[0_0_12px_rgba(59,130,246,0.9)]" />
