        {/* Footer / Control Hub - Fixed */}
        <div className="p-6 border-t border-slate-900 space-y-5 shrink-0 bg-slate-950">

          {/* Dimensioning Controls */}
          <div className="space-y-3">
             <div className="flex justify-between items-center text-[8px] font-black text-slate-600 uppercase tracking-widest">
                <span className="flex items-center gap-1.5"><Maximize2 className="w-2.5 h-2.5" /> Viewport Dimensioning</span>
                <span className="text-blue-500">{Math.round(scale * 100)}%</span>
             </div>
             <div className="flex items-center gap-3">
               <ZoomOut className="w-3 h-3 text-slate-700" />
               <input 
                 type="range" min="0.15" max="1.5" step="0.01" 
                 value={manualScale} disabled={isFitToScreen}
                 onChange={(e) => setManualScale(parseFloat(e.target.value))} 
                 className={`flex-1 h-1 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-blue-600 cursor-pointer'}`} 
               />
               <ZoomIn className="w-3 h-3 text-slate-700" />
             </div>
          </div>

          {/* Primary Operations */}
          <div className="grid grid-cols-2 gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2 py-3 rounded-lg font-black text-[9px] uppercase border transition-all active:scale-95 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20' : 'bg-blue-600 text-white border-blue-400/30'}`}>
              {isRunning ? <Pause className="w-3 h-3" /> : <Play className="w-3 h-3" />}
              {isRunning ? 'Line Halt' : 'Line Init'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("PRODUCTION RESET."); }} className="flex items-center justify-center gap-2 py-3 bg-slate-900 text-slate-500 rounded-lg border border-slate-800 font-black text-[9px] uppercase hover:text-white transition-colors active:scale-95">
              <RotateCcw className="w-3 h-3" /> Reset
            </button>
          </div>
        </div>
      </aside>

      {/* PROCESS VIEWPORT */}
      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div 
            style={{ 
              width: SIM_WIDTH, height: SIM_HEIGHT, 
              transform: `scale(${scale})`, transformOrigin: 'center',
              transition: isFitToScreen ? 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' 
            }}
            className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0"
          >
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} className="cursor-crosshair" />
          </div>
        </div>

        {/* Minimal Event Ticker */}
        <div className="h-10 bg-slate-950 border-t border-slate-900 flex items-center px-6 gap-6 overflow-hidden shrink-0 relative">
          <div className="absolute inset-y-0 left-0 w-20 bg-gradient-to-r from-slate-950 to-transparent z-10" />
          <div className="absolute inset-y-0 right-0 w-20 bg-gradient-to-l from-slate-950 to-transparent z-10" />

          <span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.3em] shrink-0 z-20">Production_Pulse</span>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-16 animate-marquee py-1">
              {logs.length > 0 ? logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-500 uppercase tracking-tight flex gap-3 items-center">
                  <span className="w-1 h-1 rounded-full bg-blue-500/30" /> {log}
                </span>
              )) : (
                <span className="text-[9px] font-bold text-slate-700 uppercase italic opacity-40">System scanning production nodes...</span>
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #334155; }

        .animate-marquee { display: flex; animation: marquee 60s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 12px;
          height: 12px;
          background: currentColor;
          border-radius: 50%;
          border: 2px solid #fff;
          cursor: pointer;
          box-shadow: 0 0 8px rgba(0,0,0,0.5);
        }
      `}</style>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  finished: boolean;
  progress: number;
  // Added for tracking and unblocking
  everRepaired: boolean;
  ignoreCollisionTimer: number;
  pendingRepairs: number; // Number of repair stages needed
  completedRepairs: number; // Number of repair stages finished
  initialRepairs: number; // Total stages assigned at QC
  isLocked: boolean; // Manual release gate
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  // Added industrial metrics
  totalStarted: number;
  passedFirstTime: number;
  totalRepaired: number;
  repairAttempts: number; // Total units sent to repair
  totalStagesCompleted: number; // Global count of repair tasks done
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Truck,
  Gauge,
  Cpu,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  Layers,
  ShieldAlert,
  Target,
  ZoomIn,
  ZoomOut,
  ChevronRight,
  MonitorDot,
  TrendingUp,
  Settings2,
  ActivitySquare,
  Search,
  Filter,
  Lock,
  Unlock,
  Key
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);
  const [hoveredVehicleId, setHoveredVehicleId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 60;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      const finalScale = Math.max(0.15, s);
      setScale(finalScale);
      setManualScale(finalScale);
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      addLog(`MANUAL RELEASE: UNIT ${v.id.toUpperCase()}`);
    }
  };

  const unlockAll = () => {
    const lockedCount = vehiclesRef.current.filter(v => v.isLocked).length;
    if (lockedCount > 0) {
      vehiclesRef.current.forEach(v => v.isLocked = false);
      addLog(`BATCH RELEASE: ${lockedCount} UNITS`);
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; // Movement fully stopped at gate

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`UNIT ${v.id.toUpperCase()} FINISHED [${passedFtt ? 'FTR' : 'REWORK'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // GATE LOCK LOGIC: After final testing (Ruído), lock before Embarque
        // Point index 22 is "Turn Final", 21 is "Sistema Ruído".
        if (v.pathIdx === 22 && !v.inRepair) {
           v.isLocked = true;
           addLog(`GATE HOLD: UNIT ${v.id.toUpperCase()}`);
        }

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           v.targetPath = [...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), ...ROLL_TEST_BRANCHES[bestLaneIdx].slice(1), ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true; 
            const stages = Math.random() < 0.4 ? 2 : 1;
            v.pendingRepairs = stages; 
            v.initialRepairs = stages;
            v.completedRepairs = 0;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`REWORK START: ${v.id.toUpperCase()} [${stages} STAGES]`);
          }
          if (v.inRepair && (station.name === 'FUNILARIA' || station.name === 'FCPA')) {
            if (v.pendingRepairs > 0) {
              v.pendingRepairs--;
              v.completedRepairs++;
              setStats(s => ({ ...s, totalStagesCompleted: s.totalStagesCompleted + 1 }));
            }
          }
          if (v.inRepair && station.name === 'ÁREA BRANCA') { v.inRepair = false; v.isRepaired = true; v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; v.color = COLORS.VEHICLE; }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 && mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 22));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#330a0a', 22);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 38;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let ledColor = '#334155'; switch(status) { case 'PROCESSING': ledColor = '#10b981'; break; case 'OCCUPIED': ledColor = '#fbbf24'; break; case 'BLOCKED': ledColor = '#ef4444'; break; }
      const isHovered = hoveredStationId === s.id;

      if (isHovered) {
        ctx.shadowBlur = 15; ctx.shadowColor = 'rgba(59, 130, 246, 0.5)';
      }

      ctx.strokeStyle = isHovered ? '#3b82f6' : 'rgba(255,255,255,0.08)'; ctx.lineWidth = isHovered ? 2 : 1;
      ctx.fillStyle = 'rgba(15, 23, 42, 0.85)'; ctx.beginPath(); ctx.roundRect(x, y, w, h, 3); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(x + 10, y + 10, 3.5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 18, y + 13);
      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.fillRect(x + 5, y + h - 6, w - 10, 2);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 5, y + h - 6, (w - 10) * prog, 2);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isHoveredV = hoveredVehicleId === v.id;
      if (isHoveredV) {
        ctx.shadowBlur = 12; ctx.shadowColor = 'white';
      } else {
        ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.4)';
      }

      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 3); ctx.fill();

      // Repair Progress Overlay
      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = 'white'; ctx.font = 'bold 7px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(`${v.completedRepairs}/${v.initialRepairs}`, 0, 2);
        else if (v.isLocked) {
          ctx.save(); ctx.rotate(-v.rotation);
          ctx.fillStyle = '#fbbf24';
          ctx.beginPath(); ctx.arc(0, -15, 4, 0, Math.PI * 2); ctx.fill();
          ctx.restore();
        }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)'; ctx.font = '800 20px Inter'; ctx.fillText('FACTORY_TWIN_V4.9', 50, 45);
  }, [hoveredStationId, hoveredVehicleId, speed]);

  useEffect(() => {
    let frameId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } frameId = requestAnimationFrame(loop); };
    frameId = requestAnimationFrame(loop); return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) { mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale }; }
  };

  // KPI Calculations
  const ftrRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const fttRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;
  const repairEfficiency = stats.repairAttempts > 0 ? (stats.totalRepaired / stats.repairAttempts) * 100 : 0;

  const allProductionStations = useMemo(() => {
    return [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
  }, []);

  const stationMonitorData = useMemo(() => {
    return allProductionStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, type: s.type };
    });
  }, [vehiclesRef.current, allProductionStations]);

  const statusBreakdown = useMemo(() => {
    const counts = { IDLE: 0, PROCESSING: 0, OCCUPIED: 0, BLOCKED: 0 };
    stationMonitorData.forEach(s => counts[s.status]++);
    return counts;
  }, [stationMonitorData]);

  const filteredStations = useMemo(() => {
    return stationMonitorData.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.status.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stationMonitorData, searchTerm]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);
  const lockedVehicles = useMemo(() => vehiclesRef.current.filter(v => v.isLocked), [vehiclesRef.current]);

  const ecatTelemetry = useMemo(() => [
    { id: 'e1', name: 'Fleet A1', unit: 'SENS_L0', speed: speed * 1.15, progress: Math.min(1, stats.active / 20) },
    { id: 'e2', name: 'Main Line', unit: 'VFD_01', speed: isRunning ? speed * 0.9 : 0, progress: 0.8 },
    { id: 'e3', name: 'Rework Bus', unit: 'BUF_QC', speed: inRepairCount > 0 ? speed * 0.4 : 0, progress: Math.min(1, inRepairCount / 5) }
  ], [speed, stats.active, isRunning, inRepairCount]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
      {/* MINIMALIST SCROLLABLE DASHBOARD */}
      <aside className="w-[340px] lg:w-[400px] bg-slate-950 border-r border-slate-900 flex flex-col shadow-2xl shrink-0 z-20">

        {/* Header - Fixed */}
        <div className="p-6 border-b border-slate-900 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20"><Cpu className="w-4 h-4 text-white" /></div>
            <h1 className="text-xs font-black tracking-[0.2em] uppercase opacity-90">Line_Ops.v4</h1>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`flex items-center gap-2 px-2.5 py-1.5 rounded-md border transition-all text-[8px] font-black uppercase tracking-wider ${isFitToScreen ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
          >
            {isFitToScreen ? <Maximize2 className="w-3 h-3" /> : <Minimize2 className="w-3 h-3" />}
            {isFitToScreen ? 'Auto-Fit' : 'Manual'}
          </button>
        </div>

        {/* Scrollable Dashboard Body */}
        <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col">

          {/* Primary Performance Matrix */}
          <section className="p-6 grid grid-cols-2 gap-3 border-b border-slate-900 bg-slate-950/20 shrink-0">
            <div className="bg-slate-900/30 p-4 rounded-xl border border-slate-800/50 flex flex-col group">
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-blue-400 transition-colors">FTR Rate</span>
              <span className="text-2xl font-black text-blue-500 tabular-nums leading-none tracking-tighter">{ftrRate.toFixed(1)}%</span>
            </div>
            <div className="bg-slate-900/30 p-4 rounded-xl border border-slate-800/50 flex flex-col group">
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-emerald-400 transition-colors">FTT Yield</span>
              <span className="text-2xl font-black text-emerald-500 tabular-nums leading-none tracking-tighter">{fttRate.toFixed(1)}%</span>
            </div>
          </section>

          {/* NEW: GATE RELEASE CONTROL */}
          <section className="p-6 space-y-4 border-b border-slate-900/50 bg-amber-500/5">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-amber-500 uppercase tracking-[0.2em] flex items-center gap-2"><Lock className="w-3 h-3" /> Gate Release Queue</span>
              {lockedVehicles.length > 0 && (
                <button 
                  onClick={unlockAll}
                  className="text-[8px] font-black bg-amber-500 text-slate-950 px-2 py-1 rounded hover:bg-amber-400 transition-colors uppercase"
                >
                  Unlock All
                </button>
              )}
            </div>
            <div className="space-y-1 max-h-[150px] overflow-y-auto custom-scrollbar">
              {lockedVehicles.length > 0 ? lockedVehicles.map(v => (
                <div 
                  key={v.id} 
                  onMouseEnter={() => setHoveredVehicleId(v.id)}
                  onMouseLeave={() => setHoveredVehicleId(null)}
                  className="flex items-center justify-between bg-slate-900/60 p-2 rounded border border-amber-500/20 group hover:border-amber-500/50 transition-all"
                >
                  <div className="flex items-center gap-2">
                    <Truck className="w-3 h-3 text-slate-500" />
                    <span className="text-[10px] font-black text-slate-200">UNIT_{v.id.toUpperCase()}</span>
                  </div>
                  <button 
                    onClick={() => unlockVehicle(v.id)}
                    className="p-1.5 bg-amber-500/10 hover:bg-amber-500 text-amber-500 hover:text-slate-950 rounded transition-all"
                  >
                    <Unlock className="w-3 h-3" />
                  </button>
                </div>
              )) : (
                <div className="text-center py-4 border border-dashed border-slate-900 rounded text-[8px] font-bold text-slate-700 uppercase italic">Gate empty: all units released</div>
              )}
            </div>
          </section>

          {/* Repair Analytics Hub */}
          <section className="p-6 space-y-4 border-b border-slate-900/50">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><Wrench className="w-3 h-3" /> Repair Intelligence</span>
              <ActivitySquare className="w-3 h-3 text-slate-700" />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div className="bg-slate-900/20 p-3 rounded-lg border border-slate-900 flex flex-col">
                <p className="text-[7px] font-bold text-slate-600 uppercase mb-1">Reworking Now</p>
                <div className="flex items-baseline gap-1.5">
                  <p className="text-lg font-black text-amber-500 tabular-nums">{inRepairCount}</p>
                  <p className="text-[9px] font-bold text-slate-700">UNITS</p>
                </div>
              </div>
              <div className="bg-slate-900/20 p-3 rounded-lg border border-slate-900 flex flex-col">
                <p className="text-[7px] font-bold text-slate-600 uppercase mb-1">Stages Fixed</p>
                <p className="text-lg font-black text-slate-300 tabular-nums">{stats.totalStagesCompleted}</p>
              </div>
            </div>
          </section>

          {/* Station Status Functionality Section */}
          <section className="p-6 space-y-6 border-b border-slate-900/50">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><MonitorDot className="w-3 h-3" /> Area Status</span>
              <span className="text-[8px] font-bold text-slate-800 tracking-widest">{stationMonitorData.length} TOTAL NODES</span>
            </div>

            {/* Status Breakdown Summary */}
            <div className="grid grid-cols-4 gap-1.5">
              {[
                { label: 'Idle', count: statusBreakdown.IDLE, color: 'bg-slate-800' },
                { label: 'Proc', count: statusBreakdown.PROCESSING, color: 'bg-emerald-500' },
                { label: 'Occ', count: statusBreakdown.OCCUPIED, color: 'bg-amber-500' },
                { label: 'Blk', count: statusBreakdown.BLOCKED, color: 'bg-red-500' },
              ].map(item => (
                <div key={item.label} className="bg-slate-900/40 p-2 rounded border border-slate-900/50 flex flex-col items-center">
                  <div className={`w-1 h-1 rounded-full ${item.color} mb-1.5`} />
                  <span className="text-[7px] font-black text-slate-600 uppercase mb-1">{item.label}</span>
                  <span className="text-[11px] font-black text-slate-400">{item.count}</span>
                </div>
              ))}
            </div>

            {/* Node Filter */}
            <div className="relative group">
              <Search className="absolute left-2.5 top-2.5 w-3 h-3 text-slate-700 group-focus-within:text-blue-500 transition-colors" />
              <input 
                type="text" 
                placeholder="SEARCH NODE..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-900/50 border border-slate-900 rounded-lg py-2 pl-8 pr-3 text-[8px] font-black tracking-widest text-slate-400 focus:outline-none focus:border-blue-500/50 transition-all placeholder:text-slate-800"
              />
            </div>

            {/* Production Station List */}
            <div className="space-y-1 max-h-[300px] overflow-y-auto custom-scrollbar pr-1">
              {filteredStations.length > 0 ? filteredStations.map((s) => (
                <div 
                  key={s.id} 
                  onMouseEnter={() => setHoveredStationId(s.id)}
                  onMouseLeave={() => setHoveredStationId(null)}
                  className={`group flex items-center justify-between py-1.5 px-2 rounded cursor-pointer transition-all ${hoveredStationId === s.id ? 'bg-blue-500/10 border-blue-500/20 translate-x-1' : 'hover:bg-slate-900/30 border border-transparent'}`}
                >
                  <div className="flex items-center gap-2.5 truncate">
                    <div className={`w-1.5 h-1.5 rounded-full transition-shadow duration-300 ${
                      s.status === 'IDLE' ? 'bg-slate-800' :
                      s.status === 'PROCESSING' ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.3)]' :
                      s.status === 'OCCUPIED' ? 'bg-amber-500' : 'bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.4)]'
                    }`} />
                    <span className={`text-[9px] font-bold transition-colors uppercase truncate tracking-tight ${hoveredStationId === s.id ? 'text-blue-400' : 'text-slate-500 group-hover:text-slate-300'}`}>{s.name}</span>
                  </div>
                  <span className={`text-[7px] font-black px-1.5 py-0.5 rounded tracking-tighter ${s.type === StationType.REPAIR ? 'text-red-500 bg-red-500/5 border border-red-500/10' : 'text-slate-700 bg-slate-900/40'}`}>{s.status}</span>
                </div>
              )) : (
                <div className="text-center py-4 border border-dashed border-slate-900 rounded text-[8px] font-bold text-slate-700 uppercase italic">No nodes found</div>
              )}
            </div>
          </section>

          {/* Real-time Telemetry Section */}
          <section className="p-6 space-y-4">
            <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><Gauge className="w-3 h-3" /> ECAT Real-Time</span>
            <div className="space-y-3">
              {ecatTelemetry.map((ecat) => (
                <div key={ecat.id} className="bg-slate-900/40 p-3 rounded-xl border border-slate-800/30 flex flex-col gap-2.5">
                  <div className="flex justify-between items-center">
                    <span className="text-[8px] font-black text-slate-500 uppercase">{ecat.name}</span>
                    <span className="text-[8px] font-mono text-blue-400 opacity-60">{ecat.unit}</span>
                  </div>
                  <div className="flex items-center gap-4">
                     <span className="text-lg font-black tabular-nums tracking-tighter text-slate-200">{Math.round(ecat.speed)}<span className="text-[8px] opacity-40 ml-1">KM/H</span></span>
                     <div className="flex-1 h-1 bg-slate-900 rounded-full overflow-hidden">
                        <div className="h-full bg-blue-600 transition-all duration-300 ease-out" style={{ width: `${ecat.progress * 100}%` }} />
                     </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* Footer / Control Hub - Fixed */}
        <div className="p-6 border-t border-slate-900 space-y-5 shrink-0 bg-slate-950">

          {/* Dimensioning Controls */}
          <div className="space-y-3">
             <div className="flex justify-between items-center text-[8px] font-black text-slate-600 uppercase tracking-widest">
                <span className="flex items-center gap-1.5"><Maximize2 className="w-2.5 h-2.5" /> Viewport Dimensioning</span>
                <span className="text-blue-500">{Math.round(scale * 100)}%</span>
             </div>
             <div className="flex items-center gap-3">
               <ZoomOut className="w-3 h-3 text-slate-700" />
               <input 
                 type="range" min="0.15" max="1.5" step="0.01" 
                 value={manualScale} disabled={isFitToScreen}
                 onChange={(e) => setManualScale(parseFloat(e.target.value))} 
                 className={`flex-1 h-1 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-blue-600 cursor-pointer'}`} 
               />
               <ZoomIn className="w-3 h-3 text-slate-700" />
             </div>
          </div>

          {/* Primary Operations */}
          <div className="grid grid-cols-2 gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2 py-3 rounded-lg font-black text-[9px] uppercase border transition-all active:scale-95 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20' : 'bg-blue-600 text-white border-blue-400/30'}`}>
              {isRunning ? <Pause className="w-3 h-3" /> : <Play className="w-3 h-3" />}
              {isRunning ? 'Line Halt' : 'Line Init'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("PRODUCTION RESET."); }} className="flex items-center justify-center gap-2 py-3 bg-slate-900 text-slate-500 rounded-lg border border-slate-800 font-black text-[9px] uppercase hover:text-white transition-colors active:scale-95">
              <RotateCcw className="w-3 h-3" /> Reset
            </button>
          </div>
        </div>
      </aside>

      {/* PROCESS VIEWPORT */}
      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div 
            style={{ 
              width: SIM_WIDTH, height: SIM_HEIGHT, 
              transform: `scale(${scale})`, transformOrigin: 'center',
              transition: isFitToScreen ? 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' 
            }}
            className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0"
          >
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} className="cursor-crosshair" />
          </div>
        </div>

        {/* Minimal Event Ticker */}
        <div className="h-10 bg-slate-950 border-t border-slate-900 flex items-center px-6 gap-6 overflow-hidden shrink-0 relative">
          <div className="absolute inset-y-0 left-0 w-20 bg-gradient-to-r from-slate-950 to-transparent z-10" />
          <div className="absolute inset-y-0 right-0 w-20 bg-gradient-to-l from-slate-950 to-transparent z-10" />

          <span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.3em] shrink-0 z-20">Production_Pulse</span>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-16 animate-marquee py-1">
              {logs.length > 0 ? logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-500 uppercase tracking-tight flex gap-3 items-center">
                  <span className="w-1 h-1 rounded-full bg-blue-500/30" /> {log}
                </span>
              )) : (
                <span className="text-[9px] font-bold text-slate-700 uppercase italic opacity-40">System scanning production nodes...</span>
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #334155; }

        .animate-marquee { display: flex; animation: marquee 60s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 12px;
          height: 12px;
          background: currentColor;
          border-radius: 50%;
          border: 2px solid #fff;
          cursor: pointer;
          box-shadow: 0 0 8px rgba(0,0,0,0.5);
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Truck,
  Gauge,
  Cpu,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  Layers,
  ShieldAlert,
  Target,
  ZoomIn,
  ZoomOut,
  ChevronRight,
  MonitorDot,
  TrendingUp,
  Settings2,
  ActivitySquare,
  Search,
  Filter,
  Lock,
  Unlock,
  Key,
  Zap
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);
  const [hoveredVehicleId, setHoveredVehicleId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 60;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      const finalScale = Math.max(0.15, s);
      setScale(finalScale);
      setManualScale(finalScale);
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: COLORS.VEHICLE,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      addLog(`MANUAL RELEASE: UNIT ${v.id.toUpperCase()}`);
    }
  };

  const unlockAll = () => {
    const lockedCount = vehiclesRef.current.filter(v => v.isLocked).length;
    if (lockedCount > 0) {
      vehiclesRef.current.forEach(v => v.isLocked = false);
      addLog(`BATCH RELEASE: ${lockedCount} UNITS`);
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`UNIT ${v.id.toUpperCase()} FINISHED [${passedFtt ? 'FTR' : 'REWORK'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === 22 && !v.inRepair) {
           v.isLocked = true;
           addLog(`GATE HOLD: UNIT ${v.id.toUpperCase()}`);
        }

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           v.targetPath = [...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), ...ROLL_TEST_BRANCHES[bestLaneIdx].slice(1), ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true; 
            const stages = Math.random() < 0.4 ? 2 : 1;
            v.pendingRepairs = stages; 
            v.initialRepairs = stages;
            v.completedRepairs = 0;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`REWORK START: ${v.id.toUpperCase()} [${stages} STAGES]`);
          }
          if (v.inRepair && (station.name === 'FUNILARIA' || station.name === 'FCPA')) {
            if (v.pendingRepairs > 0) {
              v.pendingRepairs--;
              v.completedRepairs++;
              setStats(s => ({ ...s, totalStagesCompleted: s.totalStagesCompleted + 1 }));
            }
          }
          if (v.inRepair && station.name === 'ÁREA BRANCA') { v.inRepair = false; v.isRepaired = true; v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; v.color = COLORS.VEHICLE; }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 && mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 22));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#330a0a', 22);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 38;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let ledColor = '#334155'; switch(status) { case 'PROCESSING': ledColor = '#10b981'; break; case 'OCCUPIED': ledColor = '#fbbf24'; break; case 'BLOCKED': ledColor = '#ef4444'; break; }
      const isHovered = hoveredStationId === s.id;

      if (isHovered) {
        ctx.shadowBlur = 15; ctx.shadowColor = 'rgba(59, 130, 246, 0.5)';
      }

      ctx.strokeStyle = isHovered ? '#3b82f6' : 'rgba(255,255,255,0.08)'; ctx.lineWidth = isHovered ? 2 : 1;
      ctx.fillStyle = 'rgba(15, 23, 42, 0.85)'; ctx.beginPath(); ctx.roundRect(x, y, w, h, 3); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(x + 10, y + 10, 3.5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 18, y + 13);
      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.fillRect(x + 5, y + h - 6, w - 10, 2);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 5, y + h - 6, (w - 10) * prog, 2);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isHoveredV = hoveredVehicleId === v.id;
      if (isHoveredV) {
        ctx.shadowBlur = 12; ctx.shadowColor = 'white';
      } else {
        ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.4)';
      }

      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 3); ctx.fill();

      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = 'white'; ctx.font = 'bold 7px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(`${v.completedRepairs}/${v.initialRepairs}`, 0, 2);
        else if (v.isLocked) {
          ctx.save(); ctx.rotate(-v.rotation);
          ctx.fillStyle = '#fbbf24';
          ctx.beginPath(); ctx.arc(0, -15, 4, 0, Math.PI * 2); ctx.fill();
          ctx.restore();
        }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)'; ctx.font = '800 20px Inter'; ctx.fillText('FACTORY_TWIN_V4.9', 50, 45);
  }, [hoveredStationId, hoveredVehicleId, speed]);

  useEffect(() => {
    let frameId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } frameId = requestAnimationFrame(loop); };
    frameId = requestAnimationFrame(loop); return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) { mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale }; }
  };

  const ftrRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const fttRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;
  const repairEfficiency = stats.repairAttempts > 0 ? (stats.totalRepaired / stats.repairAttempts) * 100 : 0;

  const allProductionStations = useMemo(() => {
    return [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
  }, []);

  const stationMonitorData = useMemo(() => {
    return allProductionStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, type: s.type };
    });
  }, [vehiclesRef.current, allProductionStations]);

  const statusBreakdown = useMemo(() => {
    const counts = { IDLE: 0, PROCESSING: 0, OCCUPIED: 0, BLOCKED: 0 };
    stationMonitorData.forEach(s => counts[s.status]++);
    return counts;
  }, [stationMonitorData]);

  const filteredStations = useMemo(() => {
    return stationMonitorData.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.status.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stationMonitorData, searchTerm]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);
  const lockedVehicles = useMemo(() => vehiclesRef.current.filter(v => v.isLocked), [vehiclesRef.current]);

  const ecatTelemetry = useMemo(() => {
    // Dynamic Roller Test Speed Simulation
    const isRollerProcessing = stationMonitorData.some(s => s.name.startsWith('Teste Rolo') && s.status === 'PROCESSING');
    const rollerSpeed = isRollerProcessing ? Math.floor(Math.random() * 20 + 75) : 0; // Simulate 75-95 km/h during test

    // Electrical Testing Telemetry
    const isElecProcessing = stationMonitorData.some(s => s.name === 'Reparo Elétrico' && s.status === 'PROCESSING');
    const elecVoltage = isElecProcessing ? (12.4 + Math.random() * 0.4).toFixed(2) : "0.00";
    const elecCurrent = isElecProcessing ? (15 + Math.random() * 5).toFixed(1) : "0.0";

    return [
      { id: 'e1', name: 'Fleet Controller', unit: 'SENS_L0', value: (speed * 1.15).toFixed(1), label: 'KM/H', progress: Math.min(1, stats.active / 20) },
      { id: 'e2', name: 'Roller Test Node', unit: 'ROLL_VFD', value: rollerSpeed, label: 'KM/H', progress: rollerSpeed / 100, isGauge: true },
      { id: 'e3', name: 'Electrical Test', unit: 'ECAT_DC', value: elecVoltage, label: 'V', progress: parseFloat(elecVoltage) / 14, icon: <Zap className="w-3 h-3 text-yellow-400" /> },
      { id: 'e4', name: 'ECAT Load', unit: 'AMP_01', value: elecCurrent, label: 'A', progress: parseFloat(elecCurrent) / 30 }
    ];
  }, [speed, stats.active, isRunning, inRepairCount, stationMonitorData]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
      <aside className="w-[340px] lg:w-[400px] bg-slate-950 border-r border-slate-900 flex flex-col shadow-2xl shrink-0 z-20">
        <div className="p-6 border-b border-slate-900 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20"><Cpu className="w-4 h-4 text-white" /></div>
            <h1 className="text-xs font-black tracking-[0.2em] uppercase opacity-90">Line_Ops.v4</h1>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`flex items-center gap-2 px-2.5 py-1.5 rounded-md border transition-all text-[8px] font-black uppercase tracking-wider ${isFitToScreen ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
          >
            {isFitToScreen ? <Maximize2 className="w-3 h-3" /> : <Minimize2 className="w-3 h-3" />}
            {isFitToScreen ? 'Auto-Fit' : 'Manual'}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col">
          <section className="p-6 grid grid-cols-2 gap-3 border-b border-slate-900 bg-slate-950/20 shrink-0">
            <div className="bg-slate-900/30 p-4 rounded-xl border border-slate-800/50 flex flex-col group">
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-blue-400 transition-colors">FTR Rate</span>
              <span className="text-2xl font-black text-blue-500 tabular-nums leading-none tracking-tighter">{ftrRate.toFixed(1)}%</span>
            </div>
            <div className="bg-slate-900/30 p-4 rounded-xl border border-slate-800/50 flex flex-col group">
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-emerald-400 transition-colors">FTT Yield</span>
              <span className="text-2xl font-black text-emerald-500 tabular-nums leading-none tracking-tighter">{fttRate.toFixed(1)}%</span>
            </div>
          </section>

          <section className="p-6 space-y-4 border-b border-slate-900/50 bg-amber-500/5">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-amber-500 uppercase tracking-[0.2em] flex items-center gap-2"><Lock className="w-3 h-3" /> Gate Release Queue</span>
              {lockedVehicles.length > 0 && (
                <button 
                  onClick={unlockAll}
                  className="text-[8px] font-black bg-amber-500 text-slate-950 px-2 py-1 rounded hover:bg-amber-400 transition-colors uppercase"
                >
                  Unlock All
                </button>
              )}
            </div>
            <div className="space-y-1 max-h-[150px] overflow-y-auto custom-scrollbar">
              {lockedVehicles.length > 0 ? lockedVehicles.map(v => (
                <div 
                  key={v.id} 
                  onMouseEnter={() => setHoveredVehicleId(v.id)}
                  onMouseLeave={() => setHoveredVehicleId(null)}
                  className="flex items-center justify-between bg-slate-900/60 p-2 rounded border border-amber-500/20 group hover:border-amber-500/50 transition-all"
                >
                  <div className="flex items-center gap-2">
                    <Truck className="w-3 h-3 text-slate-500" />
                    <span className="text-[10px] font-black text-slate-200">UNIT_{v.id.toUpperCase()}</span>
                  </div>
                  <button 
                    onClick={() => unlockVehicle(v.id)}
                    className="p-1.5 bg-amber-500/10 hover:bg-amber-500 text-amber-500 hover:text-slate-950 rounded transition-all"
                  >
                    <Unlock className="w-3 h-3" />
                  </button>
                </div>
              )) : (
                <div className="text-center py-4 border border-dashed border-slate-900 rounded text-[8px] font-bold text-slate-700 uppercase italic">Gate empty: all units released</div>
              )}
            </div>
          </section>

          <section className="p-6 space-y-4 border-b border-slate-900/50">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><Gauge className="w-3 h-3" /> ECAT Real-Time Telemetry</span>
              <Activity className="w-3 h-3 text-slate-700" />
            </div>
            <div className="grid grid-cols-2 gap-3">
              {ecatTelemetry.map((ecat) => (
                <div key={ecat.id} className="bg-slate-900/40 p-3 rounded-xl border border-slate-800/30 flex flex-col gap-2 relative overflow-hidden group">
                  <div className="flex justify-between items-center relative z-10">
                    <span className="text-[7px] font-black text-slate-500 uppercase tracking-tighter truncate">{ecat.name}</span>
                    <span className="text-[7px] font-mono text-blue-400/60">{ecat.unit}</span>
                  </div>
                  <div className="flex items-baseline gap-1 relative z-10">
                     <span className={`text-lg font-black tabular-nums tracking-tighter ${ecat.isGauge && ecat.value > 0 ? 'text-blue-400' : 'text-slate-200'}`}>{ecat.value}</span>
                     <span className="text-[8px] font-bold opacity-30">{ecat.label}</span>
                  </div>
                  <div className="h-1 bg-slate-900 rounded-full overflow-hidden mt-1">
                    <div className={`h-full transition-all duration-700 ease-out ${ecat.isGauge ? 'bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]' : 'bg-slate-700'}`} style={{ width: `${ecat.progress * 100}%` }} />
                  </div>
                  {ecat.icon && <div className="absolute -right-1 -bottom-1 opacity-10 group-hover:opacity-20 transition-opacity">{ecat.icon}</div>}
                </div>
              ))}
            </div>
          </section>

          <section className="p-6 space-y-6 border-b border-slate-900/50">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><MonitorDot className="w-3 h-3" /> Area Status</span>
              <span className="text-[8px] font-bold text-slate-800 tracking-widest">{stationMonitorData.length} TOTAL NODES</span>
            </div>

            <div className="grid grid-cols-4 gap-1.5">
              {[
                { label: 'Idle', count: statusBreakdown.IDLE, color: 'bg-slate-800' },
                { label: 'Proc', count: statusBreakdown.PROCESSING, color: 'bg-emerald-500' },
                { label: 'Occ', count: statusBreakdown.OCCUPIED, color: 'bg-amber-500' },
                { label: 'Blk', count: statusBreakdown.BLOCKED, color: 'bg-red-500' },
              ].map(item => (
                <div key={item.label} className="bg-slate-900/40 p-2 rounded border border-slate-900/50 flex flex-col items-center">
                  <div className={`w-1 h-1 rounded-full ${item.color} mb-1.5`} />
                  <span className="text-[7px] font-black text-slate-600 uppercase mb-1">{item.label}</span>
                  <span className="text-[11px] font-black text-slate-400">{item.count}</span>
                </div>
              ))}
            </div>

            <div className="relative group">
              <Search className="absolute left-2.5 top-2.5 w-3 h-3 text-slate-700 group-focus-within:text-blue-500 transition-colors" />
              <input 
                type="text" 
                placeholder="SEARCH NODE..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-slate-900/50 border border-slate-900 rounded-lg py-2 pl-8 pr-3 text-[8px] font-black tracking-widest text-slate-400 focus:outline-none focus:border-blue-500/50 transition-all placeholder:text-slate-800"
              />
            </div>

            <div className="space-y-1 max-h-[300px] overflow-y-auto custom-scrollbar pr-1">
              {filteredStations.length > 0 ? filteredStations.map((s) => (
                <div 
                  key={s.id} 
                  onMouseEnter={() => setHoveredStationId(s.id)}
                  onMouseLeave={() => setHoveredStationId(null)}
                  className={`group flex items-center justify-between py-1.5 px-2 rounded cursor-pointer transition-all ${hoveredStationId === s.id ? 'bg-blue-500/10 border-blue-500/20 translate-x-1' : 'hover:bg-slate-900/30 border border-transparent'}`}
                >
                  <div className="flex items-center gap-2.5 truncate">
                    <div className={`w-1.5 h-1.5 rounded-full transition-shadow duration-300 ${
                      s.status === 'IDLE' ? 'bg-slate-800' :
                      s.status === 'PROCESSING' ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.3)]' :
                      s.status === 'OCCUPIED' ? 'bg-amber-500' : 'bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.4)]'
                    }`} />
                    <span className={`text-[9px] font-bold transition-colors uppercase truncate tracking-tight ${hoveredStationId === s.id ? 'text-blue-400' : 'text-slate-500 group-hover:text-slate-300'}`}>{s.name}</span>
                  </div>
                  <span className={`text-[7px] font-black px-1.5 py-0.5 rounded tracking-tighter ${s.type === StationType.REPAIR ? 'text-red-500 bg-red-500/5 border border-red-500/10' : 'text-slate-700 bg-slate-900/40'}`}>{s.status}</span>
                </div>
              )) : (
                <div className="text-center py-4 border border-dashed border-slate-900 rounded text-[8px] font-bold text-slate-700 uppercase italic">No nodes found</div>
              )}
            </div>
          </section>
        </div>

        <div className="p-6 border-t border-slate-900 space-y-5 shrink-0 bg-slate-950">
          <div className="space-y-3">
             <div className="flex justify-between items-center text-[8px] font-black text-slate-600 uppercase tracking-widest">
                <span className="flex items-center gap-1.5"><Maximize2 className="w-2.5 h-2.5" /> Viewport Dimensioning</span>
                <span className="text-blue-500">{Math.round(scale * 100)}%</span>
             </div>
             <div className="flex items-center gap-3">
               <ZoomOut className="w-3 h-3 text-slate-700" />
               <input 
                 type="range" min="0.15" max="1.5" step="0.01" 
                 value={manualScale} disabled={isFitToScreen}
                 onChange={(e) => setManualScale(parseFloat(e.target.value))} 
                 className={`flex-1 h-1 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-blue-600 cursor-pointer'}`} 
               />
               <ZoomIn className="w-3 h-3 text-slate-700" />
             </div>
          </div>

          <div className="grid grid-cols-2 gap-2">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2 py-3 rounded-lg font-black text-[9px] uppercase border transition-all active:scale-95 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20' : 'bg-blue-600 text-white border-blue-400/30'}`}>
              {isRunning ? <Pause className="w-3 h-3" /> : <Play className="w-3 h-3" />}
              {isRunning ? 'Line Halt' : 'Line Init'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("PRODUCTION RESET."); }} className="flex items-center justify-center gap-2 py-3 bg-slate-900 text-slate-500 rounded-lg border border-slate-800 font-black text-[9px] uppercase hover:text-white transition-colors active:scale-95">
              <RotateCcw className="w-3 h-3" /> Reset
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div 
            style={{ 
              width: SIM_WIDTH, height: SIM_HEIGHT, 
              transform: `scale(${scale})`, transformOrigin: 'center',
              transition: isFitToScreen ? 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' 
            }}
            className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0"
          >
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} className="cursor-crosshair" />
          </div>
        </div>

        <div className="h-10 bg-slate-950 border-t border-slate-900 flex items-center px-6 gap-6 overflow-hidden shrink-0 relative">
          <div className="absolute inset-y-0 left-0 w-20 bg-gradient-to-r from-slate-950 to-transparent z-10" />
          <div className="absolute inset-y-0 right-0 w-20 bg-gradient-to-l from-slate-950 to-transparent z-10" />

          <span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.3em] shrink-0 z-20">Production_Pulse</span>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-16 animate-marquee py-1">
              {logs.length > 0 ? logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-500 uppercase tracking-tight flex gap-3 items-center">
                  <span className="w-1 h-1 rounded-full bg-blue-500/30" /> {log}
                </span>
              )) : (
                <span className="text-[9px] font-bold text-slate-700 uppercase italic opacity-40">System scanning production nodes...</span>
              )}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #334155; }

        .animate-marquee { display: flex; animation: marquee 60s linear infinite; }
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }

        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 12px;
          height: 12px;
          background: currentColor;
          border-radius: 50%;
          border: 2px solid #fff;
          cursor: pointer;
          box-shadow: 0 0 8px rgba(0,0,0,0.5);
        }
      `}</style>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  baseColor: string; // Original color assigned at Body Shop
  finished: boolean;
  progress: number;
  // Added for tracking and unblocking
  everRepaired: boolean;
  ignoreCollisionTimer: number;
  pendingRepairs: number; // Number of repair stages needed
  completedRepairs: number; // Number of repair stages finished
  initialRepairs: number; // Total stages assigned at QC
  isLocked: boolean; // Manual release gate
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  // Added industrial metrics
  totalStarted: number;
  passedFirstTime: number;
  totalRepaired: number;
  repairAttempts: number; // Total units sent to repair
  totalStagesCompleted: number; // Global count of repair tasks done
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Truck,
  Gauge,
  Cpu,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  Clock,
  Layers,
  ShieldAlert,
  Target,
  ZoomIn,
  ZoomOut,
  ChevronRight,
  MonitorDot,
  TrendingUp,
  Settings2,
  ActivitySquare,
  Search,
  Filter,
  Lock,
  Unlock,
  Key,
  Zap
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, Station, StationType } from './types';

// Top-down car image as a data URL
const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed, setSpeed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);
  const [hoveredVehicleId, setHoveredVehicleId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const animOffsetRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 60;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      const finalScale = Math.max(0.15, s);
      setScale(finalScale);
      setManualScale(finalScale);
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      addLog(`MANUAL RELEASE: UNIT ${v.id.toUpperCase()}`);
    }
  };

  const unlockAll = () => {
    const lockedCount = vehiclesRef.current.filter(v => v.isLocked).length;
    if (lockedCount > 0) {
      vehiclesRef.current.forEach(v => v.isLocked = false);
      addLog(`BATCH RELEASE: ${lockedCount} UNITS`);
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    animOffsetRef.current = (animOffsetRef.current + speed) % 40;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`UNIT ${v.id.toUpperCase()} FINISHED [${passedFtt ? 'FTR' : 'REWORK'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === 22 && !v.inRepair) {
           v.isLocked = true;
           addLog(`GATE HOLD: UNIT ${v.id.toUpperCase()}`);
        }

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           v.targetPath = [...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), ...ROLL_TEST_BRANCHES[bestLaneIdx].slice(1), ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true; 
            const stages = Math.random() < 0.4 ? 2 : 1;
            v.pendingRepairs = stages; 
            v.initialRepairs = stages;
            v.completedRepairs = 0;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`REWORK START: ${v.id.toUpperCase()} [${stages} STAGES]`);
          }
          if (v.inRepair && (station.name === 'FUNILARIA' || station.name === 'FCPA')) {
            if (v.pendingRepairs > 0) {
              v.pendingRepairs--;
              v.completedRepairs++;
              setStats(s => ({ ...s, totalStagesCompleted: s.totalStagesCompleted + 1 }));
            }
          }
          if (v.inRepair && station.name === 'ÁREA BRANCA') { 
            v.inRepair = false; 
            v.isRepaired = true; 
            v.targetPath = [...MAIN_PATH_POINTS]; 
            v.pathIdx = 18; 
            v.color = v.baseColor; // Restore random unique color
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 && mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 22));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#330a0a', 22);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 38;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const vehicleAtStation = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      if (vehicleAtStation) {
        if (vehicleAtStation.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = vehicleAtStation.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === vehicleAtStation.id) return false;
            const onSamePath = (other.inRepair === vehicleAtStation.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - vehicleAtStation.pos.x, 2) + Math.pow(other.pos.y - vehicleAtStation.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= vehicleAtStation.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let ledColor = '#334155'; switch(status) { case 'PROCESSING': ledColor = '#10b981'; break; case 'OCCUPIED': ledColor = '#fbbf24'; break; case 'BLOCKED': ledColor = '#ef4444'; break; }
      const isHovered = hoveredStationId === s.id;

      if (isHovered) {
        ctx.shadowBlur = 15; ctx.shadowColor = 'rgba(59, 130, 246, 0.5)';
      }

      ctx.strokeStyle = isHovered ? '#3b82f6' : 'rgba(255,255,255,0.08)'; ctx.lineWidth = isHovered ? 2 : 1;
      ctx.fillStyle = 'rgba(15, 23, 42, 0.85)'; ctx.beginPath(); ctx.roundRect(x, y, w, h, 3); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(x + 10, y + 10, 3.5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 18, y + 13);
      if (status === 'PROCESSING' && vehicleAtStation) {
        const prog = 1 - (vehicleAtStation.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.fillRect(x + 5, y + h - 6, w - 10, 2);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 5, y + h - 6, (w - 10) * prog, 2);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      const isHoveredV = hoveredVehicleId === v.id;
      if (isHoveredV) {
        ctx.shadowBlur = 12; ctx.shadowColor = 'white';
      } else {
        ctx.shadowBlur = 4; ctx.shadowColor = 'rgba(0,0,0,0.4)';
      }

      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 3); ctx.fill();

      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = 'white'; ctx.font = 'bold 7px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(`${v.completedRepairs}/${v.initialRepairs}`, 0, 2);
        else if (v.isLocked) {
          ctx.save(); ctx.rotate(-v.rotation);
          ctx.fillStyle = '#fbbf24';
          ctx.beginPath(); ctx.arc(0, -15, 4, 0, Math.PI * 2); ctx.fill();
          ctx.restore();
        }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)'; ctx.font = '800 20px Inter'; ctx.fillText('FACTORY_TWIN_V4.9', 50, 45);
  }, [hoveredStationId, hoveredVehicleId, speed]);

  useEffect(() => {
    let frameId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } frameId = requestAnimationFrame(loop); };
    frameId = requestAnimationFrame(loop); return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) { mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale }; }
  };

  const ftrRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const fttRate = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;
  const repairEfficiency = stats.repairAttempts > 0 ? (stats.totalRepaired / stats.repairAttempts) * 100 : 0;

  const allProductionStations = useMemo(() => {
    return [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
  }, []);

  const stationMonitorData = useMemo(() => {
    return allProductionStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, type: s.type };
    });
  }, [vehiclesRef.current, allProductionStations]);

  const statusBreakdown = useMemo(() => {
    const counts = { IDLE: 0, PROCESSING: 0, OCCUPIED: 0, BLOCKED: 0 };
    stationMonitorData.forEach(s => counts[s.status]++);
    return counts;
  }, [stationMonitorData]);

  const filteredStations = useMemo(() => {
    return stationMonitorData.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.status.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stationMonitorData, searchTerm]);

  const inRepairCount = useMemo(() => vehiclesRef.current.filter(v => v.inRepair).length, [vehiclesRef.current]);
  const lockedVehicles = useMemo(() => vehiclesRef.current.filter(v => v.isLocked), [vehiclesRef.current]);

  const ecatTelemetry = useMemo(() => {
    // Dynamic Roller Test Speed Simulation
    const isRollerProcessing = stationMonitorData.some(s => s.name.startsWith('Teste Rolo') && s.status === 'PROCESSING');
    const rollerSpeed = isRollerProcessing ? Math.floor(Math.random() * 20 + 75) : 0; // Simulate 75-95 km/h during test

    // Electrical Testing Telemetry
    const isElecProcessing = stationMonitorData.some(s => s.name === 'Reparo Elétrico' && s.status === 'PROCESSING');
    const elecVoltage = isElecProcessing ? (12.4 + Math.random() * 0.4).toFixed(2) : "0.00";
    const elecCurrent = isElecProcessing ? (15 + Math.random() * 5).toFixed(1) : "0.0";

    return [
      { id: 'e1', name: 'Fleet Controller', unit: 'SENS_L0', value: (speed * 1.15).toFixed(1), label: 'KM/H', progress: Math.min(1, stats.active / 20) },
      { id: 'e2', name: 'Roller Test Node', unit: 'ROLL_VFD', value: rollerSpeed, label: 'KM/H', progress: rollerSpeed / 100, isGauge: true },
      { id: 'e3', name: 'Electrical Test', unit: 'ECAT_DC', value: elecVoltage, label: 'V', progress: parseFloat(elecVoltage) / 14, icon: <Zap className="w-3 h-3 text-yellow-400" /> },
      { id: 'e4', name: 'ECAT Load', unit: 'AMP_01', value: elecCurrent, label: 'A', progress: parseFloat(elecCurrent) / 30 }
    ];
  }, [speed, stats.active, isRunning, inRepairCount, stationMonitorData]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
      <aside className="w-[340px] lg:w-[400px] bg-slate-950 border-r border-slate-900 flex flex-col shadow-2xl shrink-0 z-20">
        <div className="p-6 border-b border-slate-900 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-3">
            <div className="p-1.5 bg-blue-600 rounded-lg shadow-lg shadow-blue-900/20"><Cpu className="w-4 h-4 text-white" /></div>
            <h1 className="text-xs font-black tracking-[0.2em] uppercase opacity-90">Line_Ops.v4</h1>
          </div>
          <button 
            onClick={() => setIsFitToScreen(!isFitToScreen)}
            className={`flex items-center gap-2 px-2.5 py-1.5 rounded-md border transition-all text-[8px] font-black uppercase tracking-wider ${isFitToScreen ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'}`}
          >
            {isFitToScreen ? <Maximize2 className="w-3 h-3" /> : <Minimize2 className="w-3 h-3" />}
            {isFitToScreen ? 'Auto-Fit' : 'Manual'}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col">
          <section className="p-6 grid grid-cols-2 gap-3 border-b border-slate-900 bg-slate-950/20 shrink-0">
            <div className="bg-slate-900/30 p-4 rounded-xl border border-slate-800/50 flex flex-col group">
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-blue-400 transition-colors">FTR Rate</span>
              <span className="text-2xl font-black text-blue-500 tabular-nums leading-none tracking-tighter">{ftrRate.toFixed(1)}%</span>
            </div>
            <div className="bg-slate-900/30 p-4 rounded-xl border border-slate-800/50 flex flex-col group">
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 group-hover:text-emerald-400 transition-colors">FTT Yield</span>
              <span className="text-2xl font-black text-emerald-500 tabular-nums leading-none tracking-tighter">{fttRate.toFixed(1)}%</span>
            </div>
          </section>

          <section className="p-6 space-y-4 border-b border-slate-900/50 bg-amber-500/5">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-black text-amber-500 uppercase tracking-[0.2em] flex items-center gap-2"><Lock className="w-3 h-3" /> Gate Release Queue</span>
              {lockedVehicles.length > 0 && (
                <button 
                  onClick={unlockAll}
                  className="text-[8px] font-black bg-amber-500 text-slate-950 px-2 py-1 rounded hover:bg-amber-400 transition-colors uppercase"
