                  <div className="h-1 bg-slate-900 rounded-full overflow-hidden mt-1">
                    <div className={`h-full transition-all duration-700 ease-out ${ecat.isGauge ? 'bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]' : 'bg-slate-700'}`} style={{ width: `${ecat.progress * 100}%` }} />
                  </div>
                  {ecat.icon && <div className="absolute -right-1 -bottom-1 opacity-10 group-hover:opacity-20 transition-opacity">{ecat.icon}</div>}
