                 onChange={(e) => setManualScale(parseFloat(e.target.value))} 
                 className={`flex-1 h-1 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-blue-600 cursor-pointer'}`} 
               />
