                {lockedVehiclesCount > 0 && (
                  <button onClick={unlockAll} className="px-4 bg-amber-500 text-slate-950 rounded-xl font-black text-[9px] uppercase hover:bg-amber-400 transition-all shadow-lg shadow-amber-900/20 flex items-center gap-2">
                    <Unlock className="w-4 h-4" /> ({lockedVehiclesCount})
