                    <div className="flex items-end justify-between relative z-10 mb-4">
                       <div className="flex items-baseline gap-1.5">
                          <span className="text-4xl font-black tabular-nums tracking-tighter text-white leading-none">{ecat.value}</span>
                          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{ecat.label}</span>
                       </div>
                       <div className="flex items-center gap-2 text-[8px] font-black text-emerald-500 uppercase tracking-widest"><TrendingUp className="w-3 h-3" /> Stream OK</div>
                    </div>
                    <div className="space-y-2 relative z-10">
                       <div className="w-full h-1.5 bg-slate-950 rounded-full overflow-hidden">
                          <div className={`h-full transition-all duration-700 ease-out shadow-[0_0_12px_rgba(99,102,241,0.3)] ${colorClasses[ecat.color]}`} style={{ width: `${ecat.progress * 100}%` }} />
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
          {activeTab === 'QUALITY' && (
            <div className="p-6 space-y-6 overflow-y-auto">
              <div className="flex items-center justify-between">
                <span className="text-[10px] font-black text-rose-400 uppercase tracking-widest flex items-center gap-2"><ShieldAlert className="w-4 h-4" /> Rework Queue</span>
                <span className="text-[8px] font-black text-slate-600 uppercase bg-slate-900 px-2 py-1 rounded border border-slate-800 tracking-widest">{inRepairCount} Active</span>
              </div>
              <div className="space-y-2">
                {vehiclesRef.current.filter(v => v.inRepair).map(v => (
                  <div key={v.id} onMouseEnter={() => setHoveredVehicleId(v.id)} onMouseLeave={() => setHoveredVehicleId(null)} className="flex items-center justify-between bg-slate-900/40 border border-slate-800/50 p-4 rounded-2xl group hover:border-rose-500/30 transition-all">
                    <div className="flex items-center gap-3">
                       <div className="w-8 h-4 rounded-sm border border-rose-900" style={{ backgroundColor: v.color }} />
                       <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-200">UNIT_{v.id.toUpperCase()}</span>
                          <span className="text-[7px] font-bold text-slate-600 uppercase tracking-widest">Stage {v.completedRepairs + 1}/{v.initialRepairs}</span>
                       </div>
                    </div>
                    <button onClick={() => unlockVehicle(v.id)} className="p-2 bg-slate-800 text-slate-500 hover:text-rose-400 hover:bg-slate-700 rounded-lg transition-all"><FastForward className="w-3.5 h-3.5" /></button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="p-6 border-t border-slate-900 space-y-5 shrink-0 bg-slate-950">
          <div className="space-y-3">
             <div className="flex justify-between items-center text-[8px] font-black text-slate-600 uppercase tracking-widest">
                <span className="flex items-center gap-1.5"><Maximize2 className="w-2.5 h-2.5" /> Viewport Control</span>
                <span className="text-indigo-500">{Math.round(scale * 100)}%</span>
             </div>
             <div className="flex items-center gap-3 px-1">
               <ZoomOut className="w-3.5 h-3.5 text-slate-700" />
               <input type="range" min="0.15" max="1.5" step="0.01" value={manualScale} disabled={isFitToScreen} onChange={(e) => setManualScale(parseFloat(e.target.value))} className={`flex-1 h-1.5 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-indigo-600 cursor-pointer'}`} />
               <ZoomIn className="w-3.5 h-3.5 text-slate-700" />
             </div>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2 py-3 rounded-xl font-black text-[9px] uppercase border-2 transition-all active:scale-95 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20' : 'bg-indigo-600 text-white border-indigo-400/30 shadow-lg shadow-indigo-900/40'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />}
              {isRunning ? 'Line Halt' : 'Line Start'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setStats(s => ({ ...s, produced: 0, defects: 0 })); addLog("PRODUCTION RESET."); }} className="flex items-center justify-center gap-2 py-3 bg-slate-900 text-slate-500 rounded-xl border border-slate-800 font-black text-[9px] uppercase hover:text-white transition-colors active:scale-95">
              <RotateCcw className="w-4 h-4" /> Reset
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} className="cursor-crosshair" />
          </div>
        </div>
        <div className="h-12 bg-slate-950 border-t border-slate-900 flex items-center px-6 gap-6 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-2 shrink-0 z-20 text-indigo-500"><Terminal className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.3em]">Log_Buffer</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-20 animate-marquee py-1">
              {logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-500 uppercase tracking-tight flex gap-3 items-center">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500/30" /> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Truck,
  Gauge,
  Cpu,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  ShieldAlert,
  ZoomIn,
  ZoomOut,
  MonitorDot,
  TrendingUp,
  Settings2,
  Search,
  Zap,
  FastForward,
  Boxes,
  Microchip,
  FlaskConical,
  PackageCheck,
  AlertTriangle,
  Terminal,
  Command,
  Unlock,
  TrafficLight
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, StationType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'TELEMETRY' | 'QUALITY';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('NODES');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);
  const [hoveredVehicleId, setHoveredVehicleId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 60;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      const finalScale = Math.max(0.15, s);
      setScale(finalScale);
      setManualScale(finalScale);
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 120; // Extended grace to clear congestion
      addLog(`COMMAND: RELEASE/OVERRIDE UNIT ${v.id.toUpperCase()}`);
    }
  };

  const unlockAll = () => {
    const lockedCount = vehiclesRef.current.filter(v => v.isLocked).length;
    if (lockedCount > 0) {
      vehiclesRef.current.forEach(v => {
        if(v.isLocked) {
           v.isLocked = false;
           v.waitingTimer = 0;
           v.ignoreCollisionTimer = 120;
        }
      });
      addLog(`GLOBAL OVERRIDE: ${lockedCount} UNITS RELEASED`);
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`UNIT ${v.id.toUpperCase()} SHIPPED [${passedFtt ? 'FTT' : 'REPAIR'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === 22 && !v.inRepair) {
           v.isLocked = true;
           addLog(`GATE HOLD: UNIT ${v.id.toUpperCase()}`);
        }

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           v.targetPath = [...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), ...ROLL_TEST_BRANCHES[bestLaneIdx].slice(1), ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true; 
            const stages = Math.random() < 0.4 ? 2 : 1;
            v.pendingRepairs = stages; 
            v.initialRepairs = stages;
            v.completedRepairs = 0;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`FAI QC: DEFECT DETECTED ON ${v.id.toUpperCase()}`);
          }
          if (v.inRepair && (station.name === 'FUNILARIA' || station.name === 'FCPA')) {
            if (v.pendingRepairs > 0) {
              v.pendingRepairs--;
              v.completedRepairs++;
              setStats(s => ({ ...s, totalStagesCompleted: s.totalStagesCompleted + 1 }));
            }
          }
          if (v.inRepair && station.name === 'ÁREA BRANCA') { 
            v.inRepair = false; 
            v.isRepaired = true; 
            v.targetPath = [...MAIN_PATH_POINTS]; 
            v.pathIdx = 18; 
            v.color = v.baseColor; 
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 && mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 22));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#330a0a', 22);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 38;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 10 && Math.abs(veh.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let ledColor = '#334155';
      if (status === 'PROCESSING') ledColor = '#10b981';
      else if (status === 'OCCUPIED') ledColor = '#fbbf24';
      else if (status === 'BLOCKED') ledColor = '#ef4444';

      const isHovered = hoveredStationId === s.id;
      if (isHovered) { ctx.shadowBlur = 15; ctx.shadowColor = 'rgba(99, 102, 241, 0.5)'; }

      ctx.strokeStyle = isHovered ? '#6366f1' : 'rgba(255,255,255,0.08)'; 
      ctx.lineWidth = isHovered ? 2 : 1;
      ctx.fillStyle = 'rgba(15, 23, 42, 0.85)'; 
      ctx.beginPath(); 
      ctx.roundRect(x, y, w, h, 3); 
      ctx.fill(); 
      ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(x + 10, y + 10, 3.5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 18, y + 13);

      if (status === 'PROCESSING' && v) {
        const prog = 1 - (v.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.fillRect(x + 5, y + h - 6, w - 10, 2);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 5, y + h - 6, (w - 10) * prog, 2);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      const isHoveredV = hoveredVehicleId === v.id;
      ctx.shadowBlur = isHoveredV ? 12 : 4; 
      ctx.shadowColor = isHoveredV ? 'white' : 'rgba(0,0,0,0.4)';
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; 
      ctx.fillStyle = v.color; 
      ctx.beginPath(); 
      ctx.roundRect(-18, -9, 36, 18, 3); 
      ctx.fill();

      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = 'white'; ctx.font = 'bold 7px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(`${v.completedRepairs}/${v.initialRepairs}`, 0, 2);
        else if (v.isLocked) {
          ctx.save(); ctx.rotate(-v.rotation);
          ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(0, -15, 4, 0, Math.PI * 2); ctx.fill();
          ctx.restore();
        }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)'; ctx.font = '800 24px Inter'; ctx.fillText('FACTORY_TWIN_V4.9', 50, 45);
  }, [hoveredStationId, hoveredVehicleId, speed]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) { mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale }; }
  };

  const ftrRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const fttYield = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  const allProductionStations = useMemo(() => {
    return [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
  }, []);

  // Dependencies: vehiclesRef changes don't trigger re-renders, so we rely on `stats.active` or `stats` updates
  const stationMonitorData = useMemo(() => {
    return allProductionStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 10 && Math.abs(veh.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      let waitProgress = 0;
      let occupantId: string | null = null;
      let isOccupantLocked = false;

      if (v) {
        occupantId = v.id;
        isOccupantLocked = v.isLocked;
        if (v.waitingTimer > 0) {
          status = 'PROCESSING';
          waitProgress = 1 - (v.waitingTimer / s.wait);
        } else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, type: s.type, occupantId, waitProgress, isOccupantLocked };
    });
  }, [allProductionStations, stats.active]); // Re-calculate when vehicle positions update

  const statusBreakdown = useMemo(() => {
    const counts = { IDLE: 0, PROCESSING: 0, OCCUPIED: 0, BLOCKED: 0 };
    stationMonitorData.forEach(s => counts[s.status]++);
    return counts;
  }, [stationMonitorData]);

  const filteredStations = useMemo(() => {
    return stationMonitorData.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.status.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stationMonitorData, searchTerm]);

  // Derived counts for alerts
  const inRepairCount = vehiclesRef.current.filter(v => v.inRepair).length;
  const lockedVehicles = vehiclesRef.current.filter(v => v.isLocked);
  const blockedVehicles = stationMonitorData.filter(s => s.status === 'BLOCKED');

  const ecatTelemetry = useMemo(() => {
    const isRollerProcessing = stationMonitorData.some(s => s.name.startsWith('Teste Rolo') && s.status === 'PROCESSING');
    const rollerSpeed = isRollerProcessing ? Math.floor(Math.random() * 20 + 75) : 0; 
    const isElecProcessing = stationMonitorData.some(s => s.name === 'Reparo Elétrico' && s.status === 'PROCESSING');
    const elecVoltage = isElecProcessing ? (12.4 + Math.random() * 0.4).toFixed(2) : "0.00";
    const elecCurrent = isElecProcessing ? (15 + Math.random() * 5).toFixed(1) : "0.0";

    return [
      { id: 'e1', name: 'Fleet Speed', unit: 'SENS_L0', value: (speed * 1.15).toFixed(1), label: 'KM/H', progress: Math.min(1, stats.active / 20), color: 'emerald' },
      { id: 'e2', name: 'Roller Torque', unit: 'ROLL_VFD', value: rollerSpeed, label: 'KM/H', progress: rollerSpeed / 100, isGauge: true, color: 'blue' },
      { id: 'e3', name: 'System Bus', unit: 'ECAT_DC', value: elecVoltage, label: 'V', progress: parseFloat(elecVoltage) / 14, icon: <Zap className="w-3 h-3 text-yellow-400" />, color: 'amber' },
      { id: 'e4', name: 'Line Load', unit: 'AMP_01', value: elecCurrent, label: 'A', progress: parseFloat(elecCurrent) / 30, color: 'rose' }
    ];
  }, [speed, stats.active, stationMonitorData]);

  const getStationIcon = (type: StationType) => {
    switch(type) {
      case StationType.STORAGE: return <Boxes className="w-4 h-4" />;
      case StationType.ASSEMBLY: return <Microchip className="w-4 h-4" />;
      case StationType.MGR: return <Settings2 className="w-4 h-4" />;
      case StationType.TEST: return <FlaskConical className="w-4 h-4" />;
      case StationType.QUALITY: return <ShieldAlert className="w-4 h-4" />;
      case StationType.REPAIR: return <Wrench className="w-4 h-4" />;
      case StationType.SHIPPING: return <PackageCheck className="w-4 h-4" />;
      default: return <Activity className="w-4 h-4" />;
    }
  };

  const colorClasses: Record<string, string> = {
    emerald: 'bg-emerald-500',
    blue: 'bg-indigo-500',
    amber: 'bg-amber-500',
    rose: 'bg-rose-500'
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
      <aside className="w-[360px] lg:w-[420px] bg-slate-950 border-r border-slate-900 flex flex-col shadow-2xl shrink-0 z-20">

        {/* BRANDING */}
        <div className="p-6 border-b border-slate-900 shrink-0 space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="p-1.5 bg-indigo-600 rounded-lg shadow-lg shadow-indigo-900/30"><Cpu className="w-4 h-4 text-white" /></div>
              <h1 className="text-[10px] font-black tracking-[0.3em] uppercase text-indigo-400">FACTORY_OS v4.9</h1>
            </div>
            <div className={`flex items-center gap-1.5 px-2 py-1 rounded-full border text-[8px] font-black uppercase ${isRunning ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : 'bg-rose-500/10 border-rose-500/30 text-rose-400 animate-pulse'}`}>
              <div className={`w-1 h-1 rounded-full ${isRunning ? 'bg-emerald-400' : 'bg-rose-400'}`} />
              {isRunning ? 'System Online' : 'System Halted'}
            </div>
          </div>
          <div className="grid grid-cols-3 gap-2">
             <div className="bg-slate-900/50 p-2.5 rounded-xl border border-slate-800/50 flex flex-col">
                <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest mb-1">FTT Yield</span>
                <span className="text-sm font-black text-indigo-400 tabular-nums">{fttYield.toFixed(1)}%</span>
             </div>
             <div className="bg-slate-900/50 p-2.5 rounded-xl border border-slate-800/50 flex flex-col">
                <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest mb-1">Output</span>
                <span className="text-sm font-black text-white tabular-nums">{stats.produced}</span>
             </div>
             <div className="bg-slate-900/50 p-2.5 rounded-xl border border-slate-800/50 flex flex-col">
                <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest mb-1">Active</span>
                <span className="text-sm font-black text-amber-500 tabular-nums">{stats.active}</span>
             </div>
          </div>
        </div>

        {/* NAVIGATION */}
        <div className="flex border-b border-slate-900 bg-slate-950 px-4 shrink-0">
          {[
            { id: 'NODES', label: 'Monitoring', icon: <MonitorDot className="w-3.5 h-3.5" /> },
            { id: 'TELEMETRY', label: 'ECAT Sync', icon: <Gauge className="w-3.5 h-3.5" /> },
            { id: 'QUALITY', label: 'Rework', icon: <Wrench className="w-3.5 h-3.5" /> }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as DashboardTab)} className={`flex-1 flex items-center justify-center gap-2 py-3.5 text-[9px] font-black uppercase tracking-wider transition-all relative ${activeTab === tab.id ? 'text-indigo-400' : 'text-slate-600 hover:text-slate-400'}`}>
              {tab.icon} {tab.label}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.5)]" />}
            </button>
          ))}
        </div>

        {/* SCROLLABLE DASHBOARD AREA */}
        <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col">

          {/* MONITORING TAB */}
          {activeTab === 'NODES' && (
            <div className="p-4 space-y-6 flex-1 flex flex-col min-h-0">

              {/* SYSTEM ALERTS - VEHICLES STOPPED */}
              {(lockedVehicles.length > 0 || blockedVehicles.length > 0) && (
                <div className="space-y-2 animate-in fade-in slide-in-from-top-2 duration-500">
                  <div className="flex items-center justify-between px-1">
                    <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest flex items-center gap-2">
                       <AlertTriangle className="w-3.5 h-3.5" /> System Alerts
                    </span>
                    <button onClick={unlockAll} className="text-[8px] font-black text-amber-500 hover:text-amber-400 uppercase tracking-tighter transition-colors">
                      Release All
                    </button>
                  </div>

                  <div className="flex flex-col gap-2">
                    {lockedVehicles.map(v => (
                      <div key={v.id} className="bg-amber-500/10 border border-amber-500/30 rounded-xl p-3 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                           <Lock className="w-3.5 h-3.5 text-amber-500" />
                           <div className="flex flex-col">
                              <span className="text-[9px] font-black text-amber-500">UNIT_{v.id.toUpperCase()}</span>
                              <span className="text-[7px] font-bold text-slate-500 uppercase tracking-wider">LOCKED AT GATE</span>
                           </div>
                        </div>
                        <button onClick={() => unlockVehicle(v.id)} className="p-2 bg-amber-500 text-slate-950 rounded-lg hover:bg-amber-400 transition-all shadow-lg shadow-amber-900/20">
                          <Unlock className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    ))}
                    {blockedVehicles.map(s => (
                      <div key={s.id} className="bg-rose-500/10 border border-rose-500/30 rounded-xl p-3 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                           <TrafficLight className="w-3.5 h-3.5 text-rose-500 animate-pulse" />
                           <div className="flex flex-col">
                              <span className="text-[9px] font-black text-rose-500">UNIT_{s.occupantId?.toUpperCase()}</span>
                              <span className="text-[7px] font-bold text-slate-500 uppercase tracking-wider">CONGESTION @ {s.name}</span>
                           </div>
                        </div>
                        <button onClick={() => unlockVehicle(s.occupantId!)} className="p-2 bg-rose-500 text-white rounded-lg hover:bg-rose-400 transition-all shadow-lg shadow-rose-900/20">
                          <FastForward className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* SEARCH */}
              <div className="relative group shrink-0">
                <Search className="absolute left-3 top-3 w-3.5 h-3.5 text-slate-700 group-focus-within:text-indigo-500 transition-colors" />
                <input type="text" placeholder="FIND PRODUCTION NODE..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/50 border border-slate-800 rounded-xl py-2.5 pl-10 pr-3 text-[9px] font-black tracking-widest text-slate-300 focus:outline-none focus:border-indigo-500/50 transition-all placeholder:text-slate-700 uppercase" />
              </div>

              {/* NODE GRID */}
              <div className="space-y-3 pb-8">
                {filteredStations.map((s) => (
                  <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`group relative overflow-hidden flex flex-col p-4 rounded-2xl border-2 transition-all duration-300 ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/30 shadow-[0_8px_32px_rgba(0,0,0,0.4)] translate-x-1' : 'bg-slate-900/40 border-slate-900/50 hover:border-slate-800'}`}>
                    <div className="flex items-start justify-between mb-3">
                      <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-xl shadow-inner transition-all ${hoveredStationId === s.id ? 'bg-indigo-500 text-white' : 'bg-slate-800 text-slate-500'}`}>
                          {getStationIcon(s.type)}
                        </div>
                        <div className="flex flex-col">
                          <span className={`text-[10px] font-black tracking-tight uppercase leading-none ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-200'}`}>{s.name}</span>
                          <span className="text-[7px] font-bold text-slate-700 uppercase tracking-[0.2em] mt-1">{s.type} PHASE</span>
                        </div>
                      </div>
                      <div className={`flex items-center gap-2 px-2 py-1 rounded-full border text-[7px] font-black uppercase tracking-tighter ${s.status === 'IDLE' ? 'bg-slate-800/50 border-slate-700/50 text-slate-600' : s.status === 'PROCESSING' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : s.status === 'OCCUPIED' ? 'bg-amber-500/10 border-amber-500/30 text-amber-400' : 'bg-rose-500/10 border-rose-500/30 text-rose-400 animate-pulse'}`}>
                        {s.status}
                      </div>
                    </div>

                    {s.occupantId ? (
                      <div className="mt-1 space-y-3 bg-slate-950/60 rounded-xl p-3 border border-slate-800/50">
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-2">
                             <div className="w-6 h-3 rounded-sm border border-slate-700 shadow-sm" style={{ backgroundColor: vehiclesRef.current.find(v => v.id === s.occupantId)?.color }} />
                             <span className="text-[9px] font-black text-slate-400 tracking-widest">#{s.occupantId.toUpperCase()}</span>
                          </div>

                          {/* DYNAMIC OVERRIDE BUTTON */}
                          <button 
                            onClick={() => unlockVehicle(s.occupantId!)} 
                            className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[8px] font-black uppercase transition-all shadow-md active:scale-95 ${
                              s.isOccupantLocked || s.status === 'BLOCKED' 
                              ? 'bg-amber-500 text-slate-950 hover:bg-amber-400 shadow-amber-900/20' 
                              : 'bg-slate-800 text-slate-400 hover:text-indigo-400 hover:bg-slate-700'
                            }`}
                            title={s.isOccupantLocked ? "System Release" : "Force Release Process"}
                          >
                            {s.isOccupantLocked ? <Unlock className="w-3 h-3" /> : <FastForward className="w-3 h-3" />}
                            {s.isOccupantLocked ? 'Release' : 'Override'}
                          </button>
                        </div>

                        {s.status === 'PROCESSING' && (
                          <div className="space-y-1.5">
                            <div className="flex justify-between items-center text-[7px] font-black uppercase tracking-widest">
                              <span className="text-slate-600">Workcycle Progress</span>
                              <span className="text-emerald-500">{Math.round(s.waitProgress * 100)}%</span>
                            </div>
                            <div className="w-full h-1 bg-slate-900 rounded-full overflow-hidden">
                              <div className="h-full bg-gradient-to-r from-emerald-600 to-emerald-400 transition-all duration-300 shadow-[0_0_8px_rgba(16,185,129,0.4)]" style={{ width: `${s.waitProgress * 100}%` }} />
                            </div>
                          </div>
                        )}
                        {s.status === 'BLOCKED' && (
                          <div className="text-[7px] font-black text-rose-500 uppercase flex items-center gap-1.5 animate-pulse">
                            <AlertTriangle className="w-2.5 h-2.5" /> Traffic Impediment Detected
                          </div>
                        )}
                      </div>
                    ) : (
                      <div className="mt-1 flex items-center justify-center py-4 border border-dashed border-slate-800/50 rounded-xl">
                         <span className="text-[8px] font-black text-slate-800 uppercase tracking-[0.3em]">Node_Standby</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* TELEMETRY TAB */}
          {activeTab === 'TELEMETRY' && (
            <div className="p-6 space-y-8 flex-1 overflow-y-auto">
              <div className="grid grid-cols-1 gap-4">
                {ecatTelemetry.map((ecat) => (
                  <div key={ecat.id} className="bg-slate-900/40 p-5 rounded-2xl border border-slate-800/50 relative overflow-hidden group">
                    <div className="flex justify-between items-start mb-6 relative z-10">
                      <div className="flex flex-col gap-1">
                        <span className="text-[9px] font-black text-white uppercase tracking-tighter">{ecat.name}</span>
                        <span className="text-[7px] font-mono text-indigo-400/60 bg-indigo-500/5 px-2 py-0.5 rounded-full border border-indigo-500/10 w-fit">{ecat.unit}</span>
                      </div>
                      {ecat.icon ? ecat.icon : <Activity className="w-4 h-4 text-slate-700" />}
                    </div>
                    <div className="flex items-end justify-between relative z-10 mb-4">
                       <div className="flex items-baseline gap-1.5">
                          <span className="text-4xl font-black tabular-nums tracking-tighter text-white leading-none">{ecat.value}</span>
                          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{ecat.label}</span>
                       </div>
                       <div className="flex items-center gap-2 text-[8px] font-black text-emerald-500 uppercase tracking-widest"><TrendingUp className="w-3 h-3" /> Stream OK</div>
                    </div>
                    <div className="space-y-2 relative z-10">
                       <div className="w-full h-1.5 bg-slate-950 rounded-full overflow-hidden">
                          <div className={`h-full transition-all duration-700 ease-out shadow-[0_0_12px_rgba(99,102,241,0.3)] ${colorClasses[ecat.color]}`} style={{ width: `${ecat.progress * 100}%` }} />
                       </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* QUALITY TAB */}
          {activeTab === 'QUALITY' && (
            <div className="p-6 space-y-6 overflow-y-auto">
              <div className="flex items-center justify-between">
                <span className="text-[10px] font-black text-rose-400 uppercase tracking-widest flex items-center gap-2"><ShieldAlert className="w-4 h-4" /> Rework Queue</span>
                <span className="text-[8px] font-black text-slate-600 uppercase bg-slate-900 px-2 py-1 rounded border border-slate-800 tracking-widest">{inRepairCount} Active</span>
              </div>
              <div className="space-y-2">
                {vehiclesRef.current.filter(v => v.inRepair).map(v => (
                  <div key={v.id} onMouseEnter={() => setHoveredVehicleId(v.id)} onMouseLeave={() => setHoveredVehicleId(null)} className="flex items-center justify-between bg-slate-900/40 border border-slate-800/50 p-4 rounded-2xl group hover:border-rose-500/30 transition-all">
                    <div className="flex items-center gap-3">
                       <div className="w-8 h-4 rounded-sm border border-rose-900" style={{ backgroundColor: v.color }} />
                       <div className="flex flex-col">
                          <span className="text-[10px] font-black text-slate-200">UNIT_{v.id.toUpperCase()}</span>
                          <span className="text-[7px] font-bold text-slate-600 uppercase tracking-widest">Stage {v.completedRepairs + 1}/{v.initialRepairs}</span>
                       </div>
                    </div>
                    <button onClick={() => unlockVehicle(v.id)} className="p-2 bg-slate-800 text-slate-500 hover:text-rose-400 hover:bg-slate-700 rounded-lg transition-all"><FastForward className="w-3.5 h-3.5" /></button>
                  </div>
                ))}
                {inRepairCount === 0 && (
                   <div className="py-12 flex flex-col items-center justify-center border border-dashed border-slate-800/50 rounded-3xl opacity-30">
                     <CheckCircle2 className="w-8 h-8 text-emerald-500 mb-2" />
                     <span className="text-[8px] font-black text-slate-600 uppercase tracking-[0.3em]">Quality Clear</span>
                   </div>
                )}
              </div>
            </div>
          )}
        </div>

        {/* VIEWPORT CONTROLS */}
        <div className="p-6 border-t border-slate-900 space-y-5 shrink-0 bg-slate-950">
          <div className="space-y-3">
             <div className="flex justify-between items-center text-[8px] font-black text-slate-600 uppercase tracking-widest">
                <span className="flex items-center gap-1.5"><Maximize2 className="w-2.5 h-2.5" /> Viewport Control</span>
                <span className="text-indigo-500">{Math.round(scale * 100)}%</span>
             </div>
             <div className="flex items-center gap-3 px-1">
               <ZoomOut className="w-3.5 h-3.5 text-slate-700" />
               <input type="range" min="0.15" max="1.5" step="0.01" value={manualScale} disabled={isFitToScreen} onChange={(e) => setManualScale(parseFloat(e.target.value))} className={`flex-1 h-1.5 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-indigo-600 cursor-pointer'}`} />
               <ZoomIn className="w-3.5 h-3.5 text-slate-700" />
             </div>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2 py-3 rounded-xl font-black text-[9px] uppercase border-2 transition-all active:scale-95 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20' : 'bg-indigo-600 text-white border-indigo-400/30 shadow-lg shadow-indigo-900/40'}`}>
              {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />}
              {isRunning ? 'Line Halt' : 'Line Start'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setStats(s => ({ ...s, produced: 0, defects: 0 })); addLog("PRODUCTION RESET."); }} className="flex items-center justify-center gap-2 py-3 bg-slate-900 text-slate-500 rounded-xl border border-slate-800 font-black text-[9px] uppercase hover:text-white transition-colors active:scale-95">
              <RotateCcw className="w-4 h-4" /> Reset
            </button>
          </div>
        </div>
      </aside>

      {/* SIMULATION VIEWPORT */}
      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} className="cursor-crosshair" />
          </div>
        </div>

        {/* LOG BUFFER */}
        <div className="h-12 bg-slate-950 border-t border-slate-900 flex items-center px-6 gap-6 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-2 shrink-0 z-20 text-indigo-500"><Terminal className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.3em]">Log_Buffer</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-20 animate-marquee py-1">
              {logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-500 uppercase tracking-tight flex gap-3 items-center">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500/30" /> {log}
                </span>
              ))}
              {logs.length === 0 && <span className="text-[9px] font-bold text-slate-800 uppercase italic opacity-40">System scanning production nodes...</span>}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Truck,
  Gauge,
  Cpu,
  BarChart3,
  CheckCircle2,
  Maximize2,
  Minimize2,
  Wrench,
  ShieldAlert,
  ZoomIn,
  ZoomOut,
  MonitorDot,
  TrendingUp,
  Settings2,
  Search,
  Zap,
  FastForward,
  Boxes,
  Microchip,
  FlaskConical,
  PackageCheck,
  AlertTriangle,
  Terminal,
  Command,
  Unlock,
  AlertCircle,
  Ban
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, StationType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'TELEMETRY' | 'QUALITY';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('NODES');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(180); 
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.15); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);
  const [hoveredVehicleId, setHoveredVehicleId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 60;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      const finalScale = Math.max(0.15, s);
      setScale(finalScale);
      setManualScale(finalScale);
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 120; // Extended grace to clear congestion
      addLog(`COMMAND: RELEASE/OVERRIDE UNIT ${v.id.toUpperCase()}`);
    }
  };

  const unlockAll = () => {
    const lockedCount = vehiclesRef.current.filter(v => v.isLocked).length;
    if (lockedCount > 0) {
      vehiclesRef.current.forEach(v => {
        if(v.isLocked) {
           v.isLocked = false;
           v.waitingTimer = 0;
           v.ignoreCollisionTimer = 120;
        }
      });
      addLog(`GLOBAL OVERRIDE: ${lockedCount} UNITS RELEASED`);
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        const passedFtt = !v.everRepaired;
        setStats(s => ({ 
          ...s, 
          produced: s.produced + 1,
          passedFirstTime: passedFtt ? s.passedFirstTime + 1 : s.passedFirstTime,
          totalRepaired: v.everRepaired ? s.totalRepaired + 1 : s.totalRepaired
        }));
        addLog(`UNIT ${v.id.toUpperCase()} SHIPPED [${passedFtt ? 'FTT' : 'REPAIR'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === 22 && !v.inRepair) {
           v.isLocked = true;
           addLog(`GATE HOLD: UNIT ${v.id.toUpperCase()}`);
        }

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair) {
           const laneUsage = ROLL_TEST_BRANCHES.map((_, lIdx) => 
             currentVehicles.filter(veh => veh.id !== v.id && veh.targetPath.some(p => p.y === (lIdx === 0 ? 340 : lIdx === 1 ? 420 : 500))).length
           );
           const bestLaneIdx = laneUsage.indexOf(Math.min(...laneUsage));
           v.targetPath = [...MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), ...ROLL_TEST_BRANCHES[bestLaneIdx].slice(1), ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
        }
        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);
        if (station) {
          v.waitingTimer = station.wait;
          if (station.name === 'FAI QC' && v.hasDefect && !v.isRepaired) {
            v.inRepair = true; v.everRepaired = true; 
            const stages = Math.random() < 0.4 ? 2 : 1;
            v.pendingRepairs = stages; 
            v.initialRepairs = stages;
            v.completedRepairs = 0;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, repairAttempts: s.repairAttempts + 1 }));
            addLog(`FAI QC: DEFECT DETECTED ON ${v.id.toUpperCase()}`);
          }
          if (v.inRepair && (station.name === 'FUNILARIA' || station.name === 'FCPA')) {
            if (v.pendingRepairs > 0) {
              v.pendingRepairs--;
              v.completedRepairs++;
              setStats(s => ({ ...s, totalStagesCompleted: s.totalStagesCompleted + 1 }));
            }
          }
          if (v.inRepair && station.name === 'ÁREA BRANCA') { 
            v.inRepair = false; 
            v.isRepaired = true; 
            v.targetPath = [...MAIN_PATH_POINTS]; 
            v.pathIdx = 18; 
            v.color = v.baseColor; 
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
    if (mousePosRef.current) {
      const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
      const found = allStations.find(s => {
        const w = s.width || 110; const h = s.height || 45;
        return mousePosRef.current && mousePosRef.current.x >= s.pos.x - w/2 && mousePosRef.current.x <= s.pos.x + w/2 && mousePosRef.current.y >= s.pos.y - h/2 && mousePosRef.current.y <= s.pos.y + h/2;
      });
      setHoveredStationId(found ? found.id : null);
    }
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)'; ctx.lineWidth = 1;
    for (let x = 0; x <= SIM_WIDTH; x += 100) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, SIM_HEIGHT); ctx.stroke(); }
    for (let y = 0; y <= SIM_HEIGHT; y += 100) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(SIM_WIDTH, y); ctx.stroke(); }

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 22));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#330a0a', 22);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 38;
      const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 10 && Math.abs(veh.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      if (v) {
        if (v.waitingTimer > 0) status = 'PROCESSING';
        else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }

      let ledColor = '#334155';
      if (status === 'PROCESSING') ledColor = '#10b981';
      else if (status === 'OCCUPIED') ledColor = '#fbbf24';
      else if (status === 'BLOCKED') ledColor = '#ef4444';

      const isHovered = hoveredStationId === s.id;
      if (isHovered) { ctx.shadowBlur = 15; ctx.shadowColor = 'rgba(99, 102, 241, 0.5)'; }

      ctx.strokeStyle = isHovered ? '#6366f1' : 'rgba(255,255,255,0.08)'; 
      ctx.lineWidth = isHovered ? 2 : 1;
      ctx.fillStyle = 'rgba(15, 23, 42, 0.85)'; 
      ctx.beginPath(); 
      ctx.roundRect(x, y, w, h, 3); 
      ctx.fill(); 
      ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = ledColor; ctx.beginPath(); ctx.arc(x + 10, y + 10, 3.5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 18, y + 13);

      if (status === 'PROCESSING' && v) {
        const prog = 1 - (v.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.fillRect(x + 5, y + h - 6, w - 10, 2);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 5, y + h - 6, (w - 10) * prog, 2);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      const isHoveredV = hoveredVehicleId === v.id;
      ctx.shadowBlur = isHoveredV ? 12 : 4; 
      ctx.shadowColor = isHoveredV ? 'white' : 'rgba(0,0,0,0.4)';
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; 
      ctx.fillStyle = v.color; 
      ctx.beginPath(); 
      ctx.roundRect(-18, -9, 36, 18, 3); 
      ctx.fill();

      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.fillStyle = 'white'; ctx.font = 'bold 7px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(`${v.completedRepairs}/${v.initialRepairs}`, 0, 2);
        else if (v.isLocked) {
          ctx.save(); ctx.rotate(-v.rotation);
          ctx.fillStyle = '#fbbf24'; ctx.beginPath(); ctx.arc(0, -15, 4, 0, Math.PI * 2); ctx.fill();
          ctx.restore();
        }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)'; ctx.font = '800 24px Inter'; ctx.fillText('FACTORY_TWIN_V4.9', 50, 45);
  }, [hoveredStationId, hoveredVehicleId, speed]);

  useEffect(() => {
    let frameId: number;
    const loop = () => {
      updateSimulation();
      if (canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) draw(ctx);
      }
      frameId = requestAnimationFrame(loop);
    };
    frameId = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(frameId);
  }, [updateSimulation, draw]);

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (rect) { mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale }; }
  };

  const ftrRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const fttYield = stats.totalStarted > 0 ? (stats.produced / stats.totalStarted) * 100 : 0;

  const allProductionStations = useMemo(() => {
    return [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
  }, []);

  const stationMonitorData = useMemo(() => {
    return allProductionStations.map(s => {
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 10 && Math.abs(veh.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE';
      let waitProgress = 0;
      let occupantId: string | null = null;
      let isOccupantLocked = false;

      if (v) {
        occupantId = v.id;
        isOccupantLocked = v.isLocked;
        if (v.waitingTimer > 0) {
          status = 'PROCESSING';
          waitProgress = 1 - (v.waitingTimer / s.wait);
        } else {
          const isBlocked = v.ignoreCollisionTimer <= 0 && vehiclesRef.current.some(other => {
            if (other.id === v.id) return false;
            const onSamePath = (other.inRepair === v.inRepair);
            const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
            return onSamePath ? (distToOther < 65 && other.pathIdx >= v.pathIdx) : (distToOther < 45);
          });
          status = isBlocked ? 'BLOCKED' : 'OCCUPIED';
        }
      }
      return { id: s.id, name: s.name, status, type: s.type, occupantId, waitProgress, isOccupantLocked };
    });
  }, [allProductionStations, stats.active]);

  const statusBreakdown = useMemo(() => {
    const counts = { IDLE: 0, PROCESSING: 0, OCCUPIED: 0, BLOCKED: 0 };
    stationMonitorData.forEach(s => counts[s.status]++);
    return counts;
  }, [stationMonitorData]);

  const filteredStations = useMemo(() => {
    return stationMonitorData.filter(s => 
      s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      s.status.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [stationMonitorData, searchTerm]);

  const inRepairCount = vehiclesRef.current.filter(v => v.inRepair).length;
  const lockedVehicles = vehiclesRef.current.filter(v => v.isLocked);
  const blockedVehicles = stationMonitorData.filter(s => s.status === 'BLOCKED');

  const ecatTelemetry = useMemo(() => {
    const isRollerProcessing = stationMonitorData.some(s => s.name.startsWith('Teste Rolo') && s.status === 'PROCESSING');
    const rollerSpeed = isRollerProcessing ? Math.floor(Math.random() * 20 + 75) : 0; 
    const isElecProcessing = stationMonitorData.some(s => s.name === 'Reparo Elétrico' && s.status === 'PROCESSING');
    const elecVoltage = isElecProcessing ? (12.4 + Math.random() * 0.4).toFixed(2) : "0.00";
    const elecCurrent = isElecProcessing ? (15 + Math.random() * 5).toFixed(1) : "0.0";

    return [
      { id: 'e1', name: 'Fleet Speed', unit: 'SENS_L0', value: (speed * 1.15).toFixed(1), label: 'KM/H', progress: Math.min(1, stats.active / 20), color: 'emerald' },
      { id: 'e2', name: 'Roller Torque', unit: 'ROLL_VFD', value: rollerSpeed, label: 'KM/H', progress: rollerSpeed / 100, isGauge: true, color: 'blue' },
      { id: 'e3', name: 'System Bus', unit: 'ECAT_DC', value: elecVoltage, label: 'V', progress: parseFloat(elecVoltage) / 14, icon: <Zap className="w-3 h-3 text-yellow-400" />, color: 'amber' },
      { id: 'e4', name: 'Line Load', unit: 'AMP_01', value: elecCurrent, label: 'A', progress: parseFloat(elecCurrent) / 30, color: 'rose' }
    ];
  }, [speed, stats.active, stationMonitorData]);

  const getStationIcon = (type: StationType) => {
    switch(type) {
      case StationType.STORAGE: return <Boxes className="w-4 h-4" />;
      case StationType.ASSEMBLY: return <Microchip className="w-4 h-4" />;
      case StationType.MGR: return <Settings2 className="w-4 h-4" />;
