            </div>
          )}
          {activeTab === 'QUALITY' && (
            <div className="p-6 space-y-6 overflow-y-auto">
              <div className="flex items-center justify-between">
                <div className="flex flex-col">
                   <span className="text-[10px] font-black text-rose-400 uppercase tracking-widest flex items-center gap-2">
                     <ShieldAlert className="w-4 h-4" /> Service Orders (SO)
                   </span>
                   <span className="text-[7px] font-bold text-slate-600 uppercase mt-1 tracking-widest">Repair Chain Tracking</span>
                </div>
                <div className="bg-slate-900 border border-slate-800 px-3 py-1.5 rounded-xl flex items-center gap-2">
                   <Timer className="w-3 h-3 text-indigo-400" />
                   <span className="text-[9px] font-black text-slate-400">{inRepairVehicles.length} UNITS</span>
                </div>
              </div>

              <div className="space-y-4">
                {inRepairVehicles.map(v => (
                  <div key={v.id} onMouseEnter={() => setHoveredVehicleId(v.id)} onMouseLeave={() => setHoveredVehicleId(null)} className="bg-slate-900/40 border border-slate-800/50 p-4 rounded-2xl group hover:border-rose-500/30 transition-all flex flex-col gap-4 relative overflow-hidden">
                    {v.failureType === 'LEAKAGE' && <div className="absolute top-0 right-0 p-2 bg-blue-500/10 rounded-bl-xl"><Droplets className="w-3 h-3 text-blue-400" /></div>}

                    <div className="flex items-center justify-between">
                       <div className="flex items-center gap-3">
                          <div className="w-10 h-5 rounded-sm border border-slate-700 shadow-sm" style={{ backgroundColor: v.color }} />
                          <div className="flex flex-col">
                             <span className="text-[10px] font-black text-slate-200 uppercase tracking-tighter">UNIT_{v.id.toUpperCase()}</span>
                             <span className="text-[7px] font-black text-indigo-400/80 uppercase tracking-[0.2em]">{v.workOrderId}</span>
