                       </div>
                       <div className={`px-2 py-1 rounded-md border text-[7px] font-black uppercase tracking-widest ${v.failureType === 'LEAKAGE' ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-rose-500/10 border-rose-500/20 text-rose-400'}`}>
                         {v.failureType}
                       </div>
