                          </div>
                       </div>
                       <div className="flex items-center gap-2 p-2 bg-slate-950/60 rounded-xl border border-slate-800/30">
                          <ShieldCheck className="w-3 h-3 text-emerald-400" />
                          <div className="flex flex-col">
                             <span className="text-[6px] font-bold text-slate-600 uppercase">Repair Node</span>
                             <span className="text-[9px] font-black text-slate-300 uppercase">STG {v.completedRepairs + 1}/{v.initialRepairs}</span>
                          </div>
                       </div>
                    </div>

                    <div className="space-y-1">
                       <div className="flex justify-between text-[6px] font-black text-slate-600 uppercase tracking-widest px-1">
                          <span>Service Execution</span>
                          <span className="text-emerald-500">{Math.round((v.completedRepairs/v.initialRepairs)*100)}%</span>
                       </div>
                       <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                          <div className={`h-full transition-all duration-300 ${v.failureType === 'LEAKAGE' ? 'bg-blue-500' : 'bg-rose-500'}`} style={{ width: `${(v.completedRepairs / v.initialRepairs) * 100}%` }} />
                       </div>
                    </div>

                    <button onClick={() => unlockVehicle(v.id)} className="w-full py-2.5 bg-slate-800 text-slate-500 hover:text-white hover:bg-slate-700 rounded-xl transition-all text-[8px] font-black uppercase tracking-widest flex items-center justify-center gap-2 group/btn">
                      <FastForward className="w-3.5 h-3.5 group-hover/btn:translate-x-1 transition-transform" /> {v.completedRepairs + 1 === v.initialRepairs ? 'Complete & Re-test' : 'Advance Station'}
