            </div>
          )}
        </div>

        <div className="p-6 border-t border-slate-900 space-y-4 shrink-0 bg-slate-950">
          <div className="space-y-3">
             <div className="flex justify-between items-center text-[8px] font-black text-slate-600 uppercase tracking-widest">
                <span className="flex items-center gap-1.5"><Maximize2 className="w-2.5 h-2.5" /> Simulation Scale</span>
                <span className="text-indigo-500">{Math.round(scale * 100)}%</span>
             </div>
             <div className="flex items-center gap-3 px-1">
               <ZoomOut className="w-3.5 h-3.5 text-slate-700" />
               <input type="range" min="0.15" max="1.5" step="0.01" value={manualScale} disabled={isFitToScreen} onChange={(e) => setManualScale(parseFloat(e.target.value))} className={`flex-1 h-1.5 rounded-full appearance-none bg-slate-800 transition-opacity ${isFitToScreen ? 'opacity-20 cursor-not-allowed' : 'accent-indigo-600 cursor-pointer'}`} />
               <ZoomIn className="w-3.5 h-3.5 text-slate-700" />
             </div>
          </div>
          <div className="flex flex-col gap-2">
            <button 
              onClick={unlockAll}
              className={`flex items-center justify-center gap-2 py-3.5 rounded-xl font-black text-[10px] uppercase border-2 transition-all shadow-lg active:scale-95 group ${
                !isRunning || lockedVehicles.length > 0 
                ? 'bg-amber-500 text-slate-950 border-amber-400 shadow-amber-900/30' 
                : 'bg-slate-900 text-amber-500/50 border-amber-500/10 hover:border-amber-500/30'
              }`}
            >
              {isRunning && lockedVehicles.length === 0 ? <Key className="w-4 h-4 opacity-50" /> : <Flame className="w-4 h-4 animate-bounce" />}
              {!isRunning ? 'Full Line Recovery' : 'Master Release (Override)'}
            </button>
            <div className="grid grid-cols-2 gap-2">
              <button onClick={() => setIsRunning(!isRunning)} className={`flex items-center justify-center gap-2 py-3 rounded-xl font-black text-[9px] uppercase border-2 transition-all active:scale-95 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20' : 'bg-indigo-600 text-white border-indigo-400/30 shadow-lg shadow-indigo-900/40'}`}>
                {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />}
                {isRunning ? 'Line Halt' : 'Line Start'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats(s => ({ ...s, produced: 0, defects: 0, active: 0 })); addLog("SYSTEM RESET COMPLETE."); }} className="flex items-center justify-center gap-2 py-3 bg-slate-900 text-slate-500 rounded-xl border border-slate-800 font-black text-[9px] uppercase hover:text-white transition-colors active:scale-95">
                <RotateCcw className="w-4 h-4" /> Reset
              </button>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_120px_rgba(0,0,0,0.9)] border-[16px] border-slate-950 bg-[#0f172a] rounded-[3rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={handleMouseMove} className="cursor-crosshair" />
          </div>
        </div>
        <div className="h-12 bg-slate-950 border-t border-slate-900 flex items-center px-6 gap-6 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-2 shrink-0 z-20 text-indigo-500"><Terminal className="w-3 h-3" /><span className="text-[8px] font-black uppercase tracking-[0.3em]">System_Buffer</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-20 animate-marquee py-1">
              {logs.map((log, i) => (
                <span key={i} className="text-[9px] font-bold text-slate-500 uppercase tracking-tight flex gap-3 items-center">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500/30" /> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export type FailureType = 'ELECTRICAL' | 'ELECTRONIC' | 'MECHANICAL' | 'LEAKAGE';
export type QualityStatus = 'NONE' | 'PASS' | 'FAIL';

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  baseColor: string; // Original color assigned at Body Shop
  finished: boolean;
  progress: number;
  // Tracking and unblocking
  everRepaired: boolean;
  ignoreCollisionTimer: number;
  pendingRepairs: number; // Number of repair stages needed
  completedRepairs: number; // Number of repair stages finished
  initialRepairs: number; // Total stages assigned at QC
  isLocked: boolean; // Manual release gate
  // Automotive Repair Flow fields
  failureType: FailureType | null;
  lastFailureType: FailureType | null; // For FTR logic
  workOrderId: string | null;
  repairStartTime: number | null; // Frame count when repair started
  currentLeadTime: number; // Calculated lead time in frames
  // Industrial Gate Controls
  faiStatus: QualityStatus;
  waterTestStatus: QualityStatus;
  finalInspectionStatus: QualityStatus;
  // Logistics Flow Configuration
  everEnteredWaitingArea: boolean;
  waitingAreaEntryCount: number;
  isFtrNegative: boolean; // Flag if vehicle returns for same reason
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  // Industrial metrics
  totalStarted: number;
  passedFirstTime: number; // FTT component
  totalRepaired: number;
  repairAttempts: number;
  totalStagesCompleted: number;
  // New Enhanced Metrics
  totalLeadTimeFrames: number;
  repairCompletedCount: number;
  categoryVolumes: Record<FailureType, number>;
}

