              {isRunning ? 'System Online' : 'System Halted'}
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
             <div className="bg-slate-900/50 p-2.5 rounded-xl border border-slate-800/50 flex flex-col">
                <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest mb-1">FTT Performance</span>
                <span className={`text-sm font-black tabular-nums ${fttYield > 85 ? 'text-emerald-400' : 'text-amber-400'}`}>{fttYield.toFixed(1)}%</span>
             </div>
             <div className="bg-slate-900/50 p-2.5 rounded-xl border border-slate-800/50 flex flex-col">
                <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest mb-1">Resolution Area</span>
                <span className="text-sm font-black text-white tabular-nums">{inRepairVehicles.length} UNITS</span>
             </div>
          </div>
        </div>

        <div className="flex border-b border-slate-900 bg-slate-950 px-4 shrink-0">
          {[
            { id: 'NODES', label: 'Production', icon: <MonitorDot className="w-3.5 h-3.5" /> },
            { id: 'TELEMETRY', label: 'Performance', icon: <BarChart className="w-3.5 h-3.5" /> },
            { id: 'QUALITY', label: 'Resolution Hub', icon: <LayoutGrid className="w-3.5 h-3.5" /> }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as DashboardTab)} className={`flex-1 flex items-center justify-center gap-2 py-3.5 text-[9px] font-black uppercase tracking-wider transition-all relative ${activeTab === tab.id ? 'text-indigo-400' : 'text-slate-600 hover:text-slate-400'}`}>
              {tab.icon} {tab.label}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.5)]" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col">
          {activeTab === 'NODES' && (
            <div className="p-4 space-y-4">
              <div className="relative group shrink-0">
                <Search className="absolute left-3 top-3 w-3.5 h-3.5 text-slate-700 group-focus-within:text-indigo-500 transition-colors" />
                <input type="text" placeholder="FIND PRODUCTION NODE..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/50 border border-slate-800 rounded-xl py-2.5 pl-10 pr-3 text-[9px] font-black tracking-widest text-slate-300 focus:outline-none focus:border-indigo-500/50 transition-all placeholder:text-slate-700 uppercase" />
