              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0}); addLog("KPI BUFFER RESET."); }} className="py-4 bg-slate-900 text-slate-600 border border-slate-800 rounded-2xl font-black text-[10px] uppercase hover:text-white hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                 <RotateCcw className="w-4 h-4" /> Reset KPI
