          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_150px_rgba(0,0,0,1)] border-[20px] border-slate-950 bg-[#0f172a] rounded-[4rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const rect = canvasRef.current?.getBoundingClientRect();
              if (rect) mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale };
