          </div>
        </div>
        <div className="h-14 bg-slate-950 border-t border-slate-900 flex items-center px-8 gap-8 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-2.5 shrink-0 z-20 text-indigo-500"><Terminal className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-[0.4em]">Node_Stream</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-24 animate-marquee py-1.5">
              {logs.map((log, i) => (
                <span key={i} className="text-[10px] font-bold text-slate-500 uppercase tracking-tight flex gap-4 items-center">
                  <div className="w-2 h-2 rounded-full bg-indigo-500/40 shadow-[0_0_10px_rgba(99,102,241,0.5)]" /> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Cpu,
  CheckCircle2,
  Maximize2,
  Wrench,
  ShieldAlert,
  ZoomIn,
  ZoomOut,
  MonitorDot,
  TrendingUp,
  Settings2,
  Search,
  FastForward,
  Boxes,
  Microchip,
  FlaskConical,
  PackageCheck,
  AlertTriangle,
  // Added AlertCircle to fix the undefined name error
  AlertCircle,
  Terminal,
  Unlock,
  Key,
  Flame,
  Timer,
  Droplets,
  ShieldCheck,
  XCircle,
  BarChart,
  LayoutGrid,
  Info,
  Clock,
  ArrowRightCircle,
  History,
  TrendingDown,
  ChevronRight
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, StationType, FailureType, QualityStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const FAILURE_TYPES: FailureType[] = ['ELECTRICAL', 'ELECTRONIC', 'MECHANICAL', 'LEAKAGE'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(432); // Adjusted for ~500 VPH (3600/500 * 60 = 432 frames)
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.28); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0,
    totalLeadTimeFrames: 0,
    repairCompletedCount: 0,
    ftrFails: 0,
    ftrSuccesses: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);
  const [hoveredVehicleId, setHoveredVehicleId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 60;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      setScale(Math.max(0.15, s));
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false,
      failureType: null,
      lastFailureType: null,
      workOrderId: null,
      repairStartTime: null,
      currentLeadTime: 0,
      faiStatus: 'NONE',
      waterTestStatus: 'NONE',
      finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false,
      waitingAreaEntryCount: 0,
      isFtrNegative: false,
      viaVerde: true,
      repairAttemptsInCurrentSession: 0
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 120; 
      addLog(`MANUAL RELEASE: UNIT ${v.id.toUpperCase()}`);
    }
  };

  const unlockAll = useCallback(() => {
    const affectedUnits = vehiclesRef.current.filter(v => v.isLocked || v.waitingTimer > 0);
    const count = affectedUnits.length;
    if (count > 0 || !isRunning) {
      vehiclesRef.current.forEach(v => {
        v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 180;
      });
      if (!isRunning) {
        setIsRunning(true);
        addLog(`MASTER RECOVERY: CADENCE RESTORED. ${count} UNITS RELEASED.`);
      } else {
        addLog(`MASTER OVERRIDE: ${count} UNITS RELEASED.`);
      }
    } else {
      addLog("LOGISTICS STATUS: CLEAR.");
    }
  }, [isRunning]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.inRepair && v.repairStartTime !== null) {
        v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      }

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        if (v.viaVerde) {
          setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        }
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`SHIPPING: UNIT ${v.id.toUpperCase()} [${v.viaVerde ? 'FTT' : 'REPAIR'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // Final Security Check
        if (v.pathIdx === 22 && !v.inRepair) {
           const isClear = v.faiStatus === 'PASS' && v.waterTestStatus === 'PASS' && v.finalInspectionStatus === 'PASS';
           if (!isClear) {
             v.isLocked = true;
             addLog(`BLOCKAGE: UNIT ${v.id.toUpperCase()} FAILS FINAL SECURITY GATE.`);
           }
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          // QUALITY FLOW: DYNAMIC REDIRECTION
          const sendToResolutionHub = (source: string, forcedType?: FailureType) => {
            const cat = forcedType || FAILURE_TYPES[Math.floor(Math.random() * FAILURE_TYPES.length)];

            // FTR Metric Tracking
            if (v.lastFailureType === cat) {
              v.isFtrNegative = true;
              setStats(s => ({ ...s, ftrFails: s.ftrFails + 1 }));
              addLog(`FTR ALERT: REPETITIVE FAULT [${cat}] ON UNIT ${v.id.toUpperCase()}`);
            }

            v.lastFailureType = cat;
            v.failureType = cat;
            v.viaVerde = false;
            v.inRepair = true;
            v.everEnteredWaitingArea = true;
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0; 
            v.color = COLORS.REPAIR;
            v.repairAttemptsInCurrentSession = 0;

            setStats(s => ({ 
              ...s, 
              defects: s.defects + 1,
              categoryVolumes: { ...s.categoryVolumes, [cat]: s.categoryVolumes[cat] + 1 },
              totalWaitAreaEntries: s.totalWaitAreaEntries + 1
            }));

            addLog(`${source}: UNIT ${v.id.toUpperCase()} REDIRECTED TO HUB [${cat}]`);
          };

          if (station.name === 'Flat Top') {
             if (v.hasDefect && Math.random() < 0.35) {
               v.finalInspectionStatus = 'FAIL';
               sendToResolutionHub('FLAT TOP');
             } else {
               v.finalInspectionStatus = 'PASS';
             }
          }

          if (station.name === 'FAI QC') {
             if (v.hasDefect && v.faiStatus !== 'PASS') {
                v.faiStatus = 'FAIL';
                sendToResolutionHub('FAI QC');
             } else {
                v.faiStatus = 'PASS';
             }
          }

          if (station.name === 'SISTEMA ÁGUA') {
             if (Math.random() < 0.12 && v.waterTestStatus !== 'PASS') {
                v.waterTestStatus = 'FAIL';
                sendToResolutionHub('WATER TEST', 'LEAKAGE');
             } else {
                v.waterTestStatus = 'PASS';
             }
          }

          // Hub Dispatching
          if (station.name === 'Waiting Area') {
             v.repairAttemptsInCurrentSession++;
             if (v.failureType === 'LEAKAGE') {
                v.pathIdx = 2; // stage 3 Leakage Cell
             } else if (v.failureType === 'ELECTRICAL' || v.failureType === 'ELECTRONIC') {
                v.pathIdx = 3; // stage 4 Elec Repair
             } else {
                v.pathIdx = 1; // stage 2 Mec Repair
             }
          }

          if (v.inRepair && v.pathIdx > 1 && v.pathIdx < 5) {
             v.completedRepairs++;
          }

          // PROTOCOL RE-ENTRY
          if (v.inRepair && station.name === 'ÁREA BRANCA') {
             v.inRepair = false;
             v.isRepaired = true;

             if (v.repairAttemptsInCurrentSession === 1) {
                setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1 }));
             }

             const leadTime = frameCountRef.current - (v.repairStartTime || 0);
             setStats(s => ({ ...s, totalLeadTimeFrames: s.totalLeadTimeFrames + leadTime, repairCompletedCount: s.repairCompletedCount + 1 }));

             v.repairStartTime = null; 
             v.currentLeadTime = 0; 
             v.color = v.baseColor;

             if (v.failureType === 'LEAKAGE') {
                v.waterTestStatus = 'NONE';
                v.targetPath = [...MAIN_PATH_POINTS];
                v.pathIdx = 18; 
                addLog(`HUB EXIT: LEAK REPAIRED. UNIT ${v.id.toUpperCase()} -> WATER RE-TEST`);
             } else {
                v.finalInspectionStatus = 'NONE';
                v.targetPath = [...MAIN_PATH_POINTS];
                v.pathIdx = 10; 
                addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> FINAL GATE`);
             }
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 22));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#200505', 28);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 38; const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 10 && Math.abs(veh.pos.y - s.pos.y) < 10);
      let status: StationStatus = 'IDLE', prog = 0;
      if (v) {
        if (v.waitingTimer > 0) { status = 'PROCESSING'; prog = 1 - (v.waitingTimer / s.wait); }
        else status = 'OCCUPIED';
      }
      ctx.strokeStyle = (hoveredStationId === s.id) ? '#6366f1' : 'rgba(255,255,255,0.06)'; 
      ctx.lineWidth = (hoveredStationId === s.id) ? 2 : 1; ctx.fillStyle = 'rgba(15, 23, 42, 0.95)'; 
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke();
      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#fbbf24' : '#334155');
      ctx.beginPath(); ctx.arc(x + 12, y + 12, 4, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 9px Inter'; ctx.fillText(s.name.toUpperCase(), x + 22, y + 15);
      if (status === 'PROCESSING') { ctx.fillStyle = 'rgba(255,255,255,0.03)'; ctx.fillRect(x + 5, y + h - 6, w - 10, 3); ctx.fillStyle = '#10b981'; ctx.fillRect(x + 5, y + h - 6, (w - 10) * prog, 3); }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      if (v.viaVerde && !v.inRepair) {
        ctx.globalCompositeOperation = 'source-over';
        ctx.strokeStyle = '#10b981'; ctx.lineWidth = 2; ctx.strokeRect(-18, -9, 36, 18);
      }
      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over'; ctx.fillStyle = 'white'; ctx.font = 'bold 8px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) { ctx.fillText(v.workOrderId || '', 0, 3); }
        else { ctx.save(); ctx.rotate(-v.rotation); ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(0, -18, 5, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.4)'; ctx.font = '800 28px Inter'; ctx.fillText('VPH_FLOW_500_PRO', 50, 50);
  }, [hoveredStationId]);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const avgDwell = stats.repairCompletedCount > 0 ? (stats.totalLeadTimeFrames / stats.repairCompletedCount / 60).toFixed(1) : "0.0";

  const greenWayCount = vehiclesRef.current.filter(v => v.viaVerde && !v.inRepair).length;
  const repairHubCount = vehiclesRef.current.filter(v => v.inRepair).length;
  const lockedVehicles = vehiclesRef.current.filter(v => v.isLocked);

  const paretoData = useMemo(() => {
    return FAILURE_TYPES.map(type => ({
      type,
      total: stats.categoryVolumes[type]
    })).sort((a, b) => b.total - a.total);
  }, [stats.categoryVolumes]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
      <aside className="w-[400px] lg:w-[460px] bg-slate-950 border-r border-slate-900 flex flex-col shadow-2xl shrink-0 z-20">
        <div className="p-6 border-b border-slate-900 shrink-0 space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="p-2 bg-indigo-600 rounded-xl shadow-[0_0_15px_rgba(79,70,229,0.4)]"><Cpu className="w-5 h-5 text-white" /></div>
              <h1 className="text-[11px] font-black tracking-[0.4em] uppercase text-indigo-400">FACTORY_OS V5.2</h1>
            </div>
            <div className="flex flex-col items-end">
               <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[8px] font-black uppercase ${isRunning ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : 'bg-rose-500/10 border-rose-500/30 text-rose-400'}`}>
                 <div className={`w-1 h-1 rounded-full ${isRunning ? 'bg-emerald-400' : 'bg-rose-400'}`} />
                 {isRunning ? 'Line High-Cadence' : 'System Halted'}
               </div>
               <span className="text-[7px] font-black text-slate-600 mt-1 uppercase tracking-widest">Target: 500 VPH</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="bg-slate-900/40 p-5 rounded-3xl border border-slate-800/50 flex flex-col items-center group relative overflow-hidden transition-all hover:border-emerald-500/30">
                <div className="absolute top-0 left-0 w-full h-1 bg-emerald-500/10 group-hover:bg-emerald-500/30" />
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 flex items-center gap-1.5">
                  <CheckCircle2 className="w-2.5 h-2.5 text-emerald-500" /> VIA VERDE (FTT)
                </span>
                <span className={`text-3xl font-black tabular-nums tracking-tighter ${fttRate > 80 ? 'text-emerald-400' : 'text-amber-400'}`}>{fttRate.toFixed(1)}%</span>
             </div>
             <div className="bg-slate-900/40 p-5 rounded-3xl border border-slate-800/50 flex flex-col items-center group relative overflow-hidden transition-all hover:border-indigo-500/30">
                <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500/10 group-hover:bg-indigo-500/30" />
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1 flex items-center gap-1.5">
                  <Wrench className="w-2.5 h-2.5 text-indigo-500" /> REPAIR (FTR)
                </span>
                <span className={`text-3xl font-black tabular-nums tracking-tighter ${ftrRate > 90 ? 'text-indigo-400' : 'text-amber-400'}`}>{ftrRate.toFixed(1)}%</span>
             </div>
          </div>
        </div>

        <div className="flex border-b border-slate-900 bg-slate-950 shrink-0">
          {[
            { id: 'KPI', label: 'Dashboard', icon: <BarChart className="w-3.5 h-3.5" /> },
            { id: 'NODES', label: 'Flow Nodes', icon: <LayoutGrid className="w-3.5 h-3.5" /> },
            { id: 'QUALITY', label: 'Resolution Hub', icon: <ShieldAlert className="w-3.5 h-3.5" /> }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as DashboardTab)} className={`flex-1 flex items-center justify-center gap-2 py-4 text-[9px] font-black uppercase tracking-wider transition-all relative ${activeTab === tab.id ? 'text-indigo-400 bg-indigo-500/5' : 'text-slate-600 hover:text-slate-400 hover:bg-slate-900/30'}`}>
              {tab.icon} {tab.label}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-indigo-500 shadow-[0_-2px_10px_rgba(99,102,241,0.5)]" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col">
          {activeTab === 'KPI' && (
            <div className="p-6 space-y-8 animate-in fade-in duration-500">
              {/* Pareto Section */}
              <div className="bg-slate-900/40 p-6 rounded-3xl border border-slate-800/50 space-y-6">
                 <div className="flex justify-between items-center">
                    <div className="flex flex-col">
                      <span className="text-[11px] font-black text-white uppercase tracking-[0.2em]">FTT Pareto Analysis</span>
                      <span className="text-[7px] font-bold text-slate-600 uppercase">Primary Loss Drivers</span>
                    </div>
                    <History className="w-4 h-4 text-slate-700" />
                 </div>
                 <div className="space-y-5">
                    {paretoData.map(cat => (
                       <div key={cat.type} className="space-y-1.5 group cursor-default">
                          <div className="flex justify-between text-[8px] font-black uppercase tracking-tighter text-slate-500">
                             <span className="group-hover:text-slate-300 transition-colors">{cat.type}</span>
                             <span className="text-slate-200 tabular-nums">{cat.total} EVENTS</span>
                          </div>
                          <div className="w-full h-2.5 bg-slate-950 rounded-full overflow-hidden flex border border-slate-900">
                             <div className={`h-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(0,0,0,0.5)] ${cat.type === 'LEAKAGE' ? 'bg-blue-500' : cat.type === 'ELECTRICAL' ? 'bg-rose-500' : 'bg-amber-500'}`} style={{ width: `${stats.defects > 0 ? (cat.total / stats.defects) * 100 : 0}%` }} />
                          </div>
                       </div>
                    ))}
                 </div>
              </div>

              {/* Real-time Load Distribution */}
              <div className="bg-slate-900/40 p-6 rounded-3xl border border-slate-800/50 space-y-4">
                 <span className="text-[10px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                   <Activity className="w-3.5 h-3.5 text-indigo-500" /> Active Load Split
                 </span>
                 <div className="flex gap-4 h-16">
                    <div className="flex-1 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden">
                       <div className="absolute right-[-10px] bottom-[-10px] opacity-10 rotate-12"><CheckCircle2 className="w-12 h-12 text-emerald-500" /></div>
                       <span className="text-2xl font-black text-emerald-400 tabular-nums z-10">{greenWayCount}</span>
                       <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest z-10">VIA VERDE</span>
                    </div>
                    <div className="flex-1 bg-rose-500/10 border border-rose-500/20 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden">
                       <div className="absolute right-[-10px] bottom-[-10px] opacity-10 rotate-12"><Wrench className="w-12 h-12 text-rose-500" /></div>
                       <span className="text-2xl font-black text-rose-400 tabular-nums z-10">{repairHubCount}</span>
                       <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest z-10">RESOLUTION</span>
                    </div>
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-4 pb-8">
                 <div className="bg-slate-900/40 p-6 rounded-3xl border border-slate-800/50 flex flex-col items-center gap-2 hover:bg-slate-900/60 transition-colors cursor-pointer">
                    <Clock className="w-6 h-6 text-indigo-400" />
                    <span className="text-2xl font-black text-white tracking-tighter tabular-nums">{avgDwell}s</span>
                    <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Avg Resolution</span>
                 </div>
                 <div className="bg-slate-900/40 p-6 rounded-3xl border border-slate-800/50 flex flex-col items-center gap-2 hover:bg-slate-900/60 transition-colors cursor-pointer">
                    <TrendingUp className="w-6 h-6 text-emerald-400" />
                    <span className="text-2xl font-black text-white tracking-tighter tabular-nums">{stats.produced}</span>
                    <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Total Output</span>
                 </div>
              </div>
            </div>
          )}

          {activeTab === 'NODES' && (
            <div className="p-4 space-y-3 animate-in slide-in-from-left-4 duration-500 pb-10">
              <div className="relative group mb-6">
                <Search className="absolute left-4 top-3.5 w-4 h-4 text-slate-700 group-focus-within:text-indigo-500 transition-colors" />
                <input type="text" placeholder="FILTER PRODUCTION NODES..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/50 border border-slate-800 rounded-2xl py-3.5 pl-12 pr-4 text-[10px] font-black text-slate-300 focus:outline-none focus:border-indigo-500/50 placeholder:text-slate-700 uppercase tracking-widest" />
              </div>
              {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`p-5 rounded-3xl border-2 transition-all group flex items-center justify-between ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/30' : 'bg-slate-900/40 border-slate-900/50 hover:border-slate-800'}`}>
                   <div className="flex items-center gap-4">
                      <div className={`p-2.5 rounded-xl transition-colors ${hoveredStationId === s.id ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                         {s.type === StationType.TEST ? <FlaskConical className="w-4 h-4" /> : s.type === StationType.QUALITY ? <ShieldAlert className="w-4 h-4" /> : <MonitorDot className="w-4 h-4" />}
                      </div>
                      <div className="flex flex-col">
                         <span className={`text-[11px] font-black tracking-tight uppercase transition-colors ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-200'}`}>{s.name}</span>
                         <span className="text-[7px] font-bold text-slate-700 uppercase tracking-widest mt-0.5">{s.type} PHASE</span>
                      </div>
                   </div>
                   <ChevronRight className={`w-4 h-4 transition-all ${hoveredStationId === s.id ? 'text-indigo-500 translate-x-1' : 'text-slate-800'}`} />
                </div>
              ))}
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="p-6 space-y-6 animate-in slide-in-from-right-4 duration-500 pb-10">
               <div className="flex items-center justify-between">
                  <div className="flex flex-col">
                    <span className="text-[12px] font-black text-indigo-400 uppercase tracking-widest">Resolution Hub</span>
                    <span className="text-[7px] font-bold text-slate-600 uppercase tracking-widest">Active Repair Buffer</span>
                  </div>
                  <div className="flex items-center gap-2 px-3 py-1.5 bg-rose-500/10 rounded-xl text-[9px] font-black text-rose-500 border border-rose-500/20 shadow-lg shadow-rose-900/20">
                    <AlertCircle className="w-3 h-3" /> {repairHubCount} PENDING
                  </div>
               </div>
               <div className="space-y-5">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} onMouseEnter={() => setHoveredVehicleId(v.id)} onMouseLeave={() => setHoveredVehicleId(null)} className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-[2rem] flex flex-col gap-5 group hover:border-indigo-500/30 transition-all relative overflow-hidden">
                       <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/20 to-transparent" />
                       {v.failureType === 'LEAKAGE' && <Droplets className="absolute top-6 right-6 w-5 h-5 text-blue-500 animate-bounce" />}

                       <div className="flex items-center gap-5">
                          <div className="w-16 h-8 rounded-lg border border-slate-800 shadow-2xl transition-transform group-hover:scale-110" style={{ backgroundColor: v.color }} />
                          <div className="flex flex-col">
                             <span className="text-[12px] font-black text-slate-200 uppercase tracking-tight">UNIT_{v.id.toUpperCase()}</span>
                             <span className="text-[9px] font-bold text-indigo-500 uppercase tracking-[0.2em]">{v.workOrderId}</span>
                          </div>
                       </div>

                       <div className="grid grid-cols-2 gap-3">
                          <div className="bg-slate-950/60 p-4 rounded-2xl border border-slate-800/30 flex items-center gap-4 group/box hover:bg-slate-950 transition-colors">
                             <Timer className="w-4 h-4 text-indigo-400 group-hover/box:scale-110 transition-transform" />
                             <div className="flex flex-col">
                                <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Hub Lead Time</span>
                                <span className="text-[11px] font-black text-white tabular-nums">{(v.currentLeadTime/60).toFixed(0)}s</span>
                             </div>
                          </div>
                          <div className="bg-slate-950/60 p-4 rounded-2xl border border-slate-800/30 flex items-center gap-4 group/box hover:bg-slate-950 transition-colors">
                             <ShieldAlert className={`w-4 h-4 ${v.failureType === 'LEAKAGE' ? 'text-blue-500' : 'text-rose-500'} group-hover/box:scale-110 transition-transform`} />
                             <div className="flex flex-col">
                                <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Anomaly Class</span>
                                <span className="text-[11px] font-black text-white">{v.failureType}</span>
                             </div>
                          </div>
                       </div>

                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-4 bg-slate-800 text-slate-400 hover:text-white hover:bg-indigo-600 hover:shadow-[0_0_20px_rgba(79,70,229,0.5)] rounded-2xl transition-all text-[10px] font-black uppercase flex items-center justify-center gap-3 active:scale-[0.98]">
                         {v.pathIdx === 1 ? <ArrowRightCircle className="w-5 h-5" /> : <ShieldCheck className="w-5 h-5" />}
                         {v.pathIdx === 1 ? 'Dispatch to Spec-Area' : 'Finalize Resolution'}
                       </button>
                    </div>
                  ))}
                  {repairHubCount === 0 && (
                    <div className="py-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-800/50 rounded-[3rem] opacity-30 group hover:opacity-100 transition-opacity">
                       <CheckCircle2 className="w-16 h-16 text-emerald-500 mb-6 group-hover:scale-110 transition-transform" />
                       <span className="text-[11px] font-black tracking-[0.5em] uppercase text-slate-400">Logistics Hub Clear</span>
                    </div>
                  )}
               </div>
            </div>
          )}
        </div>

        <div className="p-8 border-t border-slate-900 bg-slate-950 shrink-0 space-y-5">
           <button onClick={unlockAll} className={`w-full py-5 rounded-2xl font-black text-[12px] uppercase border-2 transition-all active:scale-95 shadow-xl flex items-center justify-center gap-3 ${!isRunning || lockedVehicles.length > 0 ? 'bg-amber-500 text-slate-950 border-amber-400 shadow-amber-900/50' : 'bg-slate-900 text-amber-500/50 border-amber-500/10 hover:border-amber-500/30 hover:text-amber-500'}`}>
              <Key className="w-5 h-5" /> Master Gate Release
           </button>
           <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-4 rounded-2xl font-black text-[10px] uppercase border transition-all flex items-center justify-center gap-2 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20 hover:bg-slate-800' : 'bg-indigo-600 text-white border-indigo-400 shadow-lg shadow-indigo-900/40 hover:bg-indigo-500'}`}>
                 {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />}
                 {isRunning ? 'Halt Flow' : 'Resume Flow'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0}); addLog("KPI BUFFER RESET."); }} className="py-4 bg-slate-900 text-slate-600 border border-slate-800 rounded-2xl font-black text-[10px] uppercase hover:text-white hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                 <RotateCcw className="w-4 h-4" /> Reset KPI
              </button>
           </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_150px_rgba(0,0,0,1)] border-[20px] border-slate-950 bg-[#0f172a] rounded-[4rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const rect = canvasRef.current?.getBoundingClientRect();
              if (rect) mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale };
            }} className="cursor-crosshair" />
          </div>
        </div>
        <div className="h-14 bg-slate-950 border-t border-slate-900 flex items-center px-8 gap-8 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-2.5 shrink-0 z-20 text-indigo-500"><Terminal className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-[0.4em]">Node_Stream</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-24 animate-marquee py-1.5">
              {logs.map((log, i) => (
                <span key={i} className="text-[10px] font-bold text-slate-500 uppercase tracking-tight flex gap-4 items-center">
                  <div className="w-2 h-2 rounded-full bg-indigo-500/40 shadow-[0_0_10px_rgba(99,102,241,0.5)]" /> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export type FailureType = 'ELECTRICAL' | 'ELECTRONIC' | 'MECHANICAL' | 'LEAKAGE';
export type QualityStatus = 'NONE' | 'PASS' | 'FAIL';

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  baseColor: string;
  finished: boolean;
  progress: number;
  everRepaired: boolean;
  ignoreCollisionTimer: number;
  pendingRepairs: number;
  completedRepairs: number;
  initialRepairs: number;
  isLocked: boolean;
  failureType: FailureType | null;
  lastFailureType: FailureType | null;
  workOrderId: string | null;
  repairStartTime: number | null;
  currentLeadTime: number;
  faiStatus: QualityStatus;
  waterTestStatus: QualityStatus;
  finalInspectionStatus: QualityStatus;
  everEnteredWaitingArea: boolean;
  waitingAreaEntryCount: number;
  isFtrNegative: boolean;
  // Quality Flow specific
  viaVerde: boolean; // Remains true only if it never fails any gate
  repairCycleCount: number; // Tracks how many times it entered the hub
  inRetest: boolean; // Specifically for Water Test re-runs
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  totalStarted: number;
  passedFirstTime: number; // For FTT
  totalRepaired: number;
  repairAttempts: number;
  totalStagesCompleted: number;
  totalLeadTimeFrames: number;
  repairCompletedCount: number;
  ftrFails: number;
  ftrSuccesses: number; // Successfully repaired on 1st attempt
  categoryVolumes: Record<FailureType, number>;
  totalWaitAreaEntries: number;
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Cpu,
  CheckCircle2,
  Wrench,
  ShieldAlert,
  MonitorDot,
  TrendingUp,
  Settings2,
  Search,
  ArrowRightCircle,
  Terminal,
  Key,
  Timer,
  Droplets,
  ShieldCheck,
  BarChart,
  LayoutGrid,
  Info,
  Clock,
  History,
  AlertCircle,
  ChevronRight,
  Package
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, StationType, FailureType, QualityStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const FAILURE_TYPES: FailureType[] = ['ELECTRICAL', 'ELECTRONIC', 'MECHANICAL', 'LEAKAGE'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(480); // Scaled for visual density
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.26); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0,
    totalLeadTimeFrames: 0,
    repairCompletedCount: 0,
    ftrFails: 0,
    ftrSuccesses: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4'];
    return colors[Math.floor(Math.random() * colors.length)];
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 40;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      setScale(Math.max(0.15, s));
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false,
      failureType: null,
      lastFailureType: null,
      workOrderId: null,
      repairStartTime: null,
      currentLeadTime: 0,
      faiStatus: 'NONE',
      waterTestStatus: 'NONE',
      finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false,
      waitingAreaEntryCount: 0,
      isFtrNegative: false,
      viaVerde: true,
      repairCycleCount: 0,
      inRetest: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 120; 
      addLog(`MANUAL OVERRIDE: UNIT ${v.id.toUpperCase()} RELEASED`);
    }
  };

  const unlockAll = useCallback(() => {
    const affected = vehiclesRef.current.filter(v => v.isLocked || v.waitingTimer > 0);
    const count = affected.length;
    if (count > 0 || !isRunning) {
      vehiclesRef.current.forEach(v => {
        v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 180;
      });
      if (!isRunning) {
        setIsRunning(true);
        addLog(`MASTER RECOVERY: PRODUCTION FLOW RESUMED. ${count} UNITS RELEASED.`);
      } else {
        addLog(`COMMAND: RELEASE ALL GATES. ${count} UNITS MOVED.`);
      }
    }
  }, [isRunning]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.inRepair && v.repairStartTime !== null) {
        v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      }

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        if (v.viaVerde) {
          setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        }
        if (v.everRepaired && v.repairCycleCount === 1) {
          setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1 }));
        }
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`SHIPMENT: ${v.id.toUpperCase()} COMPLETED [${v.viaVerde ? 'VIA VERDE' : 'RECOVERY'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // QUALITY GATE LOGIC
        if (v.pathIdx === 22 && !v.inRepair) {
           const securityClear = v.faiStatus === 'PASS' && v.waterTestStatus === 'PASS' && v.finalInspectionStatus === 'PASS';
           if (!securityClear) {
             v.isLocked = true;
             addLog(`SECURITY BLOCK: UNIT ${v.id.toUpperCase()} REQUIRES VALIDATION.`);
           }
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          // ROUTING GATES
          const routeToRepair = (source: string, manualCategory?: FailureType) => {
            const cat = manualCategory || FAILURE_TYPES[Math.floor(Math.random() * FAILURE_TYPES.length)];
            v.viaVerde = false;
            v.inRepair = true;
            v.repairCycleCount++;
            v.failureType = cat;
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0; 
            v.color = COLORS.REPAIR;

            setStats(s => ({ 
              ...s, 
              defects: s.defects + 1,
              categoryVolumes: { ...s.categoryVolumes, [cat]: s.categoryVolumes[cat] + 1 },
              totalWaitAreaEntries: s.totalWaitAreaEntries + 1
            }));

            addLog(`${source}: UNIT ${v.id.toUpperCase()} -> RESOLUTION AREA [${cat}]`);
          };

          if (station.name === 'FAI QC') {
            if (v.hasDefect && v.faiStatus !== 'PASS') {
              v.faiStatus = 'FAIL';
              routeToRepair('FAI QC');
            } else {
              v.faiStatus = 'PASS';
            }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (Math.random() < 0.15 && v.waterTestStatus !== 'PASS') {
              v.waterTestStatus = 'FAIL';
              routeToRepair('WATER TEST', 'LEAKAGE');
            } else {
              v.waterTestStatus = 'PASS';
              v.inRetest = false;
            }
          }

          if (station.name === 'Flat Top') {
            if (v.hasDefect && Math.random() < 0.3) {
              v.finalInspectionStatus = 'FAIL';
              routeToRepair('FLAT TOP');
            } else {
              v.finalInspectionStatus = 'PASS';
            }
          }

          // REPAIR HUB STEERING
          if (station.name === 'Waiting Area') {
            if (v.failureType === 'LEAKAGE') v.pathIdx = 2; // Leakage Cell
            else if (v.failureType === 'ELECTRICAL' || v.failureType === 'ELECTRONIC') v.pathIdx = 3; // Elec Repair
            else v.pathIdx = 1; // Mec Repair
          }

          // HUB EXIT PROTOCOL
          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false;
            v.isRepaired = true;
            v.color = v.baseColor;

            const elapsed = frameCountRef.current - (v.repairStartTime || 0);
            setStats(s => ({ ...s, totalLeadTimeFrames: s.totalLeadTimeFrames + elapsed, repairCompletedCount: s.repairCompletedCount + 1 }));

            if (v.failureType === 'LEAKAGE') {
              v.waterTestStatus = 'NONE';
              v.inRetest = true;
              v.targetPath = [...MAIN_PATH_POINTS];
              v.pathIdx = 18; // Pre-Water Test
              addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> MANDATORY WATER RE-TEST`);
            } else {
              v.finalInspectionStatus = 'NONE';
              v.targetPath = [...MAIN_PATH_POINTS];
              v.pathIdx = 10; // Pre-Flat Top
              addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> FINAL VALIDATION`);
            }
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Conveyor system
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 24));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#1a0505', 30);

    // Station Rendering
    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 42; const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE', prog = 0;
      if (v) {
        if (v.waitingTimer > 0) { status = 'PROCESSING'; prog = 1 - (v.waitingTimer / s.wait); }
        else status = 'OCCUPIED';
      }
      ctx.strokeStyle = (hoveredStationId === s.id) ? '#6366f1' : 'rgba(255,255,255,0.06)'; 
      ctx.lineWidth = (hoveredStationId === s.id) ? 3 : 1; ctx.fillStyle = 'rgba(15, 23, 42, 0.98)'; 
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 8); ctx.fill(); ctx.stroke();
      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#fbbf24' : '#334155');
      ctx.beginPath(); ctx.arc(x + 14, y + 14, 5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 9px Inter'; ctx.fillText(s.name.toUpperCase(), x + 24, y + 18);
      if (status === 'PROCESSING') { ctx.fillStyle = 'rgba(255,255,255,0.04)'; ctx.fillRect(x + 6, y + h - 8, w - 12, 4); ctx.fillStyle = '#10b981'; ctx.fillRect(x + 6, y + h - 8, (w - 12) * prog, 4); }
    });

    // Vehicle Rendering
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 5); ctx.fill();
      if (v.viaVerde && !v.inRepair) {
        ctx.globalCompositeOperation = 'source-over'; ctx.strokeStyle = '#10b981'; ctx.lineWidth = 2; ctx.strokeRect(-18, -9, 36, 18);
      }
      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over'; ctx.fillStyle = 'white'; ctx.font = 'bold 8px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(v.workOrderId || '', 0, 3);
        else { ctx.save(); ctx.rotate(-v.rotation); ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(0, -18, 6, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)'; ctx.font = '900 32px Inter'; ctx.fillText('VPH_500_AUTO_FLOW', 60, 60);
  }, [hoveredStationId]);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const avgDwell = stats.repairCompletedCount > 0 ? (stats.totalLeadTimeFrames / stats.repairCompletedCount / 60).toFixed(1) : "0.0";
  const greenWayCount = vehiclesRef.current.filter(v => v.viaVerde && !v.inRepair).length;
  const repairHubCount = vehiclesRef.current.filter(v => v.inRepair).length;
  const retestCount = vehiclesRef.current.filter(v => v.inRetest).length;
  const lockedCount = vehiclesRef.current.filter(v => v.isLocked).length;

  const paretoData = useMemo(() => {
    return FAILURE_TYPES.map(type => ({
      type,
      total: stats.categoryVolumes[type]
    })).sort((a, b) => b.total - a.total);
