                          </div>
                       </div>
                    ))}
                 </div>
              </div>

              <div className="bg-slate-900/40 p-6 rounded-[2.5rem] border border-slate-800/50 space-y-4">
                 <span className="text-[11px] font-black text-white uppercase tracking-widest flex items-center gap-3">
                   <Activity className="w-4 h-4 text-indigo-500" /> Load Distribution
                 </span>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-3xl p-5 flex flex-col items-center justify-center relative overflow-hidden group">
