               <div className="space-y-6">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-[2.5rem] flex flex-col gap-5 group hover:border-indigo-500/30 transition-all relative overflow-hidden">
                       <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/30 to-transparent" />
                       {v.failureType === 'LEAKAGE' && <Droplets className="absolute top-6 right-8 w-5 h-5 text-blue-500 animate-bounce" />}

                       <div className="flex items-center gap-5">
                          <div className="w-16 h-8 rounded-xl border border-slate-800 shadow-2xl transition-transform group-hover:scale-110" style={{ backgroundColor: v.color }} />
