              </div>

              <div className="bg-slate-900/40 p-6 rounded-[2.5rem] border border-slate-800/50 space-y-6">
                 <div className="flex justify-between items-center">
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em]">Loss Drivers (Pareto)</span>
                    <History className="w-4 h-4 text-slate-700" />
