                 <div className="space-y-5">
                    {paretoData.map(cat => (
                       <div key={cat.type} className="space-y-1.5">
                          <div className="flex justify-between text-[8px] font-black uppercase tracking-tighter text-slate-500">
                             <span>{cat.type}</span>
                             <span className="text-slate-300 tabular-nums">{cat.total} UNITS</span>
                          </div>
                          <div className="w-full h-2 bg-slate-950 rounded-full overflow-hidden flex border border-slate-900/50">
                             <div className={`h-full transition-all duration-1000 ${cat.type === 'LEAKAGE' ? 'bg-blue-500' : cat.type === 'ELECTRICAL' ? 'bg-rose-500' : 'bg-amber-500'}`} style={{ width: `${stats.defects > 0 ? (cat.total / stats.defects) * 100 : 0}%` }} />
                          </div>
                       </div>
                    ))}
                 </div>
              </div>
            </div>
