          {activeTab === 'QUALITY' && (
            <div className="p-8 space-y-6 pb-16">
               <div className="flex items-center justify-between">
                  <div className="flex flex-col">
                    <span className="text-[13px] font-black text-indigo-400 uppercase tracking-widest">Active SO Buffer</span>
                    <span className="text-[8px] font-bold text-slate-600 uppercase tracking-widest">Resolution Queue</span>
                  </div>
                  <div className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 rounded-2xl text-[10px] font-black text-rose-500 border border-rose-500/20">
                    <AlertCircle className="w-4 h-4" /> {repairHubCount} PENDING
                  </div>
               </div>
               <div className="space-y-6">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-[2.5rem] flex flex-col gap-5 relative overflow-hidden group">
                       <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/30 to-transparent" />
