                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-4 bg-slate-800 text-slate-400 hover:text-white hover:bg-indigo-600 rounded-2xl transition-all text-[11px] font-black uppercase flex items-center justify-center gap-3 active:scale-[0.98]">
                         {v.pathIdx === 1 ? <ArrowRightCircle className="w-5 h-5" /> : <ShieldCheck className="w-5 h-5" />}
