             <div className="p-6 space-y-4 pb-20">
               <div className="relative group mb-8">
                 <Search className="absolute left-5 top-4 w-5 h-5 text-slate-700" />
                 <input type="text" placeholder="FILTER NETWORK..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/50 border border-slate-800 rounded-3xl py-4.5 pl-14 pr-6 text-[11px] font-black text-slate-300 focus:outline-none focus:border-indigo-500/50 uppercase tracking-widest" />
               </div>
               {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                 <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`p-6 rounded-[2rem] border-2 transition-all group flex items-center justify-between ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/30' : 'bg-slate-900/30 border-slate-900/50'}`}>
                    <div className="flex items-center gap-5">
                       <div className={`p-3 rounded-2xl ${hoveredStationId === s.id ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                          <MonitorDot className="w-5 h-5" />
                       </div>
                       <div className="flex flex-col">
                          <span className={`text-[12px] font-black transition-colors ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-100'}`}>{s.name.toUpperCase()}</span>
                          <span className="text-[8px] font-bold text-slate-600 uppercase tracking-widest mt-1">{s.type} PHASE</span>
                       </div>
                    </div>
                    <ChevronRight className={`w-5 h-5 transition-transform ${hoveredStationId === s.id ? 'text-indigo-500 translate-x-1' : 'text-slate-800'}`} />
                 </div>
               ))}
             </div>
          )}
        </div>

        <div className="p-10 border-t border-slate-900 bg-slate-950 shrink-0 space-y-6">
           <button onClick={unlockAll} className={`w-full py-5 rounded-[2rem] font-black text-[13px] uppercase border-2 transition-all active:scale-95 shadow-xl flex items-center justify-center gap-4 ${!isRunning || vehiclesRef.current.some(v=>v.isLocked) ? 'bg-amber-500 text-slate-950 border-amber-400 shadow-amber-900/40' : 'bg-slate-900 text-amber-500/50 border-amber-500/10 hover:border-amber-500/40 hover:text-amber-500'}`}>
              <Key className="w-6 h-6" /> System Recovery Override
           </button>
           <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-4.5 rounded-2xl font-black text-[11px] uppercase border transition-all flex items-center justify-center gap-2 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20 hover:bg-slate-800' : 'bg-indigo-600 text-white border-indigo-400 shadow-lg shadow-indigo-900/40'}`}>
                 {isRunning ? <Pause className="w-5 h-5" /> : <Play className="w-5 h-5 fill-current" />}
                 {isRunning ? 'Halt Flow' : 'Resume Flow'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0,rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); addLog("KPI BUFFER CLEARED."); }} className="py-4.5 bg-slate-900 text-slate-600 border border-slate-800 rounded-2xl font-black text-[11px] uppercase hover:text-white hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                 <RotateCcw className="w-5 h-5" /> Reset KPIs
              </button>
           </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.7s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_150px_rgba(0,0,0,1)] border-[24px] border-slate-950 bg-[#0f172a] rounded-[5rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const rect = canvasRef.current?.getBoundingClientRect();
              if (rect) mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale };
            }} className="cursor-crosshair" />
          </div>
        </div>
        <div className="h-16 bg-slate-950 border-t border-slate-900 flex items-center px-10 gap-10 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-3 shrink-0 z-20 text-indigo-500"><Terminal className="w-5 h-5" /><span className="text-[11px] font-black uppercase tracking-[0.4em]">Logistics_Stream</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-24 animate-marquee py-2">
              {logs.map((log, i) => (
                <span key={i} className="text-[11px] font-bold text-slate-500 uppercase tracking-tight flex gap-5 items-center">
                  <div className="w-2.5 h-2.5 rounded-full bg-indigo-500/40 shadow-[0_0_12px_rgba(99,102,241,0.6)]" /> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Cpu,
  CheckCircle2,
  Wrench,
  ShieldAlert,
  MonitorDot,
  TrendingUp,
  Settings2,
  Search,
  ArrowRightCircle,
  Terminal,
  Key,
  Timer,
  Droplets,
  ShieldCheck,
  BarChart,
  LayoutGrid,
  Info,
  Clock,
  History,
  AlertCircle,
  ChevronRight,
  Package,
  Gauge,
  Zap,
  ActivitySquare,
  AlertTriangle
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, StationType, FailureType, QualityStatus, RollFailureType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const FAILURE_TYPES: FailureType[] = ['ELECTRICAL', 'ELECTRONIC', 'MECHANICAL', 'LEAKAGE'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(480); 
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.24); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0,
    totalLeadTimeFrames: 0,
    repairCompletedCount: 0,
    ftrFails: 0,
    ftrSuccesses: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0,
    rollTestProcessed: 0,
    ecatsFailures: 0,
    velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4'];
    return colors[Math.floor(Math.random() * colors.length)];
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 40;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      setScale(Math.max(0.15, s));
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false,
      failureType: null,
      lastFailureType: null,
      workOrderId: null,
      repairStartTime: null,
      currentLeadTime: 0,
      faiStatus: 'NONE',
      waterTestStatus: 'NONE',
      finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false,
      waitingAreaEntryCount: 0,
      isFtrNegative: false,
      viaVerde: true,
      repairCycleCount: 0,
      inRetest: false,
      rollTestStatus: 'NONE',
      rollTestFailType: null,
      assignedCabinId: null
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 120; 
      addLog(`MANUAL OVERRIDE: UNIT ${v.id.toUpperCase()} RELEASED`);
    }
  };

  const unlockAll = useCallback(() => {
    const affected = vehiclesRef.current.filter(v => v.isLocked || v.waitingTimer > 0);
    const count = affected.length;
    if (count > 0 || !isRunning) {
      vehiclesRef.current.forEach(v => {
        v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 180;
      });
      if (!isRunning) {
        setIsRunning(true);
        addLog(`MASTER RECOVERY: PRODUCTION FLOW RESUMED. ${count} UNITS RELEASED.`);
      } else {
        addLog(`COMMAND: RELEASE ALL GATES. ${count} UNITS MOVED.`);
      }
    }
  }, [isRunning]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.inRepair && v.repairStartTime !== null) {
        v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      }

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        if (v.viaVerde) {
          setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        }
        if (v.everRepaired && v.repairCycleCount === 1) {
          setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1 }));
        }
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`SHIPMENT: ${v.id.toUpperCase()} COMPLETED [${v.viaVerde ? 'VIA VERDE' : 'RECOVERY'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        // --- ROLL TEST CABIN ALLOCATION (Strict 1-per-cabin) ---
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableCabinIndex = [0, 1, 2].find(idx => {
                const cabinId = PARALLEL_ROLL_STATIONS[idx].id;
                return !currentVehicles.some(other => other.assignedCabinId === cabinId);
            });

            if (availableCabinIndex !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableCabinIndex].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableCabinIndex], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0; 
                addLog(`ALLOCATION: UNIT ${v.id.toUpperCase()} -> ROLL CABIN ${availableCabinIndex + 1}`);
            } else {
                v.pathIdx--; 
                continue;
            }
        }

        // --- MERGE POINT CLEANUP ---
        if (v.assignedCabinId && v.pos.x === MAIN_PATH_POINTS[MERGE_POINT_IDX].x && v.pos.y === MAIN_PATH_POINTS[MERGE_POINT_IDX].y) {
           v.assignedCabinId = null;
        }

        // --- FINAL SHIPMENT SECURITY GATE ---
        if (v.pathIdx === 22 && !v.inRepair) {
           const securityClear = v.faiStatus === 'PASS' && v.waterTestStatus === 'PASS' && v.finalInspectionStatus === 'PASS' && v.rollTestStatus === 'PASS';
           if (!securityClear) {
             v.isLocked = true;
             addLog(`SECURITY ALERT: UNIT ${v.id.toUpperCase()} BLOCKED FOR FINAL AUDIT.`);
           }
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const routeToRepair = (source: string, manualCategory?: FailureType) => {
            const cat = manualCategory || FAILURE_TYPES[Math.floor(Math.random() * FAILURE_TYPES.length)];
            v.viaVerde = false;
            v.inRepair = true;
            v.repairCycleCount++;
            v.failureType = cat;
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0; 
            v.color = COLORS.REPAIR;
            v.assignedCabinId = null; 

            setStats(s => ({ 
              ...s, 
              defects: s.defects + 1,
              categoryVolumes: { ...s.categoryVolumes, [cat]: s.categoryVolumes[cat] + 1 },
              totalWaitAreaEntries: s.totalWaitAreaEntries + 1
            }));

            addLog(`${source}: UNIT ${v.id.toUpperCase()} FAILED. REDIRECT TO BUFFER [${cat}]`);
          };

          if (station.name === 'FAI QC') {
            if (v.hasDefect && v.faiStatus !== 'PASS') {
              v.faiStatus = 'FAIL';
              routeToRepair('FAI QC');
            } else {
              v.faiStatus = 'PASS';
            }
          }

          if (station.name.startsWith('Teste Rolo')) {
             // PROTOCOL: ECATS -> 0-100 ACCEL -> BRAKING
             const isDefectiveInRoll = v.hasDefect && Math.random() < 0.22;
             if (isDefectiveInRoll) {
                const rollFailType: RollFailureType = Math.random() < 0.45 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL';
                v.rollTestFailType = rollFailType;

                if (rollFailType === 'ECATS') {
                   setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 }));
                   routeToRepair('ROLL TEST (ECATS)', 'ELECTRONIC');
                } else {
                   setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 }));
                   routeToRepair('ROLL TEST (0-100)', 'MECHANICAL');
                }
             } else {
                v.rollTestStatus = 'PASS';
                setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 }));
                addLog(`ROLL VALIDATION: ${v.id.toUpperCase()} PASSED (ECATS/0-100/BRAKE).`);
             }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (Math.random() < 0.12 && v.waterTestStatus !== 'PASS') {
              v.waterTestStatus = 'FAIL';
              routeToRepair('WATER TEST', 'LEAKAGE');
            } else {
              v.waterTestStatus = 'PASS';
              v.inRetest = false;
            }
          }

          if (station.name === 'Flat Top') {
            if (v.hasDefect && Math.random() < 0.28) {
              v.finalInspectionStatus = 'FAIL';
              routeToRepair('FLAT TOP GATE');
            } else {
              v.finalInspectionStatus = 'PASS';
            }
          }

          if (station.name === 'Waiting Area') {
            if (v.failureType === 'LEAKAGE') v.pathIdx = 2; 
            else if (v.failureType === 'ELECTRICAL' || v.failureType === 'ELECTRONIC') v.pathIdx = 3; 
            else v.pathIdx = 1; 
          }

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false;
            v.isRepaired = true;
            v.color = v.baseColor;

            const elapsed = frameCountRef.current - (v.repairStartTime || 0);
            setStats(s => ({ ...s, totalLeadTimeFrames: s.totalLeadTimeFrames + elapsed, repairCompletedCount: s.repairCompletedCount + 1 }));

            if (v.failureType === 'LEAKAGE') {
              v.waterTestStatus = 'NONE';
              v.inRetest = true;

              // COMPLEX REPAIR LOGIC: 25% chance leak fix affects electronics/brakes -> Redo Roll Test
              const isComplex = Math.random() < 0.25;
              if (isComplex) {
                 v.rollTestStatus = 'NONE';
                 v.targetPath = [...MAIN_PATH_POINTS];
                 v.pathIdx = 10; // Back to pre-roll test sequence
                 addLog(`COMPLEX REPAIR: UNIT ${v.id.toUpperCase()} REQUIRES FULL RE-TEST (ROLL + WATER).`);
              } else {
                 v.targetPath = [...MAIN_PATH_POINTS];
                 v.pathIdx = 18; 
                 addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> WATER RE-TEST ONLY.`);
              }
            } else {
              v.finalInspectionStatus = 'NONE';
              v.targetPath = [...MAIN_PATH_POINTS];
              v.pathIdx = 10; 
              addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> FINAL GATE VALIDATION.`);
            }
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 24));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#1a0505', 30);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 42; const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE', prog = 0;
      if (v) {
        if (v.waitingTimer > 0) { status = 'PROCESSING'; prog = 1 - (v.waitingTimer / s.wait); }
        else status = 'OCCUPIED';
      }

      const isRollTest = s.name.startsWith('Teste Rolo');
      const isFailing = isRollTest && v && v.rollTestStatus === 'FAIL';

      ctx.strokeStyle = isFailing ? '#ef4444' : (hoveredStationId === s.id ? '#6366f1' : 'rgba(255,255,255,0.06)'); 
      ctx.lineWidth = (hoveredStationId === s.id || isFailing) ? 3 : 1; ctx.fillStyle = 'rgba(15, 23, 42, 0.98)'; 

      if (isFailing) {
          ctx.shadowBlur = 15;
          ctx.shadowColor = '#ef4444';
      }

      ctx.beginPath(); ctx.roundRect(x, y, w, h, 8); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#fbbf24' : '#334155');
      ctx.beginPath(); ctx.arc(x + 14, y + 14, 5, 0, Math.PI * 2); ctx.fill();

      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 9px Inter'; ctx.fillText(s.name.toUpperCase(), x + 24, y + 18);
      if (status === 'PROCESSING') { ctx.fillStyle = 'rgba(255,255,255,0.04)'; ctx.fillRect(x + 6, y + h - 8, w - 12, 4); ctx.fillStyle = '#10b981'; ctx.fillRect(x + 6, y + h - 8, (w - 12) * prog, 4); }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 5); ctx.fill();
      if (v.viaVerde && !v.inRepair) {
        ctx.globalCompositeOperation = 'source-over'; ctx.strokeStyle = '#10b981'; ctx.lineWidth = 2; ctx.strokeRect(-18, -9, 36, 18);
      }
      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over'; ctx.fillStyle = 'white'; ctx.font = 'bold 8px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(v.workOrderId || '', 0, 3);
        else { ctx.save(); ctx.rotate(-v.rotation); ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(0, -18, 6, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }
      }
      ctx.restore();
    });

    ctx.fillStyle = 'rgba(255, 255, 255, 0.25)'; ctx.font = '900 34px Inter'; ctx.fillText('VPD_500_LOGISTICS_HUB', 60, 60);
  }, [hoveredStationId]);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const greenWayCount = vehiclesRef.current.filter(v => v.viaVerde && !v.inRepair).length;
  const repairHubCount = vehiclesRef.current.filter(v => v.inRepair).length;
  const retestCount = vehiclesRef.current.filter(v => v.inRetest).length;
  const dailyProgress = (stats.produced / 500) * 100;

  const cabinsOccupancy = useMemo(() => {
    return [0, 1, 2].map(idx => {
       const cabinId = PARALLEL_ROLL_STATIONS[idx].id;
       const v = vehiclesRef.current.find(veh => veh.assignedCabinId === cabinId);
       return { id: cabinId, occupied: !!v, vehicle: v };
    });
  }, [stats.active]);

  const paretoData = useMemo(() => {
    return FAILURE_TYPES.map(type => ({
      type,
      total: stats.categoryVolumes[type]
    })).sort((a, b) => b.total - a.total);
  }, [stats.categoryVolumes]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
      <aside className="w-[420px] lg:w-[480px] bg-slate-950 border-r border-slate-900 flex flex-col shadow-2xl shrink-0 z-20">
        <div className="p-8 border-b border-slate-900 shrink-0 space-y-7">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-600 rounded-2xl shadow-lg shadow-indigo-900/30"><Cpu className="w-5 h-5 text-white" /></div>
              <div className="flex flex-col">
                <h1 className="text-[12px] font-black tracking-[0.4em] uppercase text-indigo-400">FACTORY_PRO v5.5</h1>
                <span className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Efficiency Meta: 500 VPD</span>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border text-[9px] font-black uppercase ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-rose-500/10 border-rose-500/20 text-rose-400'}`}>
               <div className={`w-1.5 h-1.5 rounded-full ${isRunning ? 'bg-emerald-400' : 'bg-rose-400'}`} />
               {isRunning ? 'System Active' : 'Emergency Halt'}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center text-[10px] font-black uppercase text-slate-500">
               <span className="flex items-center gap-2"><TrendingUp className="w-3.5 h-3.5" /> Production Progress</span>
               <span className="text-white tabular-nums">{stats.produced} / 500</span>
            </div>
            <div className="w-full h-3 bg-slate-900 rounded-full overflow-hidden border border-slate-800 p-0.5">
               <div className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full transition-all duration-1000 shadow-[0_0_15px_rgba(99,102,241,0.5)]" style={{ width: `${Math.min(100, dailyProgress)}%` }} />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="bg-slate-900/30 p-5 rounded-[2rem] border border-slate-800/50 flex flex-col items-center group transition-all hover:bg-slate-900/50">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1">FTT (FIRST TIME)</span>
                <span className={`text-3xl font-black tabular-nums tracking-tighter ${fttRate > 85 ? 'text-emerald-400' : 'text-amber-400'}`}>{fttRate.toFixed(1)}%</span>
             </div>
             <div className="bg-slate-900/30 p-5 rounded-[2rem] border border-slate-800/50 flex flex-col items-center group transition-all hover:bg-slate-900/50">
                <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest mb-1">FTR (RESOLUTION)</span>
                <span className={`text-3xl font-black tabular-nums tracking-tighter ${ftrRate > 90 ? 'text-indigo-400' : 'text-amber-400'}`}>{ftrRate.toFixed(1)}%</span>
             </div>
          </div>
        </div>

        <div className="flex border-b border-slate-900 bg-slate-950 shrink-0">
          {[
            { id: 'KPI', label: 'Dashboard', icon: <BarChart className="w-4 h-4" /> },
            { id: 'QUALITY', label: 'Resolution', icon: <ShieldAlert className="w-4 h-4" /> },
            { id: 'NODES', label: 'Topology', icon: <LayoutGrid className="w-4 h-4" /> }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as DashboardTab)} className={`flex-1 flex items-center justify-center gap-2 py-4 text-[10px] font-black uppercase tracking-widest transition-all relative ${activeTab === tab.id ? 'text-indigo-400 bg-indigo-500/5' : 'text-slate-600 hover:text-slate-400 hover:bg-slate-900/40'}`}>
              {tab.icon} {tab.label}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-1 bg-indigo-500 shadow-[0_-2px_15px_rgba(99,102,241,0.6)]" />}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {activeTab === 'KPI' && (
            <div className="p-6 space-y-8 pb-10">
              <div className="bg-slate-900/40 p-6 rounded-[2.5rem] border border-slate-800/50 space-y-5">
                 <div className="flex justify-between items-center">
                    <span className="text-[11px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                       <ActivitySquare className="w-4 h-4 text-amber-500" /> Roll Cabin Status
                    </span>
                    <span className="text-[8px] font-bold text-slate-600 uppercase tracking-widest">3 Active Bays</span>
                 </div>
                 <div className="grid grid-cols-3 gap-3">
                    {cabinsOccupancy.map((cabin, i) => (
                       <div key={cabin.id} className={`flex flex-col items-center justify-center p-4 rounded-2xl border transition-all ${cabin.occupied ? 'bg-amber-500/10 border-amber-500/30 shadow-lg shadow-amber-900/10' : 'bg-slate-950/40 border-slate-800'}`}>
                          <Gauge className={`w-6 h-6 mb-2 ${cabin.occupied ? 'text-amber-400' : 'text-slate-800'}`} />
                          <span className={`text-[8px] font-black uppercase tracking-widest ${cabin.occupied ? 'text-amber-400' : 'text-slate-600'}`}>BAY {i+1}</span>
                          <span className={`text-[9px] font-black mt-1 ${cabin.occupied ? 'text-white animate-pulse' : 'text-slate-800'}`}>{cabin.occupied ? 'TESTING' : 'READY'}</span>
                       </div>
                    ))}
                 </div>
              </div>

              <div className="bg-slate-900/40 p-6 rounded-[2.5rem] border border-slate-800/50 space-y-5">
                 <div className="flex justify-between items-center">
                    <span className="text-[11px] font-black text-white uppercase tracking-widest flex items-center gap-2">
                       <Zap className="w-4 h-4 text-indigo-500" /> Roll Failure Breakdown
                    </span>
                    <Package className="w-4 h-4 text-slate-700" />
                 </div>
                 <div className="flex h-12 bg-slate-950 rounded-2xl border border-slate-800 overflow-hidden p-1 shadow-inner">
                    <div className="h-full bg-indigo-500/90 transition-all duration-1000 flex items-center justify-center text-[9px] font-black rounded-l-xl border-r border-slate-900" style={{ width: `${stats.ecatsFailures + stats.velocityFailures > 0 ? (stats.ecatsFailures / (stats.ecatsFailures + stats.velocityFailures)) * 100 : 50}%` }}>
                       {stats.ecatsFailures > 0 && `${stats.ecatsFailures}`}
                    </div>
                    <div className="h-full bg-amber-500/90 transition-all duration-1000 flex items-center justify-center text-[9px] font-black text-slate-950 rounded-r-xl" style={{ width: `${stats.ecatsFailures + stats.velocityFailures > 0 ? (stats.velocityFailures / (stats.ecatsFailures + stats.velocityFailures)) * 100 : 50}%` }}>
                       {stats.velocityFailures > 0 && `${stats.velocityFailures}`}
                    </div>
                 </div>
                 <div className="flex justify-between px-2">
                    <div className="flex items-center gap-2 text-[8px] font-black uppercase text-slate-500">
                       <div className="w-2 h-2 rounded-full bg-indigo-500" /> ECATS Failure
                    </div>
                    <div className="flex items-center gap-2 text-[8px] font-black uppercase text-slate-500">
                       <div className="w-2 h-2 rounded-full bg-amber-500" /> Velocity (0-100)
                    </div>
                 </div>
              </div>

              <div className="bg-slate-900/40 p-6 rounded-[2.5rem] border border-slate-800/50 space-y-6">
                 <div className="flex justify-between items-center">
                    <span className="text-[11px] font-black text-white uppercase tracking-widest">Global Loss Pareto</span>
                    <History className="w-4 h-4 text-slate-700" />
                 </div>
                 <div className="space-y-5">
                    {paretoData.map(cat => (
                       <div key={cat.type} className="space-y-1.5">
                          <div className="flex justify-between text-[8px] font-black uppercase tracking-tighter text-slate-500">
                             <span>{cat.type}</span>
                             <span className="text-slate-300 tabular-nums">{cat.total} UNITS</span>
                          </div>
                          <div className="w-full h-2 bg-slate-950 rounded-full overflow-hidden flex border border-slate-900/50">
                             <div className={`h-full transition-all duration-1000 ${cat.type === 'LEAKAGE' ? 'bg-blue-500' : cat.type === 'ELECTRICAL' ? 'bg-rose-500' : 'bg-amber-500'}`} style={{ width: `${stats.defects > 0 ? (cat.total / stats.defects) * 100 : 0}%` }} />
                          </div>
                       </div>
                    ))}
                 </div>
              </div>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="p-8 space-y-6 pb-16">
               <div className="flex items-center justify-between">
                  <div className="flex flex-col">
                    <span className="text-[13px] font-black text-indigo-400 uppercase tracking-widest">Anomaly Buffer</span>
                    <span className="text-[8px] font-bold text-slate-600 uppercase tracking-widest">SO Priority Queue</span>
                  </div>
                  <div className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 rounded-2xl text-[10px] font-black text-rose-500 border border-rose-500/20">
                    <AlertCircle className="w-4 h-4" /> {repairHubCount} PENDING
                  </div>
               </div>
               <div className="space-y-6">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="bg-slate-900/40 border border-slate-800/50 p-6 rounded-[2.5rem] flex flex-col gap-5 relative overflow-hidden group hover:border-indigo-500/30 transition-all">
                       <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-indigo-500/30 to-transparent" />
                       <div className="flex items-center gap-5">
                          <div className="w-16 h-8 rounded-xl border border-slate-800 shadow-2xl transition-transform group-hover:scale-105" style={{ backgroundColor: v.color }} />
                          <div className="flex flex-col">
                             <span className="text-[13px] font-black text-slate-200 uppercase tracking-tight">UNIT_{v.id.toUpperCase()}</span>
                             <span className="text-[9px] font-bold text-indigo-500 uppercase tracking-[0.2em]">{v.workOrderId}</span>
                          </div>
                       </div>

                       <div className="grid grid-cols-2 gap-4">
                          <div className="bg-slate-950/60 p-4 rounded-3xl border border-slate-800/30 flex items-center gap-4 group/item hover:bg-slate-950 transition-colors">
                             <Timer className="w-5 h-5 text-indigo-400 group-hover/item:scale-110 transition-transform" />
                             <div className="flex flex-col">
                                <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Cycle Delay</span>
                                <span className="text-[12px] font-black text-white tabular-nums">{(v.currentLeadTime/60).toFixed(0)}s</span>
                             </div>
                          </div>
                          <div className="bg-slate-950/60 p-4 rounded-3xl border border-slate-800/30 flex items-center gap-4 group/item hover:bg-slate-950 transition-colors">
                             <ShieldAlert className={`w-5 h-5 ${v.failureType === 'LEAKAGE' ? 'text-blue-500' : 'text-rose-500'} group-hover/item:scale-110 transition-transform`} />
                             <div className="flex flex-col">
                                <span className="text-[7px] font-black text-slate-600 uppercase tracking-widest">Defect Type</span>
                                <span className="text-[12px] font-black text-white uppercase">{v.failureType}</span>
                             </div>
                          </div>
                       </div>

                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-4.5 bg-slate-800 text-slate-400 hover:text-white hover:bg-indigo-600 hover:shadow-lg shadow-indigo-900/30 rounded-2xl transition-all text-[11px] font-black uppercase flex items-center justify-center gap-3 active:scale-[0.98]">
                         {v.pathIdx === 1 ? <ArrowRightCircle className="w-5 h-5" /> : <ShieldCheck className="w-5 h-5" />}
                         {v.pathIdx === 1 ? 'Dispatch to Spec Area' : 'Verify Resolution'}
                       </button>
                    </div>
                  ))}
                  {repairHubCount === 0 && (
                    <div className="py-24 flex flex-col items-center justify-center border-2 border-dashed border-slate-800/50 rounded-[3rem] opacity-30">
                       <CheckCircle2 className="w-16 h-16 text-emerald-500 mb-6" />
                       <span className="text-[12px] font-black tracking-[0.6em] uppercase text-slate-400">Hub is Clear</span>
                    </div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'NODES' && (
             <div className="p-6 space-y-4 pb-20">
               <div className="relative group mb-8">
                 <Search className="absolute left-5 top-4 w-5 h-5 text-slate-700 focus-within:text-indigo-500" />
                 <input type="text" placeholder="FILTER NETWORK NODES..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/50 border border-slate-800 rounded-3xl py-4.5 pl-14 pr-6 text-[11px] font-black text-slate-300 focus:outline-none focus:border-indigo-500/50 uppercase tracking-widest" />
               </div>
               {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                 <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`p-6 rounded-[2rem] border-2 transition-all group flex items-center justify-between ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/30' : 'bg-slate-900/30 border-slate-900/50 hover:bg-slate-900/50'}`}>
                    <div className="flex items-center gap-5">
                       <div className={`p-3 rounded-2xl transition-colors ${hoveredStationId === s.id ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                          <MonitorDot className="w-5 h-5" />
                       </div>
                       <div className="flex flex-col">
                          <span className={`text-[12px] font-black transition-colors ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-100'}`}>{s.name.toUpperCase()}</span>
                          <span className="text-[8px] font-bold text-slate-600 uppercase tracking-widest mt-1">{s.type} PHASE</span>
                       </div>
                    </div>
                    <ChevronRight className={`w-5 h-5 transition-transform ${hoveredStationId === s.id ? 'text-indigo-500 translate-x-1' : 'text-slate-800'}`} />
                 </div>
               ))}
             </div>
          )}
        </div>

        <div className="p-10 border-t border-slate-900 bg-slate-950 shrink-0 space-y-6">
           <button onClick={unlockAll} className={`w-full py-5 rounded-[2rem] font-black text-[13px] uppercase border-2 transition-all active:scale-95 shadow-xl flex items-center justify-center gap-4 ${!isRunning || vehiclesRef.current.some(v=>v.isLocked) ? 'bg-amber-500 text-slate-950 border-amber-400 shadow-amber-900/40' : 'bg-slate-900 text-amber-500/50 border-amber-500/10 hover:border-amber-500/40 hover:text-amber-500'}`}>
              <Key className="w-6 h-6" /> System Recovery Override
           </button>
           <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-4.5 rounded-2xl font-black text-[11px] uppercase border transition-all flex items-center justify-center gap-2 ${isRunning ? 'bg-slate-900 text-amber-500 border-amber-500/20 hover:bg-slate-800' : 'bg-indigo-600 text-white border-indigo-400 shadow-lg shadow-indigo-900/40'}`}>
                 {isRunning ? <Pause className="w-5 h-5" /> : <Play className="w-5 h-5 fill-current" />}
                 {isRunning ? 'Stop Line' : 'Start Flow'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0,rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); addLog("KPI DATA CLEARED."); }} className="py-4.5 bg-slate-900 text-slate-600 border border-slate-800 rounded-2xl font-black text-[11px] uppercase hover:text-white hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                 <RotateCcw className="w-5 h-5" /> Flush Metrics
              </button>
           </div>
        </div>
      </aside>

      <main className="flex-1 relative bg-[#070b14] flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: isFitToScreen ? 'transform 0.7s cubic-bezier(0.16, 1, 0.3, 1)' : 'none' }} className="relative shadow-[0_0_150px_rgba(0,0,0,1)] border-[24px] border-slate-950 bg-[#0f172a] rounded-[5rem] shrink-0">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const rect = canvasRef.current?.getBoundingClientRect();
              if (rect) mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale };
            }} className="cursor-crosshair" />
          </div>
        </div>
        <div className="h-16 bg-slate-950 border-t border-slate-900 flex items-center px-10 gap-10 overflow-hidden shrink-0 relative">
          <div className="flex items-center gap-3 shrink-0 z-20 text-indigo-500"><Terminal className="w-5 h-5" /><span className="text-[11px] font-black uppercase tracking-[0.4em]">Node_Stream_Realtime</span></div>
          <div className="flex-1 whitespace-nowrap overflow-hidden z-20">
            <div className="flex gap-24 animate-marquee py-2">
              {logs.map((log, i) => (
                <span key={i} className="text-[11px] font-bold text-slate-500 uppercase tracking-tight flex gap-5 items-center">
                  <div className={`w-2.5 h-2.5 rounded-full ${log.includes('FAILED') || log.includes('ALERT') ? 'bg-rose-500 shadow-[0_0_12px_rgba(244,63,94,0.6)]' : 'bg-indigo-500/40 shadow-[0_0_12px_rgba(99,102,241,0.6)]'}`} /> {log}
                </span>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Activity, 
  Cpu,
  CheckCircle2,
  Wrench,
  ShieldAlert,
  MonitorDot,
  TrendingUp,
  Settings2,
  Search,
  ArrowRightCircle,
  Terminal,
  Key,
  Timer,
  Droplets,
  ShieldCheck,
  BarChart,
  LayoutGrid,
  Info,
  Clock,
  History,
  AlertCircle,
  ChevronRight,
  Package,
  Gauge,
  Zap,
  ActivitySquare,
  AlertTriangle
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, StationType, FailureType, QualityStatus, RollFailureType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const FAILURE_TYPES: FailureType[] = ['ELECTRICAL', 'ELECTRONIC', 'MECHANICAL', 'LEAKAGE'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(480); 
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.24); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale, setManualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0,
    totalLeadTimeFrames: 0,
    repairCompletedCount: 0,
    ftrFails: 0,
    ftrSuccesses: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0,
    rollTestProcessed: 0,
    ecatsFailures: 0,
    velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4'];
    return colors[Math.floor(Math.random() * colors.length)];
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 40;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      setScale(Math.max(0.15, s));
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false,
      failureType: null,
      lastFailureType: null,
      workOrderId: null,
      repairStartTime: null,
      currentLeadTime: 0,
      faiStatus: 'NONE',
      waterTestStatus: 'NONE',
      finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false,
      waitingAreaEntryCount: 0,
      isFtrNegative: false,
      viaVerde: true,
      repairCycleCount: 0,
      inRetest: false,
      rollTestStatus: 'NONE',
      rollTestFailType: null,
      assignedCabinId: null
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 120; 
      addLog(`MANUAL OVERRIDE: UNIT ${v.id.toUpperCase()} RELEASED`);
    }
  };

  const unlockAll = useCallback(() => {
    const affected = vehiclesRef.current.filter(v => v.isLocked || v.waitingTimer > 0);
    const count = affected.length;
    if (count > 0 || !isRunning) {
      vehiclesRef.current.forEach(v => {
        v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 180;
      });
      if (!isRunning) {
        setIsRunning(true);
        addLog(`MASTER RECOVERY: PRODUCTION FLOW RESUMED. ${count} UNITS RELEASED.`);
      } else {
        addLog(`COMMAND: RELEASE ALL GATES. ${count} UNITS MOVED.`);
      }
    }
  }, [isRunning]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.inRepair && v.repairStartTime !== null) {
        v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      }

      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        v.finished = true;
        if (v.viaVerde) {
          setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        }
        if (v.everRepaired && v.repairCycleCount === 1) {
          setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1 }));
        }
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        addLog(`SHIPMENT: ${v.id.toUpperCase()} COMPLETED [${v.viaVerde ? 'VIA VERDE' : 'RECOVERY'}]`);
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const onSamePath = (other.inRepair === v.inRepair);
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return onSamePath ? (distToOther < 65 && (other.pathIdx >= v.pathIdx)) : (distToOther < 45);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableCabinIndex = [0, 1, 2].find(idx => {
                const cabinId = PARALLEL_ROLL_STATIONS[idx].id;
                return !currentVehicles.some(other => other.assignedCabinId === cabinId);
            });

            if (availableCabinIndex !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableCabinIndex].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableCabinIndex], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0; 
                addLog(`ALLOCATION: UNIT ${v.id.toUpperCase()} -> ROLL CABIN ${availableCabinIndex + 1}`);
            } else {
                v.pathIdx--; 
                continue;
            }
        }

        if (v.assignedCabinId && v.pos.x === MAIN_PATH_POINTS[MERGE_POINT_IDX].x && v.pos.y === MAIN_PATH_POINTS[MERGE_POINT_IDX].y) {
           v.assignedCabinId = null;
        }

        if (v.pathIdx === 22 && !v.inRepair) {
           const securityClear = v.faiStatus === 'PASS' && v.waterTestStatus === 'PASS' && v.finalInspectionStatus === 'PASS' && v.rollTestStatus === 'PASS';
           if (!securityClear) {
             v.isLocked = true;
             addLog(`SECURITY ALERT: UNIT ${v.id.toUpperCase()} BLOCKED FOR FINAL AUDIT.`);
           }
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const routeToRepair = (source: string, manualCategory?: FailureType) => {
            const cat = manualCategory || FAILURE_TYPES[Math.floor(Math.random() * FAILURE_TYPES.length)];
            v.viaVerde = false;
            v.inRepair = true;
            v.repairCycleCount++;
            v.failureType = cat;
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS];
            v.pathIdx = 0; 
            v.color = COLORS.REPAIR;
            v.assignedCabinId = null; 

            setStats(s => ({ 
              ...s, 
              defects: s.defects + 1,
              categoryVolumes: { ...s.categoryVolumes, [cat]: s.categoryVolumes[cat] + 1 },
              totalWaitAreaEntries: s.totalWaitAreaEntries + 1
            }));

            addLog(`${source}: UNIT ${v.id.toUpperCase()} FAILED. REDIRECT TO BUFFER [${cat}]`);
          };

          if (station.name === 'FAI QC') {
            if (v.hasDefect && v.faiStatus !== 'PASS') {
              v.faiStatus = 'FAIL';
              routeToRepair('FAI QC');
            } else {
              v.faiStatus = 'PASS';
            }
          }

          if (station.name.startsWith('Teste Rolo')) {
             const isDefectiveInRoll = v.hasDefect && Math.random() < 0.22;
             if (isDefectiveInRoll) {
                const rollFailType: RollFailureType = Math.random() < 0.45 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL';
                v.rollTestFailType = rollFailType;

                if (rollFailType === 'ECATS') {
                   setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 }));
                   routeToRepair('ROLL TEST (ECATS)', 'ELECTRONIC');
                } else {
                   setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 }));
                   routeToRepair('ROLL TEST (0-100)', 'MECHANICAL');
                }
             } else {
                v.rollTestStatus = 'PASS';
                setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 }));
                addLog(`ROLL VALIDATION: ${v.id.toUpperCase()} PASSED (ECATS/0-100/BRAKE).`);
             }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (Math.random() < 0.12 && v.waterTestStatus !== 'PASS') {
              v.waterTestStatus = 'FAIL';
              routeToRepair('WATER TEST', 'LEAKAGE');
            } else {
              v.waterTestStatus = 'PASS';
              v.inRetest = false;
            }
          }

          if (station.name === 'Flat Top') {
            if (v.hasDefect && Math.random() < 0.28) {
              v.finalInspectionStatus = 'FAIL';
              routeToRepair('FLAT TOP GATE');
            } else {
              v.finalInspectionStatus = 'PASS';
            }
          }

          if (station.name === 'Waiting Area') {
            if (v.failureType === 'LEAKAGE') v.pathIdx = 2; 
            else if (v.failureType === 'ELECTRICAL' || v.failureType === 'ELECTRONIC') v.pathIdx = 3; 
            else v.pathIdx = 1; 
          }

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false;
            v.isRepaired = true;
            v.color = v.baseColor;

            const elapsed = frameCountRef.current - (v.repairStartTime || 0);
            setStats(s => ({ ...s, totalLeadTimeFrames: s.totalLeadTimeFrames + elapsed, repairCompletedCount: s.repairCompletedCount + 1 }));

            if (v.failureType === 'LEAKAGE') {
              v.waterTestStatus = 'NONE';
              v.inRetest = true;

              const isComplex = Math.random() < 0.25;
              if (isComplex) {
                 v.rollTestStatus = 'NONE';
                 v.targetPath = [...MAIN_PATH_POINTS];
                 v.pathIdx = 10; 
                 addLog(`COMPLEX REPAIR: UNIT ${v.id.toUpperCase()} REQUIRES FULL RE-TEST (ROLL + WATER).`);
              } else {
                 v.targetPath = [...MAIN_PATH_POINTS];
                 v.pathIdx = 18; 
                 addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> WATER RE-TEST ONLY.`);
              }
            } else {
              v.finalInspectionStatus = 'NONE';
              v.targetPath = [...MAIN_PATH_POINTS];
              v.pathIdx = 10; 
              addLog(`HUB EXIT: UNIT ${v.id.toUpperCase()} -> FINAL GATE VALIDATION.`);
            }
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 28) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 24));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#1a0505', 30);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 110; const h = s.height || 42; const x = s.pos.x - w / 2; const y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE', prog = 0;
      if (v) {
        if (v.waitingTimer > 0) { status = 'PROCESSING'; prog = 1 - (v.waitingTimer / s.wait); }
        else status = 'OCCUPIED';
      }

      const isRollTest = s.name.startsWith('Teste Rolo');
      const isFailing = isRollTest && v && v.rollTestStatus === 'FAIL';

      ctx.strokeStyle = isFailing ? '#ef4444' : (hoveredStationId === s.id ? '#6366f1' : 'rgba(255,255,255,0.06)'); 
      ctx.lineWidth = (hoveredStationId === s.id || isFailing) ? 3 : 1; ctx.fillStyle = 'rgba(15, 23, 42, 0.98)'; 

      if (isFailing) {
          ctx.shadowBlur = 15;
          ctx.shadowColor = '#ef4444';
      }

      ctx.beginPath(); ctx.roundRect(x, y, w, h, 8); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#fbbf24' : '#334155');
      ctx.beginPath(); ctx.arc(x + 14, y + 14, 5, 0, Math.PI * 2); ctx.fill();

      ctx.fillStyle = COLORS.TEXT; ctx.font = 'bold 9px Inter'; ctx.fillText(s.name.toUpperCase(), x + 24, y + 18);
      if (status === 'PROCESSING') { ctx.fillStyle = 'rgba(255,255,255,0.04)'; ctx.fillRect(x + 6, y + h - 8, w - 12, 4); ctx.fillStyle = '#10b981'; ctx.fillRect(x + 6, y + h - 8, (w - 12) * prog, 4); }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 5); ctx.fill();
      if (v.viaVerde && !v.inRepair) {
        ctx.globalCompositeOperation = 'source-over'; ctx.strokeStyle = '#10b981'; ctx.lineWidth = 2; ctx.strokeRect(-18, -9, 36, 18);
      }
      if (v.inRepair || v.isLocked) {
        ctx.globalCompositeOperation = 'source-over'; ctx.fillStyle = 'white'; ctx.font = 'bold 8px Inter'; ctx.textAlign = 'center';
        if (v.inRepair) ctx.fillText(v.workOrderId || '', 0, 3);
        else { ctx.save(); ctx.rotate(-v.rotation); ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(0, -18, 6, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }
      }
