  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(480); 
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.24); 
  const [isFitToScreen, setIsFitToScreen] = useState(true);
  const [scale, setScale] = useState(1);
  const [manualScale] = useState(0.65);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, 
    defects: 0, 
    active: 0, 
    cycleTime: 0,
    totalStarted: 0,
    passedFirstTime: 0,
    totalRepaired: 0,
    repairAttempts: 0,
    totalStagesCompleted: 0,
    totalLeadTimeFrames: 0,
    repairCompletedCount: 0,
    ftrFails: 0,
    ftrSuccesses: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0,
    rollTestProcessed: 0,
    ecatsFailures: 0,
    velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const getRandomColor = () => {
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4'];
    return colors[Math.floor(Math.random() * colors.length)];
  };

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    if (isFitToScreen) {
      const { clientWidth, clientHeight } = containerRef.current;
      const padding = 20;
      const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
      setScale(Math.max(0.1, s));
    } else {
      setScale(manualScale);
    }
  }, [isFitToScreen, manualScale]);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  useEffect(() => {
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
  }, []);

  const addLog = (msg: string) => {
    setLogs(prev => [msg, ...prev].slice(0, 15));
  };

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const hasInitialDefect = Math.random() < defectRate;
    const bodyColor = getRandomColor();
    const newVehicle: Vehicle = {
      id,
      pos: { ...MAIN_PATH_POINTS[0] },
      rotation: 0,
      pathIdx: 0,
      targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0,
      hasEngine: false,
      hasWheels: false,
      hasFluids: false,
      hasDefect: hasInitialDefect,
      isRepaired: false,
      inRepair: false,
      color: bodyColor,
      baseColor: bodyColor,
      finished: false,
      progress: 0,
      everRepaired: false,
      ignoreCollisionTimer: 0,
      pendingRepairs: 0,
      completedRepairs: 0,
      initialRepairs: 0,
      isLocked: false,
      failureType: null,
      lastFailureType: null,
      workOrderId: null,
      repairStartTime: null,
      currentLeadTime: 0,
      faiStatus: 'NONE',
      waterTestStatus: 'NONE',
      finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false,
      waitingAreaEntryCount: 0,
      isFtrNegative: false,
      viaVerde: true,
      repairCycleCount: 0,
      inRetest: false,
      rollTestStatus: 'NONE',
      rollTestFailType: null,
      assignedCabinId: null
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) {
      v.isLocked = false;
      v.waitingTimer = 0;
      v.ignoreCollisionTimer = 60; 
      addLog(`OVERRIDE: ${v.id.toUpperCase()} RELEASED`);
    }
  };

  const unlockAll = useCallback(() => {
    const affected = vehiclesRef.current.filter(v => v.isLocked || v.waitingTimer > 0);
    const count = affected.length;
    vehiclesRef.current.forEach(v => {
      v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 120;
    });
    if (count > 0) addLog(`SYSTEM RECOVERY: ${count} UNITS RELEASED`);
    if (!isRunning) setIsRunning(true);
  }, [isRunning]);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair && v.repairStartTime !== null) v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        if (v.everRepaired && v.repairCycleCount === 1) setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x;
      const dy = target.y - v.pos.y;
      const dist = Math.sqrt(dx * dx + dy * dy);

      const isBlocked = v.ignoreCollisionTimer <= 0 && currentVehicles.some(other => {
        if (other.id === v.id) return false;
        const distToOther = Math.sqrt(Math.pow(other.pos.x - v.pos.x, 2) + Math.pow(other.pos.y - v.pos.y, 2));
        return (other.inRepair === v.inRepair) ? (distToOther < 60 && (other.pathIdx >= v.pathIdx)) : (distToOther < 40);
      });

      if (isBlocked) continue; 

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target };
        v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableCabinIndex = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
            if (availableCabinIndex !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableCabinIndex].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableCabinIndex], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0; 
            } else {
                v.pathIdx--; continue;
            }
        }

        if (v.assignedCabinId && v.pos.x === MAIN_PATH_POINTS[MERGE_POINT_IDX].x && v.pos.y === MAIN_PATH_POINTS[MERGE_POINT_IDX].y) v.assignedCabinId = null;

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const routeToRepair = (source: string, manualCategory?: FailureType) => {
            const cat = manualCategory || FAILURE_TYPES[Math.floor(Math.random() * FAILURE_TYPES.length)];
            v.viaVerde = false; v.inRepair = true; v.repairCycleCount++; v.failureType = cat; v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR; v.assignedCabinId = null; 
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [cat]: s.categoryVolumes[cat] + 1 } }));
            addLog(`${v.id.toUpperCase()}: ${source} FAIL -> ${cat}`);
          };

          if (station.name === 'FAI QC' && v.hasDefect && v.faiStatus !== 'PASS') { v.faiStatus = 'FAIL'; routeToRepair('FAI QC'); }
          else if (station.name === 'FAI QC') v.faiStatus = 'PASS';

          if (station.name.startsWith('Teste Rolo')) {
             if (v.hasDefect && Math.random() < 0.22) {
                const rollFailType: RollFailureType = Math.random() < 0.45 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL'; v.rollTestFailType = rollFailType;
                if (rollFailType === 'ECATS') { setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 })); routeToRepair('ROLL (ECATS)', 'ELECTRONIC'); }
                else { setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 })); routeToRepair('ROLL (ACCEL)', 'MECHANICAL'); }
             } else {
                v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 }));
             }
          }

          if (station.name === 'SISTEMA ÁGUA' && Math.random() < 0.12 && v.waterTestStatus !== 'PASS') { v.waterTestStatus = 'FAIL'; routeToRepair('WATER', 'LEAKAGE'); }
          else if (station.name === 'SISTEMA ÁGUA') { v.waterTestStatus = 'PASS'; v.inRetest = false; }

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false; v.isRepaired = true; v.color = v.baseColor;
            const elapsed = frameCountRef.current - (v.repairStartTime || 0);
            setStats(s => ({ ...s, totalLeadTimeFrames: s.totalLeadTimeFrames + elapsed, repairCompletedCount: s.repairCompletedCount + 1 }));
            if (v.failureType === 'LEAKAGE') { v.waterTestStatus = 'NONE'; v.inRetest = true; v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; }
            else { v.finalInspectionStatus = 'NONE'; v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 10; }
          }
        }
      } else {
        const ratio = speed / dist; v.pos.x += dx * ratio; v.pos.y += dy * ratio;
      }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    const renderConveyorLine = (pts: Point[], color = COLORS.CONVEYOR, width = 24) => {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = width; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    renderConveyorLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(branch => renderConveyorLine(branch, '#1e293b', 20));
    renderConveyorLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    renderConveyorLine(REPAIR_PATH_POINTS, '#180a0a', 28);

    const allStations = [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS];
    allStations.forEach(s => {
      const w = s.width || 100, h = s.height || 38, x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status: StationStatus = 'IDLE', prog = 0;
      if (v) status = v.waitingTimer > 0 ? 'PROCESSING' : 'OCCUPIED';
      if (v && v.waitingTimer > 0) prog = 1 - (v.waitingTimer / s.wait);

      ctx.strokeStyle = hoveredStationId === s.id ? '#6366f1' : 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 1; ctx.fillStyle = '#0f172a';
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke();

      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#f59e0b' : '#334155');
      ctx.beginPath(); ctx.arc(x + 12, y + h / 2, 4, 0, Math.PI * 2); ctx.fill();

      ctx.fillStyle = '#94a3b8'; ctx.font = '500 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 22, y + h / 2 + 3);
      if (status === 'PROCESSING') { ctx.fillStyle = 'rgba(16,185,129,0.1)'; ctx.fillRect(x + 2, y + h - 4, w - 4, 2); ctx.fillStyle = '#10b981'; ctx.fillRect(x + 2, y + h - 4, (w - 4) * prog, 2); }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -16, -8, 32, 16);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-16, -8, 32, 16, 4); ctx.fill();
      ctx.restore();
    });
    ctx.fillStyle = 'rgba(255, 255, 255, 0.05)'; ctx.font = '700 42px Inter'; ctx.fillText('PRODUCTION_HUB', 50, 60);
  }, [hoveredStationId]);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) { const ctx = canvasRef.current.getContext('2d'); if (ctx) draw(ctx); } fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const dailyProgress = (stats.produced / 500) * 100;

  const cabinsOccupancy = useMemo(() => [0, 1, 2].map(i => ({ id: PARALLEL_ROLL_STATIONS[i].id, occupied: !!vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id) })), [stats.active]);

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">
      {/* MINIMAL SIDEBAR */}
      <aside className="w-[340px] bg-slate-950 border-r border-slate-900 flex flex-col shrink-0 z-20">

        <div className="p-8 border-b border-slate-900/50 space-y-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-500/10 rounded-lg"><Cpu className="w-5 h-5 text-indigo-500" /></div>
              <h1 className="text-xs font-bold tracking-widest text-slate-200 uppercase">Factory OS</h1>
            </div>
            <div className={`flex items-center gap-1.5 text-[9px] font-bold uppercase ${isRunning ? 'text-emerald-500' : 'text-rose-500'}`}>
               <Radio className={`w-3 h-3 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Online' : 'Halt'}
            </div>
          </div>

          <div className="space-y-2">
            <div className="flex justify-between items-baseline">
              <span className="text-[10px] font-semibold text-slate-500 uppercase tracking-wider">Throughput</span>
              <span className="text-lg font-bold text-slate-100 tabular-nums">{stats.produced} <span className="text-slate-700 font-medium">/ 500</span></span>
            </div>
            <div className="h-1 w-full bg-slate-900 rounded-full overflow-hidden">
               <div className="h-full bg-indigo-500 transition-all duration-700" style={{ width: `${Math.min(100, dailyProgress)}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/50">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" /> },
            { id: 'QUALITY', icon: <ShieldAlert className="w-4 h-4" /> },
            { id: 'NODES', icon: <LayoutGrid className="w-4 h-4" /> }
          ].map(t => (
            <button key={t.id} onClick={() => setActiveTab(t.id as DashboardTab)} className={`flex-1 flex justify-center py-4 transition-all relative ${activeTab === t.id ? 'text-indigo-400' : 'text-slate-600 hover:text-slate-400'}`}>
              {t.icon}
              {activeTab === t.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-500" />}
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">
          {activeTab === 'KPI' && (
            <div className="space-y-8 animate-in fade-in duration-500">

              <section className="space-y-4">
                <header className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest"><ActivitySquare className="w-3.5 h-3.5" /> Test Bay Monitor</header>
                <div className="grid grid-cols-3 gap-2">
                  {cabinsOccupancy.map((c, i) => (
                    <div key={c.id} className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-colors ${c.occupied ? 'bg-amber-500/5 border-amber-500/20' : 'bg-slate-900/40 border-slate-900'}`}>
                      <Gauge className={`w-4 h-4 ${c.occupied ? 'text-amber-500' : 'text-slate-800'}`} />
                      <span className={`text-[8px] font-bold uppercase tracking-tighter ${c.occupied ? 'text-amber-500' : 'text-slate-700'}`}>{c.occupied ? 'Active' : 'Idle'}</span>
                    </div>
                  ))}
                </div>
              </section>

              <section className="grid grid-cols-2 gap-3">
                <div className="p-4 bg-slate-900/40 border border-slate-900 rounded-xl space-y-1">
                  <span className="text-[9px] font-bold text-slate-600 uppercase">FTT Index</span>
                  <div className="text-xl font-bold text-slate-100">{fttRate.toFixed(1)}%</div>
                </div>
                <div className="p-4 bg-slate-900/40 border border-slate-900 rounded-xl space-y-1">
                  <span className="text-[9px] font-bold text-slate-600 uppercase">FTR Index</span>
                  <div className="text-xl font-bold text-slate-100">{ftrRate.toFixed(1)}%</div>
                </div>
              </section>

              <section className="space-y-4">
                <header className="flex justify-between text-[10px] font-bold text-slate-500 uppercase tracking-widest"><span>Defect Distribution</span> <History className="w-3 h-3" /></header>
                <div className="space-y-4">
                  {FAILURE_TYPES.map(type => (
                    <div key={type} className="space-y-1.5 group">
                      <div className="flex justify-between text-[9px] font-medium tracking-tight">
                        <span className="text-slate-500 group-hover:text-slate-300 transition-colors uppercase">{type}</span>
                        <span className="text-slate-400 tabular-nums">{stats.categoryVolumes[type]}</span>
                      </div>
                      <div className="h-1 w-full bg-slate-900/50 rounded-full overflow-hidden">
                        <div className={`h-full transition-all duration-1000 ${type === 'LEAKAGE' ? 'bg-blue-600' : 'bg-rose-600'}`} style={{ width: `${stats.defects > 0 ? (stats.categoryVolumes[type] / stats.defects) * 100 : 0}%` }} />
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="space-y-6 animate-in fade-in duration-500">
               <header className="flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-500">
                 <span>Resolution Hub</span>
                 <span className="text-rose-500">{vehiclesRef.current.filter(v=>v.inRepair).length} Units</span>
               </header>
               <div className="space-y-4">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="p-5 bg-slate-900/40 border border-slate-900 rounded-xl space-y-4 group">
                       <div className="flex justify-between items-center">
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-4 rounded border border-slate-800" style={{ backgroundColor: v.color }} />
                            <span className="text-xs font-bold text-slate-200">{v.id.toUpperCase()}</span>
                          </div>
                          <span className="text-[10px] font-medium text-slate-600 tabular-nums">{((v.currentLeadTime||0)/60).toFixed(0)}s</span>
                       </div>
                       <div className="flex justify-between text-[10px] font-semibold text-slate-500 uppercase tracking-tight">
                         <span className="flex items-center gap-1"><AlertCircle className="w-3 h-3 text-rose-600" /> {v.failureType}</span>
                         <span className="text-slate-700">{v.workOrderId}</span>
                       </div>
                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-2.5 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white rounded-lg text-[10px] font-bold uppercase tracking-widest transition-all">Verify & Release</button>
                    </div>
                  ))}
                  {vehiclesRef.current.filter(v=>v.inRepair).length === 0 && (
                    <div className="py-20 flex flex-col items-center justify-center opacity-20"><CheckCircle2 className="w-12 h-12 mb-4" /><span className="text-xs font-bold uppercase tracking-[0.3em]">Queue Empty</span></div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'NODES' && (
             <div className="space-y-6 animate-in fade-in duration-500">
               <div className="relative group">
                 <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700 group-focus-within:text-indigo-500 transition-colors" />
                 <input type="text" placeholder="Search nodes..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/30 border border-slate-900 rounded-xl py-2.5 pl-11 pr-4 text-[11px] font-medium focus:outline-none focus:border-indigo-500/50 transition-all" />
               </div>
               <div className="space-y-1.5 pr-1">
                 {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                   <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`p-4 rounded-xl border flex items-center justify-between transition-all cursor-default ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/30' : 'bg-slate-900/20 border-transparent hover:bg-slate-900/40'}`}>
                      <div className="flex items-center gap-4">
                        <MonitorDot className={`w-3.5 h-3.5 ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-700'}`} />
                        <span className={`text-[11px] font-bold tracking-tight transition-colors ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-300'}`}>{s.name}</span>
                      </div>
                      <span className="text-[8px] font-semibold text-slate-700 uppercase">{s.type}</span>
                   </div>
                 ))}
               </div>
             </div>
          )}
        </div>

        <div className="p-8 border-t border-slate-900/50 bg-slate-950/50 shrink-0 space-y-4">
           <button onClick={unlockAll} className="w-full py-3 bg-slate-900 border border-slate-800 hover:border-amber-500/50 text-slate-400 hover:text-amber-500 rounded-xl text-xs font-bold uppercase tracking-widest transition-all flex justify-center gap-2 items-center active:scale-95"><Key className="w-4 h-4" /> System Override</button>
           <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-3 rounded-xl text-[10px] font-bold uppercase border transition-all flex justify-center gap-2 items-center ${isRunning ? 'bg-slate-900 border-slate-800 text-slate-500' : 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-950'}`}>
                 {isRunning ? <Pause className="w-3.5 h-3.5" /> : <Play className="w-3.5 h-3.5 fill-current" />} {isRunning ? 'Stop' : 'Start'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0,rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); addLog("KPI DATA RESET."); }} className="py-3 bg-slate-900 border border-slate-800 text-slate-600 hover:text-rose-400 rounded-xl text-[10px] font-bold uppercase transition-all flex justify-center gap-2 items-center"><RotateCcw className="w-3.5 h-3.5" /> Reset</button>
           </div>
        </div>
      </aside>

      {/* VIEWPORT */}
      <main className="flex-1 relative flex flex-col overflow-hidden" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative overflow-hidden bg-[#070b14]">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: 'transform 0.4s ease-out' }} className="relative bg-[#020617] rounded-3xl shrink-0 overflow-hidden border border-slate-900">
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const rect = canvasRef.current?.getBoundingClientRect();
              if (rect) mousePosRef.current = { x: (e.clientX - rect.left) / scale, y: (e.clientY - rect.top) / scale };
            }} />
          </div>
        </div>

        {/* LOGS */}
        <div className="h-14 bg-slate-950 border-t border-slate-900 flex items-center px-8 gap-8 shrink-0 overflow-hidden text-[10px] font-semibold text-slate-600 uppercase tracking-widest">
          <div className="flex items-center gap-2 text-indigo-500 shrink-0"><Terminal className="w-4 h-4" /> Telemetry</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-20 animate-marquee items-center">
              {logs.map((log, i) => (
                <span key={i} className={`flex gap-3 items-center whitespace-nowrap ${log.includes('FAIL') ? 'text-rose-500' : ''}`}><div className={`w-1.5 h-1.5 rounded-full ${log.includes('FAIL') ? 'bg-rose-600' : 'bg-slate-800'}`} /> {log}</span>
              ))}
              {logs.length === 0 && <span className="opacity-20 italic">No events recorded...</span>}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 60s linear infinite; }
        .animate-in { animation: animateIn 0.5s ease-out; }
        @keyframes animateIn { from { opacity: 0; transform: translateY(4px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Cpu,
  CheckCircle2,
  ShieldAlert,
  MonitorDot,
  Search,
  ArrowRightCircle,
  Terminal,
  Key,
  Timer,
  BarChart,
  LayoutGrid,
  History,
  AlertCircle,
  ChevronRight,
  Gauge,
  Zap,
  ActivitySquare,
  Radio,
  Droplets
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, QualityStatus, RollFailureType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type StationStatus = 'IDLE' | 'PROCESSING' | 'OCCUPIED' | 'BLOCKED';
type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const FAILURE_TYPES: FailureType[] = ['ELECTRICAL', 'ELECTRONIC', 'MECHANICAL', 'LEAKAGE'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(480); 
  const [speed] = useState(2.8);
  const [defectRate] = useState(0.24); 
  const [scale, setScale] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, cycleTime: 0, totalStarted: 0, passedFirstTime: 0, 
    totalRepaired: 0, repairAttempts: 0, totalStagesCompleted: 0, totalLeadTimeFrames: 0, 
    repairCompletedCount: 0, ftrFails: 0, ftrSuccesses: 0, 
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0, rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    const { clientWidth, clientHeight } = containerRef.current;
    const s = Math.min((clientWidth - 40) / SIM_WIDTH, (clientHeight - 40) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColor = ['#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#06b6d4'][Math.floor(Math.random() * 6)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasEngine: false, hasWheels: false, hasFluids: false, hasDefect: Math.random() < defectRate,
      isRepaired: false, inRepair: false, color: bodyColor, baseColor: bodyColor, finished: false, progress: 0,
      everRepaired: false, ignoreCollisionTimer: 0, pendingRepairs: 0, completedRepairs: 0, initialRepairs: 0,
      isLocked: false, failureType: null, lastFailureType: null, workOrderId: null, repairStartTime: null,
      currentLeadTime: 0, faiStatus: 'NONE', waterTestStatus: 'NONE', finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false, waitingAreaEntryCount: 0, isFtrNegative: false, viaVerde: true,
      repairCycleCount: 0, inRetest: false, rollTestStatus: 'NONE', rollTestFailType: null, assignedCabinId: null
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 60; addLog(`UNIT ${v.id.toUpperCase()} RELEASED`); }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair && v.repairStartTime !== null) v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;
      if (v.waitingTimer > 0) { v.waitingTimer--; continue; }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (v.ignoreCollisionTimer <= 0 && currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < (o.inRepair === v.inRepair ? 60 : 40) && o.pathIdx >= v.pathIdx)) continue;

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        // Cabin Logic: Strict 1-per-cabin
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
            if (availableIdx !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0;
            } else { v.pathIdx--; continue; }
        }
        if (v.assignedCabinId && v.pos.x === MAIN_PATH_POINTS[MERGE_POINT_IDX].x && v.pos.y === MAIN_PATH_POINTS[MERGE_POINT_IDX].y) v.assignedCabinId = null;

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;
          const routeToRepair = (source: string, type: FailureType) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type; v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`${v.id.toUpperCase()}: ${source} FAILED [${type}]`);
          };

          if (station.name.startsWith('Teste Rolo')) {
             const isDefective = v.hasDefect && Math.random() < 0.25;
             if (isDefective) {
                const rollFailType: RollFailureType = Math.random() < 0.5 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL'; v.rollTestFailType = rollFailType;
                if (rollFailType === 'ECATS') { setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 })); routeToRepair('ROLL (ECATS)', 'ELECTRONIC'); }
                else { setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 })); routeToRepair('ROLL (ACCEL)', 'MECHANICAL'); }
             } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); addLog(`ROLL PASS: ${v.id.toUpperCase()}`); }
          }

          if (station.name === 'SISTEMA ÁGUA' && Math.random() < 0.15 && v.waterTestStatus !== 'PASS') { v.waterTestStatus = 'FAIL'; routeToRepair('WATER', 'LEAKAGE'); }
          else if (station.name === 'SISTEMA ÁGUA') v.waterTestStatus = 'PASS';

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false; v.color = v.baseColor;
            setStats(s => ({ ...s, repairCompletedCount: s.repairCompletedCount + 1, ftrSuccesses: s.ftrSuccesses + 1 }));
            // Specific re-test logic
            if (v.failureType === 'LEAKAGE' && Math.random() > 0.2) { 
                v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; addLog(`REPAIR DONE: ${v.id.toUpperCase()} -> WATER RETEST`);
            } else { 
                v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 10; addLog(`REPAIR DONE: ${v.id.toUpperCase()} -> FULL RETEST`);
            }
          }
        }
      } else { const r = speed / dist; v.pos.x += dx * r; v.pos.y += dy * r; }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    const line = (pts: Point[], col = COLORS.CONVEYOR, w = 24) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    line(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => line(b, '#1e293b', 20));
    line(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    line(REPAIR_PATH_POINTS, '#180a0a', 28);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const w = s.width || 100, h = s.height || 38, x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const v = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status = v ? (v.waitingTimer > 0 ? 'PROCESSING' : 'OCCUPIED') : 'IDLE';

      ctx.fillStyle = '#0f172a'; ctx.strokeStyle = 'rgba(255,255,255,0.05)';
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 6); ctx.fill(); ctx.stroke();
      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#f59e0b' : '#334155');
      ctx.beginPath(); ctx.arc(x + 12, y + h / 2, 4, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#94a3b8'; ctx.font = '600 8px Inter'; ctx.fillText(s.name.toUpperCase(), x + 22, y + h / 2 + 3);
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -16, -8, 32, 16);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-16, -8, 32, 16, 4); ctx.fill();
      ctx.restore();
    });
  }, [hoveredStationId]);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const cabins = [0, 1, 2].map(i => !!vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id));

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">
      <aside className="w-[360px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-20">
        <div className="p-8 border-b border-slate-900/50 space-y-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-500/10 rounded-lg"><Cpu className="w-5 h-5 text-indigo-500" /></div>
              <h1 className="text-xs font-bold tracking-widest text-slate-200 uppercase">Hub 500 VPD</h1>
            </div>
            <div className={`flex items-center gap-1.5 text-[9px] font-bold uppercase ${isRunning ? 'text-emerald-500' : 'text-rose-500'}`}>
               <Radio className={`w-3 h-3 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Sync' : 'Halt'}
            </div>
          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-baseline">
              <span className="text-[10px] font-semibold text-slate-600 uppercase tracking-wider">Produced / Target</span>
              <span className="text-xl font-bold text-slate-100 tabular-nums">{stats.produced} <span className="text-slate-800">/ 500</span></span>
            </div>
            <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden">
               <div className="h-full bg-indigo-500 transition-all duration-700" style={{ width: `${(stats.produced / 500) * 100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/20 px-4">
          {['KPI', 'QUALITY', 'NODES'].map(id => (
            <button key={id} onClick={() => setActiveTab(id as DashboardTab)} className={`flex-1 flex justify-center py-4 transition-all relative ${activeTab === id ? 'text-indigo-400' : 'text-slate-600 hover:text-slate-400'}`}>
              {id === 'KPI' ? <BarChart className="w-4 h-4" /> : id === 'QUALITY' ? <ShieldAlert className="w-4 h-4" /> : <LayoutGrid className="w-4 h-4" />}
              {activeTab === id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-500" />}
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-8 space-y-10">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <section className="space-y-4">
                <header className="text-[10px] font-bold text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><ActivitySquare className="w-3.5 h-3.5" /> Roll Test Bays</header>
                <div className="grid grid-cols-3 gap-3">
                  {cabins.map((occ, i) => (
                    <div key={i} className={`p-4 rounded-xl border flex flex-col items-center gap-3 transition-colors ${occ ? 'bg-amber-500/5 border-amber-500/20 shadow-lg shadow-amber-900/5' : 'bg-slate-900/20 border-slate-900'}`}>
                      <Gauge className={`w-4 h-4 ${occ ? 'text-amber-500' : 'text-slate-800'}`} />
                      <span className={`text-[9px] font-bold uppercase tracking-tighter ${occ ? 'text-amber-500' : 'text-slate-800'}`}>{occ ? 'Testing' : 'Idle'}</span>
                    </div>
                  ))}
                </div>
              </section>

              <section className="grid grid-cols-2 gap-4">
                <div className="p-5 bg-slate-900/20 border border-slate-900 rounded-2xl space-y-1">
                  <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">FTT Rate</span>
                  <div className="text-2xl font-bold text-slate-100">{fttRate.toFixed(1)}%</div>
                </div>
                <div className="p-5 bg-slate-900/20 border border-slate-900 rounded-2xl space-y-1">
                  <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">FTR Index</span>
                  <div className="text-2xl font-bold text-slate-100">{ftrRate.toFixed(1)}%</div>
                </div>
              </section>

              <section className="space-y-5">
                <header className="flex justify-between items-center text-[10px] font-bold text-slate-600 uppercase tracking-[0.2em]"><span>Failure Analysis</span> <Zap className="w-3.5 h-3.5" /></header>
                <div className="space-y-6">
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold uppercase tracking-tight">
                      <span className="text-slate-500">ECATS (Digital)</span>
                      <span className="text-slate-300">{stats.ecatsFailures}</span>
                    </div>
                    <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden"><div className="h-full bg-rose-500" style={{ width: `${(stats.ecatsFailures / (stats.ecatsFailures + stats.velocityFailures || 1)) * 100}%` }} /></div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold uppercase tracking-tight">
                      <span className="text-slate-500">Velocity (0-100)</span>
                      <span className="text-slate-300">{stats.velocityFailures}</span>
                    </div>
                    <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden"><div className="h-full bg-amber-500" style={{ width: `${(stats.velocityFailures / (stats.ecatsFailures + stats.velocityFailures || 1)) * 100}%` }} /></div>
                  </div>
                </div>
              </section>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="space-y-6 animate-in fade-in duration-500">
               <header className="flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-600">
                 <span>Resolution Queue</span>
                 <span className="text-rose-500">{vehiclesRef.current.filter(v=>v.inRepair).length} PENDING</span>
               </header>
               <div className="space-y-4">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="p-6 bg-slate-900/30 border border-slate-900 rounded-2xl space-y-5 group hover:border-indigo-500/30 transition-all">
                       <div className="flex justify-between items-center">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-5 rounded border border-slate-800 shadow-lg" style={{ backgroundColor: v.color }} />
                            <span className="text-xs font-bold text-slate-200 tracking-wider">#{v.id.toUpperCase()}</span>
                          </div>
                          <span className="text-[10px] font-mono text-slate-600 tabular-nums">{((v.currentLeadTime||0)/60).toFixed(0)}s</span>
                       </div>
                       <div className="flex justify-between text-[9px] font-bold text-slate-500 uppercase">
                         <span className="flex items-center gap-1.5 text-rose-500/80"><AlertCircle className="w-3 h-3" /> {v.failureType}</span>
                         <span className="text-slate-800">{v.workOrderId}</span>
                       </div>
                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-3 bg-slate-800/50 hover:bg-indigo-600 text-slate-400 hover:text-white rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all">Verify & Sync</button>
                    </div>
                  ))}
                  {vehiclesRef.current.filter(v=>v.inRepair).length === 0 && (
                    <div className="py-24 flex flex-col items-center justify-center opacity-10"><CheckCircle2 className="w-12 h-12 mb-4" /><span className="text-xs font-bold uppercase tracking-[0.5em]">Sync Clear</span></div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'NODES' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700" />
                <input type="text" placeholder="Search factory nodes..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/20 border border-slate-900 rounded-xl py-3 pl-12 pr-4 text-[11px] font-medium focus:outline-none focus:border-indigo-500/40 transition-all" />
              </div>
              <div className="space-y-2">
                {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                  <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`p-4 rounded-xl border flex items-center justify-between transition-all cursor-default ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/20' : 'bg-transparent border-transparent hover:bg-slate-900/20'}`}>
                     <div className="flex items-center gap-4">
                       <MonitorDot className={`w-3.5 h-3.5 ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-800'}`} />
                       <span className={`text-[11px] font-bold transition-colors ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-400'}`}>{s.name}</span>
                     </div>
                     <span className="text-[8px] font-bold text-slate-800 uppercase tracking-widest">{s.type}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="p-8 border-t border-slate-900/50 space-y-5">
           <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 120; }); addLog("SYSTEM RECOVERED."); }} className="w-full py-4 bg-slate-900/50 border border-slate-900 hover:border-indigo-500/40 text-slate-500 hover:text-indigo-400 rounded-2xl text-[10px] font-bold uppercase tracking-[0.2em] transition-all flex justify-center gap-3 items-center active:scale-95"><Key className="w-4 h-4" /> Global Override</button>
           <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-4 rounded-2xl text-[10px] font-bold uppercase transition-all flex justify-center gap-2 items-center ${isRunning ? 'bg-slate-900 text-slate-600' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-950'}`}>
                 {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />} {isRunning ? 'Halt' : 'Start'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0,rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); addLog("KPI BUFFER CLEARED."); }} className="py-4 bg-slate-900 text-slate-700 hover:text-rose-500 rounded-2xl text-[10px] font-bold uppercase transition-all flex justify-center gap-2 items-center border border-transparent hover:border-rose-900/30"><RotateCcw className="w-4 h-4" /> Reset</button>
           </div>
        </div>
      </aside>

      <main className="flex-1 relative flex flex-col bg-[#070b14]" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative p-10">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' }} className="relative bg-[#020617] rounded-[2rem] shrink-0 overflow-hidden border border-slate-900 shadow-2xl">
            <div className="absolute top-10 right-10 flex gap-10 z-10 opacity-20 pointer-events-none">
                <div className="flex items-center gap-3"><Gauge className="w-12 h-12 text-slate-700" /><div className="flex flex-col"><span className="text-2xl font-black text-slate-700">0-100</span><span className="text-xs font-bold text-slate-800">TELEMETRY</span></div></div>
                <div className="flex items-center gap-3"><Droplets className="w-12 h-12 text-slate-700" /><div className="flex flex-col"><span className="text-2xl font-black text-slate-700">WAT_QC</span><span className="text-xs font-bold text-slate-800">STATIC_HEAD</span></div></div>
            </div>
            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const r = canvasRef.current?.getBoundingClientRect();
              if (r) mousePosRef.current = { x: (e.clientX - r.left) / scale, y: (e.clientY - r.top) / scale };
            }} />
          </div>
        </div>

        <div className="h-14 bg-[#020617] border-t border-slate-900/50 flex items-center px-10 gap-10 shrink-0 overflow-hidden text-[10px] font-bold uppercase tracking-[0.4em] text-slate-700">
          <div className="flex items-center gap-3 text-indigo-500/50 shrink-0"><Terminal className="w-4 h-4" /> Live_Sync</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-20 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-3 items-center ${l.includes('FAILED') ? 'text-rose-600' : 'text-slate-600'}`}><div className={`w-1.5 h-1.5 rounded-full ${l.includes('FAILED') ? 'bg-rose-600' : 'bg-slate-800'}`} /> {l}</span>
              ))}
              {logs.length === 0 && <span className="opacity-30 italic">Awaiting Telemetry Stream...</span>}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 50s linear infinite; }
        .animate-in { animation: animateIn 0.6s ease-out; }
        @keyframes animateIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;
